import React, { useState } from 'react';
import api from '../api';
import { useToast } from './ToastProvider';
import { Loader2, X, Building } from 'lucide-react';

interface AddCollegeModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: (college: { id: string; name: string; code?: string | null }) => void;
}

const AddCollegeModal: React.FC<AddCollegeModalProps> = ({ isOpen, onClose, onSuccess }) => {
    const { showToast } = useToast();
    const [name, setName] = useState('');
    const [code, setCode] = useState('');
    const [loading, setLoading] = useState(false);

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!name.trim()) return;

        try {
            setLoading(true);
            const response = await api.post('/colleges', {
                name: name.trim(),
                code: code.trim().toUpperCase() || undefined
            });

            showToast('success', 'College created successfully');
            onSuccess(response.data);
            setName('');
            setCode('');
            onClose();
        } catch (error: any) {
            console.error('Failed to create college:', error);
            showToast('error', error.response?.data?.error || 'Failed to create college');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4 animate-in fade-in duration-200">
            <div className="bg-[#151d30] rounded-2xl p-6 max-w-sm w-full border border-slate-800 shadow-xl">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="text-xl font-bold text-white flex items-center gap-2">
                        <Building className="w-5 h-5 text-teal-400" />
                        Add New College
                    </h3>
                    <button
                        onClick={onClose}
                        className="p-1.5 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white"
                    >
                        <X size={18} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-300 mb-1">College Code (Optional)</label>
                        <input
                            type="text"
                            value={code}
                            onChange={(e) => setCode(e.target.value.toUpperCase())}
                            placeholder="e.g. COCIS"
                            className="w-full px-3 py-2 bg-[#0a0f1e] rounded-lg border border-slate-700 focus:border-teal-500 focus:outline-none text-white font-mono"
                            maxLength={10}
                            autoFocus
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-slate-300 mb-1">College Name</label>
                        <input
                            type="text"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            placeholder="e.g. College of Computing and IS"
                            className="w-full px-3 py-2 bg-[#0a0f1e] rounded-lg border border-slate-700 focus:border-teal-500 focus:outline-none text-white"
                            required
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={loading || !name}
                        className="w-full mt-2 btn-primary flex items-center justify-center gap-2"
                    >
                        {loading ? (
                            <>
                                <Loader2 size={16} className="animate-spin" />
                                Saving...
                            </>
                        ) : (
                            'Create & Select'
                        )}
                    </button>
                </form>
            </div>
        </div>
    );
};

export default AddCollegeModal;

import React, { useState } from 'react';
import api from '../api';
import { useToast } from './ToastProvider';
import { Lock, X, Loader2, ShieldCheck } from 'lucide-react';

interface ChangePasswordModalProps {
    isOpen: boolean;
    onClose: () => void;
}

const ChangePasswordModal: React.FC<ChangePasswordModalProps> = ({ isOpen, onClose }) => {
    const { showToast } = useToast();
    const [currentPassword, setCurrentPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    if (!isOpen) return null;

    const validateForm = () => {
        if (!currentPassword || !newPassword || !confirmPassword) {
            setError('All fields are required');
            return false;
        }
        if (newPassword.length < 8) {
            setError('New password must be at least 8 characters long');
            return false;
        }
        if (newPassword === currentPassword) {
            setError('New password must be different from current password');
            return false;
        }
        if (newPassword !== confirmPassword) {
            setError('New passwords do not match');
            return false;
        }
        return true;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        if (!validateForm()) return;

        setLoading(true);

        try {
            await api.post('/auth/change-password', {
                currentPassword,
                newPassword
            });

            showToast('success', 'Password changed successfully');
            onClose();
        } catch (err: any) {
            console.error('[CHANGE_PW] Error:', err);
            setError(err.response?.data?.message || 'Failed to change password. Please check your current password and try again.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div
            className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center py-8 px-4"
            onClick={(e) => e.target === e.currentTarget && onClose()}
        >
            <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 w-full max-w-md relative overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                {/* Header */}
                <div className="flex items-center justify-between p-5 border-b border-slate-100 bg-slate-50/50">
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-xl bg-indigo-100 text-indigo-600">
                            <ShieldCheck className="w-5 h-5" />
                        </div>
                        <h2 className="text-lg font-bold text-slate-800">Change Password</h2>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 rounded-lg hover:bg-slate-200 transition-colors text-slate-500"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Form */}
                <form onSubmit={handleSubmit} className="p-6 space-y-4">
                    {error && (
                        <div className="p-3 rounded-lg text-sm bg-red-50 text-red-600 border border-red-100">
                            {error}
                        </div>
                    )}

                    <div className="space-y-1.5">
                        <label className="text-sm font-semibold text-slate-700">Current Password</label>
                        <div className="relative group">
                            <Lock className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-600 w-4 h-4" />
                            <input
                                type="password"
                                value={currentPassword}
                                onChange={(e) => setCurrentPassword(e.target.value)}
                                className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
                                placeholder="Enter current password"
                            />
                        </div>
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-sm font-semibold text-slate-700">New Password</label>
                        <div className="relative group">
                            <Lock className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-600 w-4 h-4" />
                            <input
                                type="password"
                                value={newPassword}
                                onChange={(e) => setNewPassword(e.target.value)}
                                minLength={8}
                                className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
                                placeholder="Min. 8 characters"
                            />
                        </div>
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-sm font-semibold text-slate-700">Confirm New Password</label>
                        <div className="relative group">
                            <Lock className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-600 w-4 h-4" />
                            <input
                                type="password"
                                value={confirmPassword}
                                onChange={(e) => setConfirmPassword(e.target.value)}
                                minLength={8}
                                className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
                                placeholder="Re-type new password"
                            />
                        </div>
                    </div>

                    <div className="pt-4 flex items-center justify-end gap-3">
                        <button
                            type="button"
                            onClick={onClose}
                            disabled={loading}
                            className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-slate-900 transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={loading}
                            className="bg-indigo-600 hover:bg-indigo-700 text-white px-5 py-2 rounded-xl text-sm font-medium shadow-sm transition-all flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            {loading ? (
                                <><Loader2 className="w-4 h-4 animate-spin" /> Updating...</>
                            ) : (
                                "Update Password"
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default ChangePasswordModal;

import React, { useState, useEffect } from 'react';
import { X, Search, Loader2 } from 'lucide-react';
import { toast } from 'react-hot-toast';
import api from '../../api';

interface AddTeamMemberModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
    team: {
        id: string;
        name: string;
        members: Array<{ id: string }>;
    };
}

interface Member {
    id: string;
    fullName: string;
    email: string;
    fellowshipNumber: string;
}

const AddTeamMemberModal: React.FC<AddTeamMemberModalProps> = ({
    isOpen,
    onClose,
    onSuccess,
    team,
}) => {
    const [members, setMembers] = useState<Member[]>([]);
    const [selectedMemberId, setSelectedMemberId] = useState('');
    const [loading, setLoading] = useState(false);
    const [fetchingMembers, setFetchingMembers] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');

    useEffect(() => {
        if (isOpen) {
            fetchMembers();
        }
    }, [isOpen]);

    const fetchMembers = async () => {
        setFetchingMembers(true);
        try {
            const response = await api.get('/members');
            setMembers(response.data.data || []);
        } catch (error) {
            console.error('Error fetching members:', error);
            toast.error('Failed to load members');
        } finally {
            setFetchingMembers(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!selectedMemberId) {
            toast.error('Please select a member');
            return;
        }

        setLoading(true);
        try {
            await api.post(`/teams/${team.id}/members`, {
                memberId: selectedMemberId,
            });

            const selectedMember = members.find(m => m.id === selectedMemberId);
            toast.success(`${selectedMember?.fullName} added to ${team.name}`);
            onSuccess();
            handleClose();
        } catch (error: any) {
            console.error('Error adding team member:', error);
            toast.error(error.response?.data?.message || 'Failed to add member');
        } finally {
            setLoading(false);
        }
    };

    const handleClose = () => {
        if (!loading) {
            setSelectedMemberId('');
            setSearchQuery('');
            onClose();
        }
    };

    // Filter out existing team members and apply search
    const existingMemberIds = team.members.map(m => m.id);
    const filteredMembers = members.filter(member => {
        const matchesSearch = member.fullName.toLowerCase().includes(searchQuery.toLowerCase()) ||
            member.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
            member.fellowshipNumber.includes(searchQuery);

        const isNotInTeam = !existingMemberIds.includes(member.id);

        return matchesSearch && isNotInTeam;
    });

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="glass-card p-6 w-full max-w-lg">
                <div className="flex justify-between items-center mb-6">
                    <div>
                        <h2 className="text-2xl font-bold text-teal-400">Add Team Member</h2>
                        <p className="text-gray-400 text-sm mt-1">{team.name}</p>
                    </div>
                    {!loading && (
                        <button
                            onClick={handleClose}
                            className="p-2 hover:bg-gray-800 rounded-lg transition-colors"
                        >
                            <X className="text-gray-400" size={20} />
                        </button>
                    )}
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {/* Search */}
                    <div>
                        <label className="block text-sm text-gray-400 mb-2">
                            Search Members
                        </label>
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                            <input
                                type="text"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                placeholder="Search by name, email, or fellowship number..."
                                className="w-full pl-10 pr-4 py-2 bg-gray-800/50 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:border-teal-500"
                            />
                        </div>
                    </div>

                    {/* Member Selection */}
                    <div>
                        <label className="block text-sm text-gray-400 mb-2">
                            Select Member to Add *
                        </label>
                        {fetchingMembers ? (
                            <div className="flex items-center justify-center py-8 text-gray-500">
                                <Loader2 className="animate-spin mr-2" size={20} />
                                Loading members...
                            </div>
                        ) : filteredMembers.length === 0 ? (
                            <div className="text-center py-8 text-gray-500">
                                {searchQuery
                                    ? 'No members found matching your search'
                                    : 'All members are already in this team'}
                            </div>
                        ) : (
                            <div className="max-h-64 overflow-y-auto border border-gray-700 rounded-lg">
                                {filteredMembers.map((member) => (
                                    <label
                                        key={member.id}
                                        className={`flex items-center gap-3 p-3 cursor-pointer hover:bg-gray-800/50 transition-colors ${selectedMemberId === member.id ? 'bg-cyan-500/10 border-l-2 border-cyan-500' : ''
                                            }`}
                                    >
                                        <input
                                            type="radio"
                                            name="member"
                                            value={member.id}
                                            checked={selectedMemberId === member.id}
                                            onChange={(e) => setSelectedMemberId(e.target.value)}
                                            className="text-cyan-500 focus:ring-cyan-500"
                                        />
                                        <div className="flex-1">
                                            <p className="text-white font-medium">{member.fullName}</p>
                                            <p className="text-sm text-gray-400">{member.email}</p>
                                            <p className="text-xs text-gray-500">#{member.fellowshipNumber}</p>
                                        </div>
                                    </label>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Actions */}
                    <div className="flex gap-3 pt-4">
                        <button
                            type="button"
                            onClick={handleClose}
                            disabled={loading}
                            className="flex-1 px-6 py-3 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition-all disabled:opacity-50 disabled:cursor-not-allowed font-medium"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={loading || !selectedMemberId || fetchingMembers}
                            className="flex-1 px-6 py-3 bg-cyan-600 text-white rounded-lg hover:bg-cyan-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed font-medium"
                        >
                            {loading ? 'Adding...' : 'Add Member'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default AddTeamMemberModal;

import React, { useState, useEffect } from 'react';
import { X, AlertCircle, Search, Loader2 } from 'lucide-react';
import { toast } from 'react-hot-toast';
import api from '../../api';
import { useAuth } from '../../context/AuthContext';

interface AssignTeamLeaderModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
    team: {
        id: string;
        name: string;
        leader?: {
            id: string;
            fullName: string;
        } | null;
    };
}

interface Member {
    id: string;
    fullName: string;
    email: string;
    fellowshipNumber: string;
}

const AssignTeamLeaderModal: React.FC<AssignTeamLeaderModalProps> = ({
    isOpen,
    onClose,
    onSuccess,
    team,
}) => {
    const { refreshUser } = useAuth();
    const [members, setMembers] = useState<Member[]>([]);
    const [selectedMemberId, setSelectedMemberId] = useState('');
    const [loading, setLoading] = useState(false);
    const [fetchingMembers, setFetchingMembers] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');

    useEffect(() => {
        if (isOpen) {
            fetchMembers();
        }
    }, [isOpen]);

    const fetchMembers = async () => {
        setFetchingMembers(true);
        try {
            const response = await api.get('/members');
            setMembers(response.data.data || []);
        } catch (error) {
            console.error('Error fetching members:', error);
            toast.error('Failed to load members');
        } finally {
            setFetchingMembers(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!selectedMemberId) {
            toast.error('Please select a member');
            return;
        }

        setLoading(true);
        try {
            await api.post(`/teams/${team.id}/assign-leader`, {
                memberId: selectedMemberId,
            });

            const selectedMember = members.find(m => m.id === selectedMemberId);
            toast.success(`${selectedMember?.fullName} assigned as team leader`);
            // Refresh auth session so Navbar/profile tags update for the current user
            await refreshUser();
            onSuccess();
            handleClose();
        } catch (error: any) {
            console.error('Error assigning team leader:', error);
            toast.error(error.response?.data?.message || 'Failed to assign team leader');
        } finally {
            setLoading(false);
        }
    };

    const handleClose = () => {
        if (!loading) {
            setSelectedMemberId('');
            setSearchQuery('');
            onClose();
        }
    };

    // Filter out current leader and apply search
    const filteredMembers = members.filter(member => {
        const matchesSearch = member.fullName.toLowerCase().includes(searchQuery.toLowerCase()) ||
            member.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
            member.fellowshipNumber.includes(searchQuery);

        const isNotCurrentLeader = member.id !== team.leader?.id;

        return matchesSearch && isNotCurrentLeader;
    });

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="glass-card p-6 w-full max-w-lg">
                <div className="flex justify-between items-center mb-6">
                    <div>
                        <h2 className="text-2xl font-bold text-teal-400">
                            {team.leader ? 'Change' : 'Assign'} Team Leader
                        </h2>
                        <p className="text-gray-400 text-sm mt-1">{team.name}</p>
                    </div>
                    {!loading && (
                        <button
                            onClick={handleClose}
                            className="p-2 hover:bg-gray-800 rounded-lg transition-colors"
                        >
                            <X className="text-gray-400" size={20} />
                        </button>
                    )}
                </div>

                {team.leader && (
                    <div className="mb-4 p-3 bg-yellow-500/10 border border-yellow-500/30 rounded-lg">
                        <div className="flex items-start gap-2">
                            <AlertCircle className="text-yellow-400 flex-shrink-0 mt-0.5" size={18} />
                            <div className="text-sm">
                                <p className="text-yellow-400 font-medium">Current Leader</p>
                                <p className="text-gray-300">{team.leader.fullName}</p>
                                <p className="text-gray-400 text-xs mt-1">
                                    Selecting a new leader will remove the current leader's tag
                                </p>
                            </div>
                        </div>
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-4">
                    {/* Search */}
                    <div>
                        <label className="block text-sm text-gray-400 mb-2">
                            Search Members
                        </label>
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                            <input
                                type="text"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                placeholder="Search by name, email, or fellowship number..."
                                className="w-full pl-10 pr-4 py-2 bg-gray-800/50 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:border-teal-500"
                            />
                        </div>
                    </div>

                    {/* Member Selection */}
                    <div>
                        <label className="block text-sm text-gray-400 mb-2">
                            Select New Team Leader *
                        </label>
                        {fetchingMembers ? (
                            <div className="flex items-center justify-center py-8 text-gray-500">
                                <Loader2 className="animate-spin mr-2" size={20} />
                                Loading members...
                            </div>
                        ) : filteredMembers.length === 0 ? (
                            <div className="text-center py-8 text-gray-500">
                                {searchQuery ? 'No members found matching your search' : 'No available members'}
                            </div>
                        ) : (
                            <div className="max-h-64 overflow-y-auto border border-gray-700 rounded-lg">
                                {filteredMembers.map((member) => (
                                    <label
                                        key={member.id}
                                        className={`flex items-center gap-3 p-3 cursor-pointer hover:bg-gray-800/50 transition-colors ${selectedMemberId === member.id ? 'bg-teal-500/10 border-l-2 border-teal-500' : ''
                                            }`}
                                    >
                                        <input
                                            type="radio"
                                            name="member"
                                            value={member.id}
                                            checked={selectedMemberId === member.id}
                                            onChange={(e) => setSelectedMemberId(e.target.value)}
                                            className="text-teal-500 focus:ring-teal-500"
                                        />
                                        <div className="flex-1">
                                            <p className="text-white font-medium">{member.fullName}</p>
                                            <p className="text-sm text-gray-400">{member.email}</p>
                                            <p className="text-xs text-gray-500">#{member.fellowshipNumber}</p>
                                        </div>
                                    </label>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Actions */}
                    <div className="flex gap-3 pt-4">
                        <button
                            type="button"
                            onClick={handleClose}
                            disabled={loading}
                            className="flex-1 px-6 py-3 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition-all disabled:opacity-50 disabled:cursor-not-allowed font-medium"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={loading || !selectedMemberId || fetchingMembers}
                            className="flex-1 px-6 py-3 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed font-medium"
                        >
                            {loading ? 'Assigning...' : team.leader ? 'Change Leader' : 'Assign Leader'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default AssignTeamLeaderModal;

import React, { useState } from 'react';
import { X } from 'lucide-react';
import api from '../../api';
import { toast } from 'react-hot-toast';

interface CreateTeamModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

const CreateTeamModal: React.FC<CreateTeamModalProps> = ({ isOpen, onClose, onSuccess }) => {
    const [name, setName] = useState('');
    const [description, setDescription] = useState('');
    const [loading, setLoading] = useState(false);

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!name.trim()) {
            toast.error('Team name is required');
            return;
        }

        setLoading(true);
        try {
            await api.post('/teams', {
                name: name.trim(),
                description: description.trim() || undefined,
            });

