import { useEffect, useState } from 'react';
import { CheckCircle, XCircle, AlertTriangle, Info, X } from 'lucide-react';

export type ToastType = 'success' | 'error' | 'warning' | 'info';

export interface ToastProps {
    id: string;
    type: ToastType;
    message: string;
    duration?: number;
    onClose: (id: string) => void;
}

const Toast = ({ id, type, message, duration = 4000, onClose }: ToastProps) => {
    const [progress, setProgress] = useState(100);
    const [isExiting, setIsExiting] = useState(false);

    useEffect(() => {
        const interval = setInterval(() => {
            setProgress((prev) => {
                const newProgress = prev - (100 / (duration / 50));
                if (newProgress <= 0) {
                    clearInterval(interval);
                    handleClose();
                    return 0;
                }
                return newProgress;
            });
        }, 50);

        return () => clearInterval(interval);
    }, [duration]);

    const handleClose = () => {
        setIsExiting(true);
        setTimeout(() => onClose(id), 300);
    };

    const icons = {
        success: <CheckCircle className="w-6 h-6" />,
        error: <XCircle className="w-6 h-6" />,
        warning: <AlertTriangle className="w-6 h-6" />,
        info: <Info className="w-6 h-6" />,
    };

    // Standard light theme styling
    const styles = {
        success: 'bg-white border-green-200 text-slate-800 shadow-xl shadow-green-100',
        error: 'bg-white border-red-200 text-slate-800 shadow-xl shadow-red-100',
        warning: 'bg-white border-yellow-200 text-slate-800 shadow-xl shadow-yellow-100',
        info: 'bg-white border-blue-200 text-slate-800 shadow-xl shadow-blue-100',
    };

    const iconBgStyles = {
        success: 'bg-green-50 text-green-600',
        error: 'bg-red-50 text-red-600',
        warning: 'bg-yellow-50 text-yellow-600',
        info: 'bg-blue-50 text-blue-600',
    };

    const progressStyles = {
        success: 'bg-green-500',
        error: 'bg-red-500',
        warning: 'bg-yellow-500',
        info: 'bg-blue-500',
    };

    const topBarStyles = {
        success: 'bg-green-500',
        error: 'bg-red-500',
        warning: 'bg-yellow-500',
        info: 'bg-blue-500',
    };

    return (
        <div
            className={`
                pointer-events-auto max-w-md w-full rounded-xl border-2 shadow-2xl overflow-hidden
                transition-all duration-300 ease-out
                ${styles[type]}
                ${isExiting ? 'opacity-0 translate-x-full scale-95' : 'opacity-100 translate-x-0 scale-100'}
            `}
            role="alert"
            aria-live="polite"
        >
            {/* Top accent bar */}
            <div className={`h-1 w-full ${topBarStyles[type]}`}></div>

            <div className="p-4">
                <div className="flex items-start gap-4">
                    {/* Icon with glassmorphic background */}
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center shrink-0 ${iconBgStyles[type]}`}>
                        {icons[type]}
                    </div>

                    {/* Message */}
                    <div className="flex-1 min-w-0 pt-1">
                        <p className="text-sm font-semibold leading-relaxed">{message}</p>
                    </div>

                    {/* Close button */}
                    <button
                        onClick={handleClose}
                        className="text-slate-400 hover:text-slate-600 transition-colors shrink-0 mt-1 hover:bg-slate-100 rounded-full p-1"
                        aria-label="Close notification"
                    >
                        <X className="w-4 h-4" />
                    </button>
                </div>

                {/* Progress bar */}
                <div className="mt-3 h-1 bg-slate-100 rounded-full overflow-hidden">
                    <div
                        className={`h-full transition-all duration-50 linear ${progressStyles[type]}`}
                        style={{ width: `${progress}%` }}
                    />
                </div>
            </div>
        </div>
    );
};

export default Toast;

import { createContext, useContext, useState, useCallback } from 'react';
import type { ReactNode } from 'react';
import Toast from './Toast';
import type { ToastType } from './Toast';

interface ToastMessage {
    id: string;
    type: ToastType;
    message: string;
    duration?: number;
}

interface ToastContextType {
    showToast: (type: ToastType, message: string, duration?: number) => void;
    success: (message: string, duration?: number) => void;
    error: (message: string, duration?: number) => void;
    warning: (message: string, duration?: number) => void;
    info: (message: string, duration?: number) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export const useToast = () => {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error('useToast must be used within ToastProvider');
    }
    return context;
};

export const ToastProvider = ({ children }: { children: ReactNode }) => {
    const [toasts, setToasts] = useState<ToastMessage[]>([]);

    const showToast = useCallback((type: ToastType, message: string, duration: number = 4000) => {
        const id = Math.random().toString(36).substr(2, 9);
        setToasts((prev) => [...prev, { id, type, message, duration }]);
    }, []);

    const removeToast = useCallback((id: string) => {
        setToasts((prev) => prev.filter((toast) => toast.id !== id));
    }, []);

    const success = useCallback((message: string, duration?: number) => {
        showToast('success', message, duration);
    }, [showToast]);

    const error = useCallback((message: string, duration?: number) => {
        showToast('error', message, duration);
    }, [showToast]);

    const warning = useCallback((message: string, duration?: number) => {
        showToast('warning', message, duration);
    }, [showToast]);

    const info = useCallback((message: string, duration?: number) => {
        showToast('info', message, duration);
    }, [showToast]);

    return (
        <ToastContext.Provider value={{ showToast, success, error, warning, info }}>
            {children}
            {/* Toast Container */}
            <div
                className="fixed top-20 right-4 z-[9999] flex flex-col gap-3 pointer-events-none"
                aria-live="polite"
                aria-atomic="true"
            >
                {toasts.map((toast) => (
                    <Toast
                        key={toast.id}
                        id={toast.id}
                        type={toast.type}
                        message={toast.message}
                        duration={toast.duration}
                        onClose={removeToast}
                    />
                ))}
            </div>
        </ToastContext.Provider>
    );
};

import React, { useState, useEffect } from 'react';
import { X, Loader2, MapPin, Send } from 'lucide-react';
import api from '../api';
import { useToast } from './ToastProvider';
import CustomSelect from './CustomSelect';

interface TransferRequestModalProps {
    isOpen: boolean;
    onClose: () => void;
    currentRegionName: string;
}

interface Region {
    id: string;
    name: string;
}

const TransferRequestModal: React.FC<TransferRequestModalProps> = ({ isOpen, onClose, currentRegionName }) => {
    const { showToast } = useToast();
    const [regions, setRegions] = useState<Region[]>([]);
    const [loadingRegions, setLoadingRegions] = useState(false);
    
    const [selectedRegionId, setSelectedRegionId] = useState('');
    const [reason, setReason] = useState('');
    const [submitting, setSubmitting] = useState(false);

    useEffect(() => {
        if (isOpen) {
            fetchRegions();
            setSelectedRegionId('');
            setReason('');
        }
    }, [isOpen]);

    const fetchRegions = async () => {
        try {
            setLoadingRegions(true);
            const res = await api.get('/regions');
            setRegions(res.data);
        } catch (error) {
            showToast('error', 'Failed to load regions.');
        } finally {
            setLoadingRegions(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        
        if (!selectedRegionId) {
            showToast('error', 'Please select a destination region.');
            return;
        }

        try {
            setSubmitting(true);
            await api.post('/transfers', {
                toRegionId: selectedRegionId,
                reason,
            });
            showToast('success', 'Transfer request submitted successfully. Awaiting origin approval.');
            onClose();
        } catch (error: any) {
            showToast('error', error.response?.data?.message || 'Failed to submit transfer request.');
        } finally {
            setSubmitting(false);
        }
    };

    if (!isOpen) return null;

    // Filter out current region from options
    const regionOptions = [
        { value: '', label: 'Select destination region', disabled: true },
        ...regions
            .filter(r => r.name !== currentRegionName)
            .map(r => ({ value: r.id, label: r.name }))
    ];

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={onClose}></div>
            <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl relative z-10 overflow-hidden animate-fade-in">
                {/* Header */}
                <div className="px-6 py-5 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                    <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                        <MapPin className="text-[#48A111]" size={22} />
                        Request Region Transfer
                    </h2>
                    <button
                        onClick={onClose}
                        className="p-2 rounded-xl text-slate-400 hover:bg-slate-100 hover:text-slate-600 transition-colors"
                        disabled={submitting}
                    >
                        <X size={20} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-6 space-y-5">
                    
                    <div className="p-4 bg-[#e9f5e1]/50 border border-[#c5e3b0] rounded-xl text-sm text-slate-700">
                        <p>
                            You are currently assigned to <strong className="text-[#48A111]">{currentRegionName || 'No Region'}</strong>.
                        </p>
                        <p className="mt-1 text-slate-500">
                            Transferring requires approval from your current Regional Head and validation from the new Regional Head.
                        </p>
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-sm font-bold text-slate-700">Destination Region</label>
                        {loadingRegions ? (
                            <div className="h-12 bg-slate-50 border border-slate-200 rounded-xl flex items-center justify-center">
                                <Loader2 size={16} className="animate-spin text-slate-400" />
                            </div>
                        ) : (
                            <CustomSelect
                                value={selectedRegionId}
                                onChange={setSelectedRegionId}
                                options={regionOptions}
                                placeholder="Where do you want to transfer to?"
                            />
                        )}
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-sm font-bold text-slate-700">Reason for Request <span className="text-slate-400 font-normal">(Optional)</span></label>
                        <textarea
                            value={reason}
                            onChange={(e) => setReason(e.target.value)}
                            className="input min-h-[100px] resize-none transition-all focus:border-[#48A111] focus:ring-1 focus:ring-[#48A111]"
                            placeholder="Briefly explain why you are requesting this transfer..."
                            maxLength={500}
                        />
                        <p className="text-xs text-slate-400 text-right">{reason.length}/500</p>
                    </div>

                    <div className="pt-2">
                        <button
                            type="submit"
                            disabled={submitting || !selectedRegionId}
                            className="w-full py-3.5 px-4 bg-[#48A111] text-white font-bold rounded-xl shadow-md hover:shadow-lg hover:-translate-y-0.5 transition-all disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:translate-y-0 flex items-center justify-center gap-2"
                        >
                            {submitting ? (
                                <><Loader2 size={18} className="animate-spin" /> Submitting Request...</>
                            ) : (
                                <><Send size={18} /> Submit Transfer Request</>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default TransferRequestModal;

