                                <Flag size={20} /> Configure Bring 1 Campaign
                            </h2>
                            <button onClick={() => setShowCreateB1Modal(false)} className="text-slate-400 hover:text-slate-700">
                                <span className="text-2xl leading-none">&times;</span>
