                                    />
                                </div>
                            </div>
                            
                            <div className="pt-4 flex justify-end gap-3">
                                <button 
                                    type="button" 
                                    onClick={() => setEditMobData(null)}
                                    className="px-4 py-2 text-sm font-bold text-slate-600 hover:bg-slate-100 rounded-lg"
                                >
                                    Cancel
                                </button>
                                <button 
                                    type="submit" 
                                    className="px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-bold rounded-lg shadow-sm"
                                >
                                    Save Changes
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Edit Bring 1 Modal */}
            {editB1Data && (
                <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-scale-in">
                        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                            <h3 className="font-bold text-lg text-slate-900 flex items-center gap-2">
                                <Edit2 size={20} className="text-[#48A111]" /> Edit Bring 1 Config
                            </h3>
                        </div>
                        <form onSubmit={handleUpdateBring1Global} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-1">Initiative Title</label>
                                <input 
                                    type="text" required
                                    placeholder="e.g. Bring 1 Campaign"
                                    value={editB1Data.title}
                                    onChange={e => setEditB1Data({...editB1Data, title: e.target.value})}
                                    className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:border-[#48A111] transition-colors"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-1">Description (Optional)</label>
                                <textarea 
                                    value={editB1Data.description || ''}
                                    onChange={e => setEditB1Data({...editB1Data, description: e.target.value})}
                                    className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:border-[#48A111] transition-colors min-h-[80px]"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 mb-1">Min Pledges/Member</label>
                                    <input 
                                        type="number" required min="1"
                                        value={editB1Data.minPledges}
                                        onChange={e => setEditB1Data({...editB1Data, minPledges: e.target.value})}
                                        className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:border-[#48A111] transition-colors"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 mb-1">Override Target</label>
                                    <input 
                                        type="number" min="1" placeholder="Auto-calculated"
                                        value={editB1Data.manualTarget || ''}
                                        onChange={e => setEditB1Data({...editB1Data, manualTarget: e.target.value ? parseInt(e.target.value) : null})}
                                        className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:border-[#48A111] transition-colors"
                                    />
                                </div>
                            </div>
                            
                            <div className="pt-4 flex justify-end gap-3">
                                <button 
                                    type="button" 
                                    onClick={() => setEditB1Data(null)}
                                    className="px-4 py-2 text-sm font-bold text-slate-600 hover:bg-slate-100 rounded-lg"
                                >
                                    Cancel
                                </button>
                                <button 
                                    type="submit" 
                                    className="px-6 py-2 bg-[#48A111] hover:bg-[#387f0e] text-white text-sm font-bold rounded-lg shadow-sm"
                                >
                                    Save Changes
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Chat Modal Layer */}
            {chatEntity && (
                <ContactChatModal 
                    isOpen={!!chatEntity}
                    entityId={chatEntity.id}
                    entityName={chatEntity.name}
                    type={chatEntity.type}
                    currentUserId={currentUserId}
                    onClose={() => setChatEntity(null)} 
                    onMessagesRead={() => {
                        if (activeTab === 'mobilization') loadMobCampaignDetail(selectedMobCampaign.id);
                        if (activeTab === 'bring1') fetchBring1Pledges(selectedB1EventId);
                    }}
                />
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api';
import { toast } from 'react-hot-toast';
import {
    ArrowLeft, Users, Target, Activity, TrendingUp, UserCheck, Download, MapPin, 
    CheckCircle2, AlertCircle, FileSpreadsheet, ChevronDown, Send
} from 'lucide-react';
import * as XLSX from 'xlsx';

// ΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface CampaignReportData {
    campaign: {
        id: string;
        title: string;
        type: 'MOBILIZATION' | 'BRING_ONE';
        status: string;
        targetContactsPerMember: number;
        deadline: string;
    };
    stats: {
        totalTarget: number;
        membersSubmitted: number;
        contactsSubmitted: number;
        leadersSubmitted: number;
        averageContactsPerMember: number;
        statusBreakdown: { PENDING: number; CONFIRMED: number; NOT_CONFIRMED: number };
        regionBreakdown: Record<string, number>;
        successPercentage: number;
        duplicatePercentage: number;
        confirmationPercentage: number;
        pendingPercentage: number;
        notConfirmedPercentage: number;
    };
    drilldowns: {
        submitters: Array<{ memberId: string, name: string; region: string; isLeader: boolean; contactsCount: number }>;
        contacts: Array<{ id: string, contactName: string; phone: string; submittedBy: string; region: string; status: string; isDuplicate: boolean }>;
    };
}

// ΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function pct(value: number) {
    return `${Math.round(value)}%`;
}

// ΓöÇΓöÇ Sub-components ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function StatCard({ icon: Icon, label, value, sub, accent = '#48A111' }: any) {
    return (
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-5 flex flex-col gap-3 transition-shadow hover:shadow-md hover:border-slate-300">
            <div className="flex items-center gap-3">
                <div className="p-2 rounded-lg" style={{ backgroundColor: `${accent}18` }}>
                    <Icon size={18} style={{ color: accent }} />
                </div>
                <span className="text-slate-500 text-sm font-medium">{label}</span>
            </div>
            <p className="text-3xl font-bold text-slate-900">{value}</p>
            {sub && <div className="text-sm">{sub}</div>}
        </div>
    );
}

// ΓöÇΓöÇ Main Page ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export default function CampaignReport() {
    const { type, id } = useParams<{ type: string; id: string }>();
    const navigate = useNavigate();
    
    const [loading, setLoading] = useState(true);
    const [report, setReport] = useState<CampaignReportData | null>(null);

    // Pagination States
    const [submitterPage, setSubmitterPage] = useState(1);
    const [contactPage, setContactPage] = useState(1);
    const ITEMS_PER_PAGE = 10;

    useEffect(() => {
        fetchReport();
    }, [id, type]);

    const fetchReport = async () => {
        try {
            const endpoint = type === 'bring1' 
                ? `/bring-one/campaigns/${id}/report` 
                : `/campaigns/${id}/report`;
            
            const res = await api.get(endpoint);
            setReport(res.data);
        } catch (error: any) {
            console.error(error);
            toast.error('Failed to load campaign report.');
        } finally {
            setLoading(false);
        }
    };

    // ΓöÇΓöÇ Pagination Calculation ΓöÇΓöÇ //
    const paginatedSubmitters = report?.drilldowns.submitters.slice(
        (submitterPage - 1) * ITEMS_PER_PAGE, submitterPage * ITEMS_PER_PAGE
    ) || [];
    const totalSubmitterPages = Math.ceil((report?.drilldowns.submitters.length || 1) / ITEMS_PER_PAGE);

    const paginatedContacts = report?.drilldowns.contacts.slice(
        (contactPage - 1) * ITEMS_PER_PAGE, contactPage * ITEMS_PER_PAGE
    ) || [];
    const totalContactPages = Math.ceil((report?.drilldowns.contacts.length || 1) / ITEMS_PER_PAGE);

    // ΓöÇΓöÇ Export Logic ΓöÇΓöÇ //
    const exportToExcel = () => {
        if (!report) return;

        const wb = XLSX.utils.book_new();

        // 1. Overview Sheet
        const overviewData = [
            ['Metric', 'Value'],
            ['Campaign Name', report.campaign.title],
            ['Campaign Type', report.campaign.type],
            ['Status', report.campaign.status],
            ['Target per Member', report.campaign.targetContactsPerMember],
            ['Total Universe Target', report.stats.totalTarget],
            ['Members Who Submitted', report.stats.membersSubmitted],
            ['Leaders Who Submitted', report.stats.leadersSubmitted],
            ['Total Contacts Gathered', report.stats.contactsSubmitted],
            ['Success Progress', pct(report.stats.successPercentage)],
            ['Average Contacts / Member', report.stats.averageContactsPerMember],
            ['Confirmed Percentage', pct(report.stats.confirmationPercentage)],
            ['Pending Percentage', pct(report.stats.pendingPercentage)],
            ['Duplicate Percentage', pct(report.stats.duplicatePercentage)]
        ];
        const wsOverview = XLSX.utils.aoa_to_sheet(overviewData);
        wsOverview['!cols'] = [{ wch: 30 }, { wch: 20 }];
        XLSX.utils.book_append_sheet(wb, wsOverview, 'Overview');

        // 2. Submitters Sheet
        const wsSubmitters = XLSX.utils.json_to_sheet(report.drilldowns.submitters.map(s => ({
            'Member Name': s.name,
            'Region': s.region,
            'Is Leader': s.isLeader ? 'Yes' : 'No',
            'Contacts Submitted': s.contactsCount
        })));
        wsSubmitters['!cols'] = [{ wch: 30 }, { wch: 20 }, { wch: 15 }, { wch: 20 }];
        XLSX.utils.book_append_sheet(wb, wsSubmitters, 'Submitters');

        // 3. Raw Contacts Sheets (Grouped by Region)
        const regionMap = new Map<string, any[]>();
        report.drilldowns.contacts.forEach(c => {
            const r = c.region || 'Unassigned';
            if (!regionMap.has(r)) regionMap.set(r, []);
            regionMap.get(r)!.push(c);
        });

        let sheetCounter = 1;
        Array.from(regionMap.keys()).sort().forEach(regionName => {
            let sheetName = regionName.replace(/[^a-zA-Z0-9 ]/g, "").trim().substring(0, 31);
            if (!sheetName) sheetName = `Group ${sheetCounter++}`;
            
            // Check for sheet name collisions just in case
            if (wb.SheetNames.includes(sheetName)) {
                sheetName = `${sheetName.substring(0, 27)} ${sheetCounter++}`;
            }

            const regionContacts = regionMap.get(regionName)!;
            const wsContacts = XLSX.utils.json_to_sheet(regionContacts.map(c => ({
                'Contact/Pledge Name': c.contactName,
                'Phone/Email': c.phone,
                'Submitted By': c.submittedBy,
                'Region': c.region,
                'Call/Event Status': c.status,
                'Is Duplicate': c.isDuplicate ? 'Yes' : 'No'
            })));
            wsContacts['!cols'] = [{ wch: 30 }, { wch: 25 }, { wch: 30 }, { wch: 20 }, { wch: 20 }, { wch: 15 }];
            XLSX.utils.book_append_sheet(wb, wsContacts, sheetName);
        });

        if (regionMap.size === 0) {
            XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet([]), 'No Contacts');
        }

        // Save
        const safeTitle = report.campaign.title.replace(/[^a-z0-9]/gi, '_').toLowerCase();
        XLSX.writeFile(wb, `campaign_report_${safeTitle}.xlsx`);
    };

    if (loading) {
        return (
            <div className="flex h-[70vh] items-center justify-center">
                <div className="w-12 h-12 border-4 border-[#48A111] border-t-transparent rounded-full animate-spin"></div>
            </div>
        );
    }

    if (!report) {
        return (
            <div className="text-center py-20">
                <AlertCircle className="mx-auto text-slate-400 mb-4" size={48} />
                <h2 className="text-xl font-bold text-slate-700">Report Not Found</h2>
                <button 
                    onClick={() => navigate('/campaign-management')} 
                    className="mt-4 text-[#48A111] font-semibold hover:underline"
                >
                    Back to Campaigns
                </button>
            </div>
        );
    }

    const { campaign, stats } = report;

    return (
        <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500 pb-12">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                <div>
                    <button
                        onClick={() => navigate('/campaign-management')}
                        className="flex items-center gap-2 text-sm font-medium text-slate-500 hover:text-slate-900 mb-3"
                    >
                        <ArrowLeft size={16} /> Back to Campaigns
                    </button>
                    <div className="flex items-center gap-3 mb-2">
                        <div className="p-3 bg-indigo-100 text-indigo-700 rounded-xl">
                            <Target size={28} />
                        </div>
                        <div>
                            <h1 className="text-3xl font-bold tracking-tight text-slate-900">
                                {campaign.title}
                            </h1>
                            <div className="flex items-center gap-4 text-sm font-medium text-slate-500 mt-1">
                                <span className={`px-2 py-0.5 rounded-full text-xs font-bold ${
                                    campaign.status === 'OPEN' ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-700'
                                }`}>
                                    {campaign.status}
                                </span>
                                <span>{campaign.type.replace('_', ' ')}</span>
                                <span>Target: {stats.totalTarget} Total</span>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex gap-3">
                    <button
                        onClick={exportToExcel}
                        className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 hover:bg-slate-800 text-white rounded-xl font-semibold transition-colors shadow-sm"
                    >
                        <Download size={18} /> Export Full Report
                    </button>
                </div>
            </div>

            {/* KPI Section 1: Overview */}
            <div>
                <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                    <Activity size={20} className="text-[#48A111]" /> Headline Metrics
                </h2>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                    <StatCard
                        icon={TrendingUp} label="Total Mission Success"
                        value={pct(stats.successPercentage)} accent="#48A111"
                        sub={<span className="text-slate-500 text-xs">{stats.contactsSubmitted} of {stats.totalTarget} target reached</span>}
                    />
                    <StatCard
                        icon={Users} label="Participating Members"
                        value={stats.membersSubmitted} accent="#3b82f6"
                        sub={<span className="text-slate-500 text-xs">{stats.leadersSubmitted} are leaders</span>}
                    />
                    <StatCard
                        icon={Send} label="Total Contacts Gathered"
                        value={stats.contactsSubmitted} accent="#8b5cf6"
                        sub={<span className="text-slate-500 text-xs">Avg. {stats.averageContactsPerMember.toFixed(1)} per person</span>}
                    />
                    <StatCard
                        icon={CheckCircle2} label="Confirmed Success"
                        value={stats.statusBreakdown.CONFIRMED} accent="#f59e0b"
                        sub={<span className="text-slate-500 text-xs">{pct(stats.confirmationPercentage)} yield rate</span>}
                    />
                </div>
            </div>

            {/* KPI Section 2: Secondary Metrics */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white p-6 justify-between flex rounded-xl border border-slate-200">
                     <span className="text-slate-500 font-medium">Pending Processing</span>
                     <span className="text-xl font-bold text-slate-800">{stats.statusBreakdown.PENDING} <span className="text-sm font-normal text-slate-400">({pct(stats.pendingPercentage)})</span></span>
                </div>
                <div className="bg-white p-6 justify-between flex rounded-xl border border-slate-200">
                     <span className="text-slate-500 font-medium">Not Confirmed (Failed)</span>
                     <span className="text-xl font-bold text-slate-800">{stats.statusBreakdown.NOT_CONFIRMED} <span className="text-sm font-normal text-slate-400">({pct(stats.notConfirmedPercentage)})</span></span>
                </div>
                <div className="bg-white p-6 justify-between flex rounded-xl border border-slate-200">
                     <span className="text-slate-500 font-medium">Duplicate Entries</span>
                     <span className="text-xl font-bold text-slate-800 text-red-600">{pct(stats.duplicatePercentage)}</span>
                </div>
            </div>

            {/* Drilldown Tables */}
            <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                
                {/* Submitters Table */}
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col">
                    <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                        <h3 className="font-bold text-lg text-slate-800 flex items-center gap-2">
                            <UserCheck size={20} className="text-indigo-500"/> Participating Members
                        </h3>
                    </div>
                    <div className="overflow-x-auto flex-1">
                        <table className="w-full text-left text-sm">
                            <thead className="bg-slate-50/50 text-slate-500 border-b border-slate-100">
                                <tr>
                                    <th className="px-6 py-3 font-semibold">Name</th>
                                    <th className="px-6 py-3 font-semibold">Region</th>
                                    <th className="px-6 py-3 font-semibold text-center">Contacts</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {paginatedSubmitters.map((s, i) => (
                                    <tr key={i} className="hover:bg-slate-50 transition-colors">
                                        <td className="px-6 py-3 font-medium text-slate-900 flex items-center gap-2">
                                            {s.name}
                                            {s.isLeader && <span className="w-2 h-2 rounded-full bg-blue-500" title="Leader" />}
                                        </td>
                                        <td className="px-6 py-3 text-slate-600">{s.region}</td>
                                        <td className="px-6 py-3 text-center font-bold text-indigo-600">{s.contactsCount}</td>
                                    </tr>
                                ))}
                                {paginatedSubmitters.length === 0 && (
                                    <tr><td colSpan={3} className="px-6 py-8 text-center text-slate-500">No submissions yet</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                    {/* Pagination */}
                    {totalSubmitterPages > 1 && (
                        <div className="p-4 border-t border-slate-100 flex justify-between items-center bg-slate-50">
                            <button 
                                onClick={() => setSubmitterPage(p => Math.max(1, p - 1))}
                                disabled={submitterPage === 1}
                                className="px-3 py-1 bg-white border border-slate-200 rounded text-sm disabled:opacity-50 hover:bg-slate-50"
                            >Prev</button>
                            <span className="text-xs font-bold text-slate-500">Page {submitterPage} of {totalSubmitterPages}</span>
                            <button 
                                onClick={() => setSubmitterPage(p => Math.min(totalSubmitterPages, p + 1))}
                                disabled={submitterPage === totalSubmitterPages}
                                className="px-3 py-1 bg-white border border-slate-200 rounded text-sm disabled:opacity-50 hover:bg-slate-50"
                            >Next</button>
                        </div>
                    )}
                </div>

                {/* Contacts Table */}
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col">
                    <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                        <h3 className="font-bold text-lg text-slate-800 flex items-center gap-2">
                            <FileSpreadsheet size={20} className="text-green-600"/> Raw Contacts Pipeline
                        </h3>
                    </div>
                    <div className="overflow-x-auto flex-1">
                        <table className="w-full text-left text-sm">
                            <thead className="bg-slate-50/50 text-slate-500 border-b border-slate-100">
                                <tr>
                                    <th className="px-6 py-3 font-semibold">Contact / Pledge</th>
                                    <th className="px-6 py-3 font-semibold">Submitted By</th>
                                    <th className="px-6 py-3 font-semibold">Status</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {paginatedContacts.map((c, i) => (
                                    <tr key={i} className={`hover:bg-slate-50 transition-colors ${c.isDuplicate ? 'bg-red-50/30' : ''}`}>
                                        <td className="px-6 py-3 font-medium text-slate-900">
                                            {c.contactName}
                                            {c.isDuplicate && <span className="ml-2 text-[10px] font-bold text-red-500 bg-red-100 px-1.5 py-0.5 rounded">DUP</span>}
                                        </td>
                                        <td className="px-6 py-3 text-slate-600">{c.submittedBy}</td>
                                        <td className="px-6 py-3">
                                            <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                                                c.status === 'CONFIRMED' ? 'bg-green-100 text-green-700' :
                                                c.status === 'NOT_CONFIRMED' ? 'bg-red-100 text-red-700' :
                                                'bg-amber-100 text-amber-700'
                                            }`}>
                                                {c.status}
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                                {paginatedContacts.length === 0 && (
                                    <tr><td colSpan={3} className="px-6 py-8 text-center text-slate-500">No contacts yet</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                    {/* Pagination */}
                    {totalContactPages > 1 && (
                        <div className="p-4 border-t border-slate-100 flex justify-between items-center bg-slate-50">
                            <button 
                                onClick={() => setContactPage(p => Math.max(1, p - 1))}
                                disabled={contactPage === 1}
                                className="px-3 py-1 bg-white border border-slate-200 rounded text-sm disabled:opacity-50 hover:bg-slate-50"
                            >Prev</button>
                            <span className="text-xs font-bold text-slate-500">Page {contactPage} of {totalContactPages}</span>
                            <button 
                                onClick={() => setContactPage(p => Math.min(totalContactPages, p + 1))}
                                disabled={contactPage === totalContactPages}
                                className="px-3 py-1 bg-white border border-slate-200 rounded text-sm disabled:opacity-50 hover:bg-slate-50"
                            >Next</button>
                        </div>
                    )}
                </div>

            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import api from '../api';
import { Target, Users, Loader2, Calendar, Plus, Trash2, CheckCircle2, AlertCircle, AlertTriangle, Phone, Pencil, X, Check, MessageCircle } from 'lucide-react';
import { useToast } from '../components/ToastProvider';
import ContactChatModal from '../components/Campaigns/ContactChatModal';

export default function Campaigns() {
    const { showToast } = useToast();
    const [loading, setLoading] = useState(true);
    const [campaigns, setCampaigns] = useState<any[]>([]);
    
    // State for the currently selected campaign to submit to
    const [activeCampaignId, setActiveCampaignId] = useState<string | null>(null);
    const [activeCampaignDetail, setActiveCampaignDetail] = useState<any | null>(null);
    const [newContacts, setNewContacts] = useState([{ name: '', phone: '', email: '', relationship: '', callStatus: 'PENDING', transportNeed: 'PENDING', location: '' }]);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [editingContact, setEditingContact] = useState<{ id: string; name: string; phone: string; email: string; relationship: string; transportNeed: string; location: string } | null>(null);

    // Chat State
    const [chatEntity, setChatEntity] = useState<{ id: string; name: string } | null>(null);

    const getUserIdFromToken = () => {
        const token = localStorage.getItem('token');
        if (!token) return '';
        try {
            const payload = JSON.parse(atob(token.split('.')[1]));
            return payload.id;
        } catch {
            return '';
        }
    };
    const currentUserId = getUserIdFromToken();

    useEffect(() => {
        fetchCampaigns();
    }, []);

    const fetchCampaigns = async () => {
        try {
            setLoading(true);
            const res = await api.get('/campaigns');
            const data = res.data;
            setCampaigns(data);
            if (data.length > 0) {
                const firstId = activeCampaignId || data[0].id;
                setActiveCampaignId(firstId);
                fetchCampaignDetail(firstId);
            }
        } catch (error) {
            console.error('Failed to fetch campaigns:', error);
            showToast('error', 'Failed to load campaigns');
        } finally {
            setLoading(false);
        }
    };

    const fetchCampaignDetail = async (id: string) => {
        try {
            const res = await api.get(`/campaigns/${id}`);
            setActiveCampaignDetail(res.data);
        } catch (error) {
            console.error('Failed to fetch campaign detail:', error);
        }
    };

    const handleAddRow = () => {
        setNewContacts([...newContacts, { name: '', phone: '', email: '', relationship: '', callStatus: 'PENDING', transportNeed: 'PENDING', location: '' }]);
    };

    const handleRemoveRow = (index: number) => {
        if (newContacts.length === 1) return;
        setNewContacts(newContacts.filter((_, i) => i !== index));
    };

    const handleChange = (index: number, field: string, value: string) => {
        const updated = [...newContacts];
        updated[index] = { ...updated[index], [field]: value };
        setNewContacts(updated);
    };

    const handleSubmitContacts = async (e: React.FormEvent, campaign: any) => {
        e.preventDefault();
        
        const validContacts = newContacts.filter(c => {
            if (!c.name.trim() || !c.phone.trim()) return false;
            if (c.transportNeed === 'NEEDS_TRANSPORT' && !c.location.trim()) return false;
            return true;
        });
        if (validContacts.length === 0) {
            showToast('error', 'Please provide name, phone, and location (if transport is needed) for at least one contact');
            return;
        }

        const remainingSlots = campaign.maxContacts - (campaign.contacts?.length || 0);
        if (validContacts.length > remainingSlots) {
            showToast('error', `You can only submit ${remainingSlots} more contacts for this campaign`);
            return;
        }

        try {
            setIsSubmitting(true);
            await api.post(`/campaigns/${campaign.id}/contacts`, { contacts: validContacts });
            showToast('success', 'Contacts submitted successfully!');
            setNewContacts([{ name: '', phone: '', email: '', relationship: '', callStatus: 'PENDING', transportNeed: 'PENDING', location: '' }]);
            fetchCampaigns(); // refresh to show updated progress
            fetchCampaignDetail(campaign.id); // also refresh detail view
        } catch (error: any) {
            console.error('Submit error:', error);
            showToast('error', error.response?.data?.message || 'Failed to submit contacts');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleUpdateCallStatus = async (campaignId: string, contactId: string, callStatus: string) => {
        try {
            await api.patch(`/campaigns/${campaignId}/contacts/${contactId}`, { callStatus });
            fetchCampaignDetail(campaignId);
        } catch (error: any) {
            showToast('error', error.response?.data?.message || 'Failed to update status');
        }
    };

    const handleSaveContactEdit = async (campaignId: string) => {
        if (!editingContact) return;
        try {
            await api.patch(`/campaigns/${campaignId}/contacts/${editingContact.id}`, {
                name: editingContact.name,
                phone: editingContact.phone,
                email: editingContact.email,
                relationship: editingContact.relationship,
                transportNeed: editingContact.transportNeed,
                location: editingContact.location,
            });
            showToast('success', 'Contact updated!');
            setEditingContact(null);
            fetchCampaignDetail(campaignId);
        } catch (error: any) {
            showToast('error', error.response?.data?.message || 'Failed to update contact');
        }
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center py-20 animate-fade-in">
                <Loader2 size={40} className="animate-spin text-[#48A111]" />
            </div>
        );
    }

    if (campaigns.length === 0) {
        return (
            <div className="max-w-4xl mx-auto p-12 text-center bg-white rounded-3xl border border-slate-200 shadow-xl mt-8 animate-fade-in">
                <div className="w-24 h-24 rounded-full bg-slate-50 border-4 border-slate-100 flex items-center justify-center mx-auto mb-6">
                    <Target size={40} className="text-slate-400" />
                </div>
                <h2 className="text-2xl font-bold text-slate-800 mb-3">No Active Campaigns</h2>
                <p className="text-slate-500 text-lg">There are currently no open mobilization campaigns. Check back later!</p>
            </div>
        );
    }

    const activeCampaign = campaigns.find((c: any) => c.id === activeCampaignId) || campaigns[0];
    // Use _count.contacts (from list view) for progress tracking
    const userSubmittedCount = activeCampaignDetail?.contacts?.length || 0;
    const totalContactCount = activeCampaign._count?.contacts || 0;
    const isFull = userSubmittedCount >= activeCampaign.maxContacts;
    const remainingSlots = activeCampaign.maxContacts - userSubmittedCount;
    
    const deadlineStr = new Date(activeCampaign.submissionDeadline).toLocaleDateString('en-GB', {
        weekday: 'short', day: 'numeric', month: 'long', year: 'numeric'
    });
    
    const now = new Date();
    const deadlineDate = new Date(activeCampaign.submissionDeadline);
    const isPastDeadline = now > deadlineDate;

    return (
        <div className="max-w-7xl mx-auto space-y-8 animate-fade-in">
            {/* Header */}
            <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-3">
                    <div className="p-3 rounded-xl bg-[#e9f5e1] text-[#48A111]">
                        <Target className="w-6 h-6" />
                    </div>
                    <div>
                        <h1 className="text-3xl font-bold text-slate-900">Mobilization Campaigns</h1>
                        <p className="text-slate-500 text-sm">Contribute to ongoing fellowship outreach efforts</p>
                    </div>
                </div>
            </div>

            <div className="grid lg:grid-cols-3 gap-8">
                {/* Left Col: Campaign Selector */}
                <div className="lg:col-span-1 space-y-4">
                    <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider px-2">Open Campaigns</h3>
                    {campaigns.map((camp: any) => (
                        <button
                            key={camp.id}
                            onClick={() => {
                                setActiveCampaignId(camp.id);
                                fetchCampaignDetail(camp.id);
                            }}
                            className={`w-full text-left p-5 rounded-2xl border transition-all cursor-pointer ${
                                activeCampaignId === camp.id 
                                ? 'bg-white border-[#48A111] shadow-md ring-1 ring-[#48A111]' 
                                : 'bg-slate-50 border-slate-200 hover:bg-white hover:border-slate-300 shadow-sm'
                            }`}
                        >
                            <div className="flex justify-between items-start mb-2">
                                <h4 className={`font-bold ${activeCampaignId === camp.id ? 'text-[#48A111]' : 'text-slate-800'}`}>
                                    {camp.title}
                                </h4>
                                {(camp._count?.contacts || 0) >= camp.maxContacts && (
                                    <CheckCircle2 size={16} className="text-[#48A111]" />
                                )}
                            </div>
                            <div className="flex items-center gap-1.5 text-xs text-slate-500 mb-3">
                                <Calendar size={12} /> Ends {new Date(camp.submissionDeadline).toLocaleDateString()}
                            </div>
                            
                            {/* Mini Progress Bar */}
                            <div className="space-y-1">
                                <div className="flex justify-between text-[10px] font-bold text-slate-400">
                                    <span>Progress</span>
                                    <span>{camp._count?.contacts || 0} / {camp.maxContacts}</span>
                                </div>
                                <div className="h-1.5 w-full bg-slate-200 rounded-full overflow-hidden">
                                    <div 
                                        className="h-full bg-[#48A111] transition-all duration-500"
                                        style={{ width: `${Math.min(100, ((camp._count?.contacts || 0) / camp.maxContacts) * 100)}%` }}
                                    />
                                </div>
                            </div>
                        </button>
                    ))}
                </div>

                {/* Right Col: Active Campaign Details & Form */}
                <div className="lg:col-span-2 space-y-6">
                    {/* Active Campaign Header */}
                    <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-64 h-64 bg-[#e9f5e1] rounded-full blur-3xl opacity-50 -translate-y-1/2 translate-x-1/3"></div>
                        <div className="relative z-10">
                            <h2 className="text-2xl font-bold text-slate-900 mb-2">{activeCampaign.title}</h2>
                            <p className="text-slate-600 mb-6">{activeCampaign.description || 'No description provided.'}</p>
                            
                            <div className="flex flex-wrap gap-4">
                                <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-xl border border-slate-100">
                                    <Calendar className="text-slate-400" size={18} />
                                    <span className="text-sm font-semibold text-slate-700">Deadline: {deadlineStr}</span>
                                </div>
                                <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-xl border border-slate-100">
                                    <Users className="text-slate-400" size={18} />
                                    <span className="text-sm font-semibold text-slate-700">Goal: Up to {activeCampaign.maxContacts} contacts</span>
                                </div>
                                <div className="flex items-center gap-2 px-4 py-2 bg-[#e9f5e1] rounded-xl border border-[#c5e3b0]">
                                    <CheckCircle2 className="text-[#48A111]" size={18} />
                                    <span className="text-sm font-semibold text-[#387f0e]">My submitted: {userSubmittedCount} / {activeCampaign.maxContacts}</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Submission Section */}
                    {isPastDeadline ? (
                        <div className="p-8 bg-amber-50 rounded-2xl border border-amber-200 text-center">
                            <AlertCircle size={40} className="mx-auto text-amber-500 mb-3" />
                            <h3 className="text-xl font-bold text-amber-800 mb-1">Submission Closed</h3>
                            <p className="text-amber-700 font-medium">The deadline for this campaign has passed.</p>
                        </div>
                    ) : isFull ? (
                        <div className="p-8 bg-[#e9f5e1] rounded-2xl border border-[#c5e3b0] text-center">
                            <CheckCircle2 size={40} className="mx-auto text-[#48A111] mb-3" />
                            <h3 className="text-xl font-bold text-[#387f0e] mb-1">Target Reached!</h3>
                            <p className="text-[#48A111] font-medium">You have successfully submitted your maximum allowed contacts ({activeCampaign.maxContacts}) for this campaign.</p>
                        </div>
                    ) : (
                        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                            <div className="px-6 py-5 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                                <div>
                                    <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                                        <Plus className="text-[#48A111]" /> Submit Contacts
                                    </h3>
                                    <p className="text-xs text-slate-500 mt-1">
                                        You can submit {remainingSlots} more contacts.
                                    </p>
                                </div>
                                <div className="text-right">
                                    <span className="text-2xl font-extrabold text-[#48A111]">{userSubmittedCount}</span>
                                    <span className="text-slate-400 font-bold"> / {activeCampaign.maxContacts}</span>
                                </div>
                            </div>

                            <form onSubmit={(e) => handleSubmitContacts(e, activeCampaign)} className="p-6">
                                <div className="space-y-4">
                                    {newContacts.map((contact, index) => (
                                        <div key={index} className="flex gap-4 items-start p-4 bg-slate-50 rounded-2xl border border-slate-100">
                                            <div className="flex items-center justify-center w-6 h-6 rounded-full bg-slate-200 text-slate-500 text-xs font-bold shrink-0 mt-2">
                                                {index + 1}
                                            </div>
                                            <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4">
                                                <input 
                                                    type="text" 
                                                    placeholder="Full Name *" 
                                                    required
                                                    value={contact.name}
                                                    onChange={(e) => handleChange(index, 'name', e.target.value)}
                                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-[#48A111] focus:ring-1 focus:ring-[#48A111] outline-none transition-all text-sm bg-white"
                                                />
                                                <input 
                                                    type="tel" 
                                                    placeholder="Phone Number *" 
                                                    required
                                                    value={contact.phone}
                                                    onChange={(e) => handleChange(index, 'phone', e.target.value)}
                                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-[#48A111] focus:ring-1 focus:ring-[#48A111] outline-none transition-all text-sm bg-white"
                                                />
                                                <input 
                                                    type="email" 
                                                    placeholder="Email (Optional)" 
                                                    value={contact.email}
                                                    onChange={(e) => handleChange(index, 'email', e.target.value)}
                                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-[#48A111] focus:ring-1 focus:ring-[#48A111] outline-none transition-all text-sm bg-white"
                                                />
                                                <input 
                                                    type="text" 
                                                    placeholder="Relationship (e.g. Friend, Colleague)" 
                                                    value={contact.relationship}
                                                    onChange={(e) => handleChange(index, 'relationship', e.target.value)}
                                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-[#48A111] focus:ring-1 focus:ring-[#48A111] outline-none transition-all text-sm bg-white"
                                                />
                                                <select
                                                    value={contact.callStatus}
                                                    onChange={(e) => handleChange(index, 'callStatus', e.target.value)}
                                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-[#48A111] focus:ring-1 focus:ring-[#48A111] outline-none transition-all text-sm bg-white font-medium text-slate-700"
                                                >
                                                    <option value="PENDING">Status: Pending</option>
                                                    <option value="CONFIRMED">Status: Confirmed</option>
                                                    <option value="NOT_CONFIRMED">Status: Dropped Out</option>
                                                </select>
                                                <select
                                                    value={contact.transportNeed}
                                                    onChange={(e) => handleChange(index, 'transportNeed', e.target.value)}
                                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-[#48A111] focus:ring-1 focus:ring-[#48A111] outline-none transition-all text-sm bg-white font-medium text-slate-700"
                                                >
                                                    <option value="PENDING">Transport: Pending</option>
                                                    <option value="NEEDS_TRANSPORT">Needs Transport</option>
                                                    <option value="DOES_NOT_NEED_TRANSPORT">Doesn't Need Transport</option>
                                                </select>
                                                {contact.transportNeed === 'NEEDS_TRANSPORT' && (
                                                    <input 
                                                        type="text" 
                                                        placeholder="Location *" 
                                                        required
                                                        value={contact.location}
                                                        onChange={(e) => handleChange(index, 'location', e.target.value)}
                                                        className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-[#48A111] focus:ring-1 focus:ring-[#48A111] outline-none transition-all text-sm bg-white md:col-span-2"
                                                    />
                                                )}
                                            </div>
                                            <button 
                                                type="button" 
                                                onClick={() => handleRemoveRow(index)}
                                                disabled={newContacts.length === 1}
                                                className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-30 disabled:hover:bg-transparent mt-1"
                                                title="Remove row"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </div>
                                    ))}
                                </div>

                                <div className="mt-6 flex flex-col md:flex-row justify-between items-center gap-4 pt-6 border-t border-slate-100">
                                    <button 
                                        type="button" 
                                        onClick={handleAddRow}
                                        disabled={userSubmittedCount + newContacts.length >= activeCampaign.maxContacts}
                                        className="flex items-center gap-2 text-sm font-bold text-[#48A111] hover:bg-[#e9f5e1] px-4 py-2 rounded-xl transition-colors disabled:opacity-50 disabled:hover:bg-transparent"
                                    >
                                        <Plus size={18} /> Add Another Contact Row
                                    </button>
                                    
                                    <button 
                                        type="submit" 
                                        disabled={isSubmitting || userSubmittedCount + newContacts.length > activeCampaign.maxContacts}
                                        className="w-full md:w-auto px-8 py-3 bg-[#48A111] text-white font-bold rounded-xl shadow-lg hover:shadow-xl hover:-translate-y-0.5 transition-all disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none flex items-center justify-center gap-2"
                                    >
                                        {isSubmitting ? <Loader2 size={18} className="animate-spin" /> : 'Submit Contacts'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    )}
                    
                    {/* Previously Submitted Contacts with Call Status Tracking */}
                    {activeCampaignDetail?.contacts && activeCampaignDetail.contacts.length > 0 && (
                        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                            <div className="px-6 pt-5 pb-3 border-b border-slate-100 flex justify-between items-center">
                                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider">
                                    My Submitted Contacts
                                </h3>
                                <span className="bg-slate-100 text-slate-600 px-2 py-0.5 rounded-md text-xs font-bold">
                                    {activeCampaignDetail.contacts.length} Total
                                </span>
                            </div>
                            
                            {/* Duplicate warning banner */}
                            {activeCampaignDetail.contacts.some((c: any) => c.isDuplicate) && (
                                <div className="mx-4 mt-3 px-4 py-2.5 bg-amber-50 border border-amber-200 rounded-xl flex items-center gap-2 text-amber-700 text-sm">
                                    <AlertTriangle size={16} className="shrink-0" />
                                    <span><strong>Note:</strong> Some contacts are flagged as duplicates ΓÇö they share a phone number or email already on this campaign.</span>
                                </div>
                            )}

                            <div className="p-4 grid sm:grid-cols-2 gap-3">
                                {activeCampaignDetail.contacts.map((c: any) => (
                                    <div key={c.id} className={`p-4 rounded-xl border flex flex-col gap-2 ${c.isDuplicate ? 'border-amber-200 bg-amber-50/50' : 'border-slate-100 bg-slate-50'}`}>
                                        {editingContact?.id === c.id ? (
                                            /* ΓöÇΓöÇ Inline Edit Form ΓöÇΓöÇ */
                                            <div className="flex flex-col gap-2">
                                                <input
                                                    className="text-sm border border-slate-300 rounded-lg px-2.5 py-1.5 outline-none focus:border-[#48A111]"
                                                    placeholder="Name"
                                                    value={editingContact!.name}
                                                    onChange={e => setEditingContact({ ...editingContact!, name: e.target.value })}
                                                />
                                                <input
                                                    className="text-sm border border-slate-300 rounded-lg px-2.5 py-1.5 outline-none focus:border-[#48A111]"
                                                    placeholder="Phone"
                                                    value={editingContact!.phone}
                                                    onChange={e => setEditingContact({ ...editingContact!, phone: e.target.value })}
                                                />
                                                <input
                                                    className="text-sm border border-slate-300 rounded-lg px-2.5 py-1.5 outline-none focus:border-[#48A111]"
                                                    placeholder="Email (optional)"
                                                    value={editingContact!.email}
                                                    onChange={e => setEditingContact({ ...editingContact!, email: e.target.value })}
                                                />
                                                <input
                                                    className="text-sm border border-slate-300 rounded-lg px-2.5 py-1.5 outline-none focus:border-[#48A111]"
                                                    placeholder="Relationship (optional)"
                                                    value={editingContact!.relationship}
                                                    onChange={e => setEditingContact({ ...editingContact!, relationship: e.target.value })}
                                                />
                                                <select
                                                    className="text-sm border border-slate-300 rounded-lg px-2.5 py-1.5 outline-none focus:border-[#48A111]"
                                                    value={editingContact!.transportNeed}
                                                    onChange={e => setEditingContact({ ...editingContact!, transportNeed: e.target.value })}
                                                >
                                                    <option value="PENDING">Transport: Pending</option>
                                                    <option value="NEEDS_TRANSPORT">Needs Transport</option>
                                                    <option value="DOES_NOT_NEED_TRANSPORT">Doesn't Need Transport</option>
                                                </select>
                                                {editingContact!.transportNeed === 'NEEDS_TRANSPORT' && (
                                                    <input
                                                        className="text-sm border border-slate-300 rounded-lg px-2.5 py-1.5 outline-none focus:border-[#48A111]"
                                                        placeholder="Location *"
                                                        value={editingContact!.location}
                                                        onChange={e => setEditingContact({ ...editingContact!, location: e.target.value })}
                                                    />
                                                )}
                                                <div className="flex gap-2 mt-1">
                                                    <button
                                                        onClick={() => handleSaveContactEdit(activeCampaign.id)}
                                                        className="flex-1 flex items-center justify-center gap-1.5 text-xs font-bold bg-[#48A111] text-white px-3 py-1.5 rounded-lg hover:bg-[#3a8a0e] transition-colors"
                                                    >
                                                        <Check size={13} /> Save
                                                    </button>
                                                    <button
                                                        onClick={() => setEditingContact(null)}
                                                        className="flex-1 flex items-center justify-center gap-1.5 text-xs font-bold bg-slate-200 text-slate-600 px-3 py-1.5 rounded-lg hover:bg-slate-300 transition-colors"
                                                    >
                                                        <X size={13} /> Cancel
                                                    </button>
                                                </div>
                                            </div>
                                        ) : (
                                            /* ΓöÇΓöÇ View Mode ΓöÇΓöÇ */
                                            <>
                                                <div className="flex items-start justify-between gap-2">
                                                    <div>
                                                        <div className="font-bold text-slate-800 text-sm flex items-center gap-1.5">
                                                            {c.name}
                                                            {c.isDuplicate && (
                                                                <span className="text-[10px] font-bold px-1.5 py-0.5 bg-amber-100 text-amber-700 border border-amber-200 rounded-full">DUPLICATE</span>
                                                            )}
                                                        </div>
                                                        <div className="text-xs text-slate-500 flex items-center gap-1 mt-0.5">
                                                            <Phone size={11} /> {c.phone}
                                                            {c.email && <span className="ml-2 text-slate-400">{c.email}</span>}
                                                        </div>
                                                        {c.relationship && (
                                                            <span className="text-[10px] text-slate-400 bg-slate-200/60 px-1.5 py-0.5 rounded mt-1 inline-block">{c.relationship}</span>
                                                        )}
                                                        {c.transportNeed && c.transportNeed !== 'PENDING' && (
                                                            <span className={`text-[10px] px-1.5 py-0.5 rounded mt-1 inline-block ml-1 ${c.transportNeed === 'NEEDS_TRANSPORT' ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-200/60 text-slate-500'}`}>
                                                                {c.transportNeed === 'NEEDS_TRANSPORT' ? `Needs Transport${c.location ? ` (${c.location})` : ''}` : 'No Transport Needed'}
                                                            </span>
                                                        )}
                                                    </div>
                                                    <div className="flex flex-col gap-2 shrink-0">
                                                        <button
                                                            onClick={() => setChatEntity({ id: c.id, name: c.name })}
                                                            className="p-1.5 text-cyan-600 hover:bg-cyan-50 rounded-lg transition-colors relative"
                                                            title="Chat with Admin"
                                                        >
                                                            <MessageCircle size={16} />
                                                            {c._count?.messages > 0 && (
                                                                <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>
                                                            )}
                                                        </button>
                                                        {activeCampaign.status === 'OPEN' && (
                                                            <button
                                                                onClick={() => setEditingContact({ id: c.id, name: c.name, phone: c.phone, email: c.email || '', relationship: c.relationship || '', transportNeed: c.transportNeed || 'PENDING', location: c.location || '' })}
                                                                className="p-1.5 text-slate-400 hover:text-[#48A111] hover:bg-[#e9f5e1] rounded-lg transition-colors"
                                                                title="Edit contact"
                                                            >
                                                                <Pencil size={15} />
                                                            </button>
                                                        )}
                                                    </div>
                                                </div>
                                                {/* Call status tracker */}
                                                <div className="pt-2 border-t border-slate-100">
                                                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider block mb-1">Follow-up Status</label>
                                                    <select
                                                        value={c.callStatus}
                                                        onChange={(e) => handleUpdateCallStatus(activeCampaign.id, c.id, e.target.value)}
                                                        className={`w-full text-xs font-bold rounded-lg px-2.5 py-1.5 border transition-colors outline-none cursor-pointer ${
                                                            c.callStatus === 'PENDING'       ? 'bg-slate-100 text-slate-600 border-slate-200' :
                                                            c.callStatus === 'CONFIRMED'     ? 'bg-emerald-100 text-emerald-700 border-emerald-200' :
                                                                                               'bg-red-100 text-red-700 border-red-200'
                                                        }`}
                                                    >
                                                        <option value="PENDING">Pending</option>
                                                        <option value="CONFIRMED">Confirmed Attending</option>
                                                        <option value="NOT_CONFIRMED">Not Confirmed</option>
                                                    </select>
                                                </div>
                                            </>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Chat Modal */}
                    {chatEntity && (
                        <ContactChatModal
                            isOpen={!!chatEntity}
                            onClose={() => setChatEntity(null)}
                            entityId={chatEntity.id}
                            entityName={chatEntity.name}
                            type="MOBILIZATION"
                            currentUserId={currentUserId}
                            onMessagesRead={() => {
                                if (activeCampaignId) fetchCampaignDetail(activeCampaignId);
                            }}
                        />
                    )}

                </div>
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { Html5QrcodeScanner } from 'html5-qrcode';
import api from '../api';
import { Scan, CheckCircle, XCircle, Zap, Camera, AlertTriangle, Loader2, RefreshCw, Hash, User } from 'lucide-react';
import EventSelector from '../components/EventSelector';
import type { Event } from '../types/event';
import { useLiveQuery } from 'dexie-react-hooks';
import db from '../db';

interface MemberData {
    id: string;
    fullName: string;
    fellowshipNumber: string;
    phoneNumber: string;
    region: {
        id: string;
        name: string;
    };
}

const CheckIn = () => {
    const [activeEvents, setActiveEvents] = useState<Event[]>([]);
    const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);
    const [result, setResult] = useState('');
    const [scanning, setScanning] = useState(false);
    const [status, setStatus] = useState<'idle' | 'success' | 'error' | 'loading'>('idle');
    const [message, setMessage] = useState('');
    const [permissionDenied, setPermissionDenied] = useState(false);
    const [accessDenied, setAccessDenied] = useState(false);
    const scannerRef = useRef<Html5QrcodeScanner | null>(null);

    // Fellowship number check-in states
    const [fellowshipNumber, setFellowshipNumber] = useState('');
    const [fellowshipLookupLoading, setFellowshipLookupLoading] = useState(false);
    const [memberData, setMemberData] = useState<MemberData | null>(null);
    const [showConfirmation, setShowConfirmation] = useState(false);

    // Offline Roster state
    const [isSyncingRoster, setIsSyncingRoster] = useState(false);
    const pendingSyncCount = useLiveQuery(
        () => selectedEvent ? db.syncQueue.where('eventId').equals(selectedEvent.id).count() : 0,
        [selectedEvent?.id]
    ) || 0;

    // Check if the current event has a roster downloaded
    const rosterCount = useLiveQuery(
        () => selectedEvent ? db.roster.where('eventId').equals(selectedEvent.id).count() : 0,
        [selectedEvent?.id]
    ) || 0;

    const checkPermission = async (eventId: string, attempt = 1): Promise<void> => {
        try {
            const response = await api.get(`/volunteers/${eventId}/check-permission`);
            if (!response.data.hasPermission) {
                setAccessDenied(true);
                setMessage('You do not have permission to perform check-ins for this event.');
            } else {
                // Explicitly clear access denied in case this was a retry that succeeded
                setAccessDenied(false);
            }
        } catch (error) {
            if (attempt < 3) {
                // Retry with exponential backoff: 1s, 2s
                const delay = attempt * 1000;
                console.warn(`[CheckIn] Permission check failed (attempt ${attempt}), retrying in ${delay}ms...`);
                setTimeout(() => checkPermission(eventId, attempt + 1), delay);
            } else {
                // All 3 attempts failed ΓÇö deny access for security
                console.error('Failed to check permission after 3 attempts:', error);
                setAccessDenied(true);
                setMessage('Unable to verify check-in permissions after multiple attempts. Please check your connection and refresh the page.');
            }
        }
    };

    const fetchActiveEvent = async () => {
        try {
            if (navigator.onLine) {
                const response = await api.get('/events/active');
                setActiveEvents(response.data);
                if (response.data.length > 0) {
                    setSelectedEvent(response.data[0]);
                    checkPermission(response.data[0].id);
                }

                // Always update cache ΓÇö including empty array ΓÇö so stale past events are cleared
                await db.transaction('rw', db.events, async () => {
                    await db.events.clear();
                    if (response.data.length > 0) {
                        await db.events.bulkPut(response.data);
                    }
                });
            } else {
                throw new Error('Offline mode - Loading cached events');
            }
        } catch (error) {
            console.log('Unable to fetch live events. Falling back to offline events cache...', error);
            try {
                const cachedEvents = await db.events.toArray();
                setActiveEvents(cachedEvents);
                if (cachedEvents.length > 0) {
                    setSelectedEvent(cachedEvents[0]);
                    // Let's assume permission is valid offline if they have the roster downloaded.
                    setAccessDenied(false);
                    setPermissionDenied(false);
                } else {
                    console.error('No cached events found.');
                    setMessage('No active event and no cached events found. Please connect to the internet to load events.');
                }
            } catch (cacheError) {
                console.error('Failed to load cached events', cacheError);
                setMessage('Failed to load cached events. Please connect to the internet.');
            }
        } finally {
            // Assuming setLoading is defined elsewhere or will be added by the user.
            // For now, we'll just leave it as is.
            // setLoading(false);
        }
    };

    useEffect(() => {
        fetchActiveEvent();
    }, []);

    // ΓöÇΓöÇΓöÇ OFFLINE SYNCING ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const syncEventRoster = async () => {
        if (!selectedEvent) return;
        try {
            setIsSyncingRoster(true);
            const response = await api.get(`/attendance/${selectedEvent.id}/offline-roster`);
            const members = response.data.members;

            // Map server data to Dexie schema
            const rosterRecords = members.map((m: any) => ({
                id: m.id,
                eventId: selectedEvent.id,
                fullName: m.fullName,
                fellowshipNumber: m.fellowshipNumber,
                phoneNumber: m.phoneNumber,
                qrCode: m.qrCode,
                regionName: m.region?.name || 'Unknown'
            }));

            // Wipe old roster for this event and replace with fresh data
            await db.transaction('rw', db.roster, async () => {
                await db.roster.where('eventId').equals(selectedEvent.id).delete();
                await db.roster.bulkPut(rosterRecords);
            });

            setStatus('success');
            setMessage(`Downloaded ${members.length} members for offline check-in!`);
            setTimeout(() => setStatus('idle'), 3000);
        } catch (error) {
            console.error('Failed to sync roster:', error);
            setStatus('error');
            setMessage('Failed to download roster. Ensure you have internet connection.');
            setTimeout(() => setStatus('idle'), 5000);
        } finally {
            setIsSyncingRoster(false);
        }
    };

    // ΓöÇΓöÇΓöÇ HYBRID VERIFICATION WRAPPER (ONLINE FIRST, OFFLINE FALLBACK) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const processCheckIn = async (method: 'QR' | 'FELLOWSHIP_NUMBER', identifier: string) => {
        if (!selectedEvent) return;

        setStatus('loading');

        try {
            // OPTION A: LIVE ONLINE CHECK-IN (Default)
            if (navigator.onLine) {
                try {
                    const payload = method === 'QR'
                        ? { qrCode: identifier, method: 'QR', eventId: selectedEvent.id }
                        : { fellowshipNumber: identifier, method: 'FELLOWSHIP_NUMBER', eventId: selectedEvent.id };

                    const response = await api.post('/attendance/check-in', payload);

                    setMemberData(response.data.member);
                    setShowConfirmation(true);
                    setStatus('success');
                    setMessage(`[Live] ${response.data.member.fullName} checked in!`);

                    autoDismiss(method);
                    return; // Live check-in succeeded, exit early!
                } catch (liveError: any) {
                    // If it's a 400 or 409 error (e.g., already checked in, wrong QR), don't fallback to offline. Pass the live error down.
                    if (liveError.response && [400, 403, 404].includes(liveError.response.status)) {
                        throw new Error(liveError.response.data.error || 'Live Check-in Rejected.');
                    }
                    console.warn('Live checkin failed (Likely network). Falling back to Offline db...', liveError);
                    // Otherwise, it's likely a 500 or network error. Continue down to Option B (Offline fallback).
                }
            }

            // OPTION B: OFFLINE LOCAL DB FALLBACK
            // Find member in local DB
            let member;
            if (method === 'QR') {
                member = await db.roster.where('qrCode').equals(identifier).and(m => m.eventId === selectedEvent.id).first();
            } else {
                member = await db.roster.where('fellowshipNumber').equals(identifier).and(m => m.eventId === selectedEvent.id).first();
            }

            if (!member) {
                throw new Error(rosterCount > 0
                    ? 'Member not found. Verify they are registered.'
                    : 'Roster not synced! Cannot verify offline. Please connect to internet and download the roster.');
            }

            // Check if already checked in locally in the queue
            const alreadyInQueue = await db.syncQueue.where({ memberId: member.id, eventId: selectedEvent.id }).first();
            if (alreadyInQueue) {
                throw new Error('Already scanned today! (Pending sync)');
            }

            // Save to offline queue
            await db.syncQueue.add({
                memberId: member.id,
                eventId: selectedEvent.id,
                method: method,
                timestamp: new Date().toISOString(),
                fullName: member.fullName
            });

            setMemberData({
                id: member.id,
                fullName: member.fullName,
                fellowshipNumber: member.fellowshipNumber,
                phoneNumber: member.phoneNumber,
                region: { id: '', name: member.regionName || 'Unknown' }
            });
            setShowConfirmation(true);
            setStatus('success');
            setMessage(`[Offline] ${member.fullName} checked in locally.`);

            autoDismiss(method);

        } catch (error: any) {
            console.error('Check-in error:', error);
            setStatus('error');
            setMessage(error.message || 'Check-in Failed. Please try again.');
            setTimeout(() => setStatus('idle'), 5000);
        }
    };

    const autoDismiss = (method: 'QR' | 'FELLOWSHIP_NUMBER') => {
        setTimeout(() => {
            setStatus('idle');
            if (method === 'QR') setResult('');
            if (method === 'FELLOWSHIP_NUMBER') setFellowshipNumber('');
            setShowConfirmation(false);
            setMemberData(null);
        }, 4000);
    };

    useEffect(() => {
        if (scanning && selectedEvent && !accessDenied) {
            setPermissionDenied(false);

            const scanner = new Html5QrcodeScanner(
                'qr-reader',
                {
                    fps: 10,
                    qrbox: { width: 250, height: 250 },
                    aspectRatio: 1.0,
                    showTorchButtonIfSupported: true,
                    showZoomSliderIfSupported: true,
                },
                false
            );

            scannerRef.current = scanner;

            scanner.render(
                async (decodedText) => {
                    setResult(decodedText);
                    setStatus('loading');
                    setScanning(false);
                    scanner.clear();

                    try {
                        await processCheckIn('QR', decodedText);
                    } catch (error: any) {
                        // Error is handled inside processCheckIn
                    }
                },
                (errorMessage) => {
                    if (errorMessage.includes('Permission') || errorMessage.includes('NotAllowedError')) {
                        setPermissionDenied(true);
                        setScanning(false);
                        scanner.clear();
                    }
                }
            );

            return () => {
                scanner.clear().catch((error) => {
                    console.error('Failed to clear scanner', error);
                });
            };
        }
    }, [scanning, selectedEvent, accessDenied]);

    const handleStartScan = () => {
        setPermissionDenied(false);
        setStatus('idle');
        setScanning(true);
        setFellowshipNumber('');
        setShowConfirmation(false);
        setMemberData(null);
    };

    const handleStopScan = () => {
        if (scannerRef.current) {
            scannerRef.current.clear().catch(console.error);
        }
        setScanning(false);
    };

    const handleFellowshipLookup = async () => {
        if (!fellowshipNumber || fellowshipNumber.length !== 6 || !selectedEvent) return;

        setFellowshipLookupLoading(true);
        setMemberData(null);
        setShowConfirmation(false);

        try {
            await processCheckIn('FELLOWSHIP_NUMBER', fellowshipNumber.toUpperCase());
        } catch (error: any) {
            // Error handled inside process
        } finally {
            setFellowshipLookupLoading(false);
        }
    };

    const handleRetry = () => {
        setStatus('idle');
        setResult('');
        setPermissionDenied(false);
        setFellowshipNumber('');
        setShowConfirmation(false);
        setMemberData(null);
    };

    return (
        <div className="max-w-2xl mx-auto animate-fade-in">
            <div className="bg-white rounded-2xl border border-slate-200 shadow-xl p-8 relative overflow-hidden">

                {/* Background decoration */}
                <div className="absolute top-0 right-0 w-64 h-64 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 opacity-40" style={{ backgroundColor: '#e9f5e1' }} />

                <div className="relative">
                    {/* Header */}
                    <div className="flex items-center gap-3 mb-8">
                        <div className="p-3 rounded-xl" style={{ backgroundColor: '#e9f5e1', color: '#48A111', outline: '1.5px solid #c5e3b0' }}>
                            <Scan className="w-6 h-6" />
                        </div>
                        <div>
                            <div className="flex items-center gap-2">
                                <h2 className="text-2xl font-bold text-slate-900">Event Check-in</h2>
                                <Zap className="w-5 h-5" style={{ color: '#F2B50B' }} />
                            </div>
                            <p className="text-slate-500 text-sm">Scan QR code or enter fellowship number</p>
                        </div>
                    </div>

                    {/* Access Denied State */}
                    {accessDenied && (
                        <div className="mb-6 bg-red-50 border border-red-200 rounded-xl p-5 animate-slide-up">
                            <div className="flex items-start gap-4">
                                <div className="w-10 h-10 rounded-full bg-red-100 flex items-center justify-center shrink-0">
                                    <AlertTriangle className="text-red-500" size={20} />
                                </div>
                                <div className="flex-1">
                                    <h3 className="text-red-700 font-bold text-base mb-1">Access Denied</h3>
                                    <p className="text-red-600 text-sm mb-2 leading-relaxed">{message}</p>
                                    <p className="text-red-400 text-xs">
                                        Only Fellowship Managers and assigned Check-in Volunteers can access this page for the current event.
                                    </p>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Permission Denied State */}
                    {permissionDenied && (
                        <div className="mb-6 bg-yellow-50 border border-yellow-200 rounded-xl p-5 animate-slide-up">
                            <div className="flex items-start gap-4">
                                <div className="w-10 h-10 rounded-full bg-yellow-100 flex items-center justify-center shrink-0">
                                    <AlertTriangle className="text-yellow-600" size={20} />
                                </div>
                                <div className="flex-1">
                                    <h3 className="text-yellow-800 font-bold text-base mb-1">Camera Permission Required</h3>
                                    <p className="text-yellow-700 text-sm mb-4 leading-relaxed">
                                        To scan QR codes, we need access to your camera. Please allow camera access when prompted by your browser.
                                    </p>
                                    <button
                                        onClick={handleStartScan}
                                        className="px-5 py-2.5 rounded-xl text-white text-sm font-semibold flex items-center gap-2 transition-all hover:scale-[1.02] active:scale-[0.98] shadow-md"
                                        style={{ backgroundColor: '#48A111' }}
                                        onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = '#F2B50B')}
                                        onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = '#48A111')}
                                    >
                                        <RefreshCw size={16} />
                                        Try Again
                                    </button>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Event Selector */}
                    <div className="mb-4">
                        <EventSelector
                            events={activeEvents}
                            selectedEvent={selectedEvent}
                            onEventChange={(event: Event) => {
                                setSelectedEvent(event);
                                checkPermission(event.id);
                            }}
                        />
                    </div>

                    {/* Offline Roster Status */}
                    {!accessDenied && selectedEvent && (
                        <div className="mb-6 flex flex-col sm:flex-row items-stretch sm:items-center justify-between gap-3 p-4 rounded-xl border" style={{ backgroundColor: rosterCount > 0 ? '#f8fafc' : '#fffbeb', borderColor: rosterCount > 0 ? '#e2e8f0' : '#fef3c7' }}>
                            <div className="flex flex-col">
                                <span className={`text-sm font-bold ${rosterCount > 0 ? 'text-slate-700' : 'text-amber-700'} flex items-center gap-1.5`}>
                                    {rosterCount > 0 ? <CheckCircle size={16} className="text-[#48A111]" /> : <AlertTriangle size={16} />}
                                    {rosterCount > 0 ? 'Offline Environment Ready' : 'Warning: Not Ready for Offline'}
                                </span>
                                <span className="text-xs text-slate-500 mt-0.5">
                                    {rosterCount} members loaded ΓÇó {pendingSyncCount} check-ins waiting to sync
                                </span>
                            </div>

                            <button
                                onClick={syncEventRoster}
                                disabled={isSyncingRoster || !navigator.onLine}
                                className="px-4 py-2 text-xs font-semibold rounded-lg bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                            >
                                {isSyncingRoster ? <Loader2 size={14} className="animate-spin" /> : <RefreshCw size={14} />}
                                Download Roster
                            </button>
                        </div>
                    )}

                    {/* Main Content - Only show if access is granted */}
                    {!accessDenied && selectedEvent && (
                        <>
                            {/* QR Scanner Button */}
                            {!scanning && status === 'idle' && !permissionDenied && !showConfirmation && (
                                <div className="mb-6">
                                    <button
                                        onClick={handleStartScan}
                                        className="w-full py-4 px-6 rounded-xl font-bold text-base flex items-center justify-center gap-3 text-white transition-all hover:scale-[1.02] active:scale-[0.98] shadow-lg"
                                        style={{ backgroundColor: '#48A111' }}
                                        onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = '#F2B50B')}
                                        onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = '#48A111')}
                                    >
                                        <Camera size={22} />
                                        Start QR Scanner
                                    </button>
                                    <p className="text-center text-slate-400 text-xs mt-2">
                                        Camera access is required for scanning
                                    </p>
                                </div>
                            )}

                            {/* Scanner Window */}
                            {scanning && (
                                <div className="mb-6 animate-scale-in">
                                    <div className="relative">
                                        <div id="qr-reader" className="rounded-xl overflow-hidden shadow-lg" style={{ border: '3px solid #48A111' }} />
                                        <div className="absolute top-4 left-0 right-0 flex justify-center pointer-events-none">
                                            <div className="bg-black/50 backdrop-blur-sm px-4 py-2 rounded-full border border-white/20">
                                                <p className="text-white text-sm font-medium flex items-center gap-2">
                                                    <Scan size={14} className="animate-pulse" />
                                                    Align QR code within the box
                                                </p>
                                            </div>
                                        </div>
                                    </div>
                                    <button
                                        onClick={handleStopScan}
                                        className="w-full mt-4 py-3 px-6 rounded-xl font-semibold flex items-center justify-center gap-2 text-white bg-red-500 hover:bg-red-600 shadow-md transition-all active:scale-95"
                                    >
                                        <XCircle size={18} />
                                        Stop Scanner
                                    </button>
                                </div>
                            )}

                            {/* OR Divider */}
                            {!scanning && status === 'idle' && !showConfirmation && (
                                <div className="flex items-center gap-4 my-5">
                                    <div className="flex-1 h-px bg-slate-200" />
                                    <span className="text-slate-400 text-sm font-semibold">OR</span>
                                    <div className="flex-1 h-px bg-slate-200" />
                                </div>
                            )}

                            {/* Fellowship Number Input */}
                            {!scanning && status === 'idle' && !showConfirmation && (
                                <div className="mb-6">
                                    <label className="text-sm font-semibold text-slate-700 flex items-center gap-2 mb-3">
                                        <Hash size={16} style={{ color: '#48A111' }} />
                                        Enter Fellowship Number
                                    </label>
                                    <div className="flex gap-3">
                                        <input
                                            type="text"
                                            value={fellowshipNumber}
                                            onChange={(e) => setFellowshipNumber(e.target.value.toUpperCase())}
                                            placeholder="AAA001"
                                            maxLength={6}
                                            className="flex-1 px-4 py-3 rounded-xl bg-slate-50 border-2 border-slate-200 text-slate-900 placeholder-slate-400 font-mono text-lg tracking-widest focus:outline-none transition-all"
                                            style={{}}
                                            onFocus={(e) => { e.currentTarget.style.borderColor = '#48A111'; e.currentTarget.style.boxShadow = '0 0 0 3px rgba(72,161,17,0.12)'; }}
                                            onBlur={(e) => { e.currentTarget.style.borderColor = '#e2e8f0'; e.currentTarget.style.boxShadow = 'none'; }}
                                            onKeyDown={(e) => {
                                                if (e.key === 'Enter' && fellowshipNumber.length === 6) {
                                                    handleFellowshipLookup();
                                                }
                                            }}
                                        />
                                        <button
                                            onClick={handleFellowshipLookup}
                                            disabled={fellowshipNumber.length !== 6 || fellowshipLookupLoading}
                                            className="px-5 py-3 rounded-xl text-white font-semibold flex items-center gap-2 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-md hover:scale-[1.02] active:scale-[0.98]"
                                            style={{ backgroundColor: '#48A111' }}
                                            onMouseEnter={(e) => !e.currentTarget.disabled && (e.currentTarget.style.backgroundColor = '#F2B50B')}
                                            onMouseLeave={(e) => !e.currentTarget.disabled && (e.currentTarget.style.backgroundColor = '#48A111')}
                                        >
                                            {fellowshipLookupLoading ? (
                                                <>
                                                    <Loader2 size={16} className="animate-spin" />
                                                    <span>Checking...</span>
                                                </>
                                            ) : (
                                                <>
                                                    <User size={16} />
                                                    <span>Check In</span>
                                                </>
                                            )}
                                        </button>
                                    </div>
                                    <p className="text-slate-400 text-xs mt-2">
                                        Enter the 6-character fellowship number (e.g., AAA001)
                                    </p>
                                </div>
                            )}

                            {/* Loading State */}
                            {status === 'loading' && (
                                <div className="rounded-xl p-5 flex items-center gap-4 animate-slide-up border" style={{ backgroundColor: '#e9f5e1', borderColor: '#c5e3b0' }}>
                                    <Loader2 className="animate-spin shrink-0" style={{ color: '#48A111' }} size={28} />
                                    <div>
                                        <p className="font-semibold text-slate-900">Processing Check-in...</p>
                                        <p className="text-slate-500 text-sm mt-0.5">Please wait a moment</p>
                                    </div>
                                </div>
                            )}

                            {/* Success State */}
                            {status === 'success' && memberData && (
                                <div className="bg-green-50 border border-green-200 rounded-xl p-5 animate-slide-up relative overflow-hidden">
                                    <div className="absolute top-0 left-0 right-0 h-1 rounded-t-xl" style={{ backgroundColor: '#48A111' }} />
                                    <div className="flex items-start gap-4">
                                        <div className="w-12 h-12 rounded-full flex items-center justify-center shrink-0" style={{ backgroundColor: '#e9f5e1' }}>
                                            <CheckCircle size={24} style={{ color: '#48A111' }} />
                                        </div>
                                        <div className="flex-1">
                                            <p className="font-bold text-lg text-slate-900 mb-3">{message}</p>
                                            <div className="p-4 bg-white rounded-xl border border-green-100 space-y-1.5">
                                                <div className="flex items-center gap-2 mb-2">
                                                    <User size={15} style={{ color: '#48A111' }} />
                                                    <span className="text-slate-600 text-sm font-semibold">Member Details</span>
                                                </div>
                                                <div className="ml-5 space-y-1">
                                                    <p className="text-slate-900 font-medium">{memberData.fullName}</p>
                                                    <p className="text-slate-500 text-sm">Fellowship: {memberData.fellowshipNumber}</p>
                                                    <p className="text-slate-500 text-sm">Region: {memberData.region.name}</p>
                                                    <p className="text-slate-500 text-sm">Phone: {memberData.phoneNumber}</p>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {/* Error State */}
                            {status === 'error' && (
                                <div className="bg-red-50 border border-red-200 rounded-xl p-5 animate-slide-up relative overflow-hidden">
                                    <div className="absolute top-0 left-0 right-0 h-1 bg-red-500 rounded-t-xl" />
                                    <div className="flex items-start gap-4">
                                        <div className="w-12 h-12 rounded-full bg-red-100 flex items-center justify-center shrink-0">
                                            <XCircle className="text-red-500" size={24} />
                                        </div>
                                        <div className="flex-1">
                                            <p className="font-bold text-slate-900 text-lg mb-1">{message}</p>
                                            <p className="text-slate-500 text-sm mb-4">Please try again or contact an administrator</p>
                                            <button
                                                onClick={handleRetry}
                                                className="px-4 py-2 bg-red-500 text-white font-semibold rounded-lg hover:bg-red-600 transition-all text-sm flex items-center gap-2"
                                            >
                                                <RefreshCw size={15} />
                                                Try Again
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {/* How It Works Instructions */}
                            {!scanning && status === 'idle' && !result && !permissionDenied && !showConfirmation && (
                                <div className="mt-6 p-5 bg-slate-50 rounded-xl border border-slate-200 relative">
                                    <div className="absolute -top-3 left-4 px-3 py-1 rounded-full text-xs font-bold text-white" style={{ backgroundColor: '#48A111' }}>
                                        HOW IT WORKS
                                    </div>
                                    <div className="space-y-4 pt-1">
                                        <div>
                                            <p className="font-semibold text-sm mb-1.5 flex items-center gap-2" style={{ color: '#48A111' }}>
                                                <Scan size={14} />
                                                QR Code Check-in:
                                            </p>
                                            <ol className="text-slate-500 space-y-0.5 list-none ml-5 text-sm">
                                                <li>ΓÇó Click "Start QR Scanner"</li>
                                                <li>ΓÇó Allow camera access</li>
                                                <li>ΓÇó Position QR code within the box</li>
                                                <li>ΓÇó Automatic check-in</li>
                                            </ol>
                                        </div>
                                        <div>
                                            <p className="font-semibold text-sm mb-1.5 flex items-center gap-2" style={{ color: '#F2B50B' }}>
                                                <Hash size={14} />
                                                Fellowship Number Check-in:
                                            </p>
                                            <ol className="text-slate-500 space-y-0.5 list-none ml-5 text-sm">
                                                <li>ΓÇó Enter 6-character fellowship number</li>
                                                <li>ΓÇó Click "Check In"</li>
                                                <li>ΓÇó System verifies and checks in member</li>
                                            </ol>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>
        </div>
    );
};

export default CheckIn;

import React, { useState, useEffect } from 'react';
import api from '../api';
import { useToast } from '../components/ToastProvider';
import { BookOpen, Plus, Trash2, Search, X, Loader2, Edit2, GraduationCap, Building } from 'lucide-react';
import EmptyState from '../components/EmptyState';

interface College {
    id: string;
    name: string;
    code?: string;
}

interface Course {
    id: string;
    name: string;
    code: string;
    memberCount: number;
    collegeId?: string;
    college?: College;
}

const CourseManagement = () => {
    const { showToast } = useToast();
    const [courses, setCourses] = useState<Course[]>([]);
    const [colleges, setColleges] = useState<College[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingCourse, setEditingCourse] = useState<Course | null>(null);
    const [formData, setFormData] = useState({ name: '', code: '', collegeId: '' });
    const [submitting, setSubmitting] = useState(false);

    useEffect(() => {
        fetchColleges();
        fetchCourses();
    }, []);

    const fetchColleges = async () => {
        try {
            const response = await api.get('/colleges');
            setColleges(response.data);
        } catch (error) {
            console.error('Failed to fetch colleges:', error);
            showToast('error', 'Failed to load colleges');
        }
    };

    const fetchCourses = async () => {
        try {
            setLoading(true);
            const response = await api.get('/courses');
            setCourses(response.data);
        } catch (error) {
            console.error('Failed to fetch courses:', error);
            showToast('error', 'Failed to load courses');
        } finally {
            setLoading(false);
        }
    };

    const handleOpenModal = (course?: Course) => {
        if (course) {
            setEditingCourse(course);
            setFormData({ name: course.name, code: course.code, collegeId: course.collegeId || '' });
        } else {
            setEditingCourse(null);
            setFormData({ name: '', code: '', collegeId: '' });
        }
        setIsModalOpen(true);
    };

    const handleCloseModal = () => {
        setIsModalOpen(false);
        setEditingCourse(null);
        setFormData({ name: '', code: '', collegeId: '' });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name.trim() || !formData.code.trim()) return;

        try {
            setSubmitting(true);
            const payload: any = {
                name: formData.name.trim(),
                code: formData.code.trim().toUpperCase(),
                collegeId: formData.collegeId || undefined
            };

            if (editingCourse) {
                const response = await api.patch(`/courses/${editingCourse.id}`, payload);
                setCourses(courses.map(c => c.id === editingCourse.id ? { ...response.data, memberCount: c.memberCount } : c));
                showToast('success', 'Course updated successfully');
            } else {
                const response = await api.post('/courses', payload);
                setCourses([...courses, { ...response.data, memberCount: 0 }]);
                showToast('success', 'Course created successfully');
            }
            handleCloseModal();
        } catch (error: any) {
            console.error('Failed to save course:', error);
            showToast('error', error.response?.data?.error || 'Failed to save course');
        } finally {
            setSubmitting(false);
        }
    };

    const handleDelete = async (course: Course) => {
        if (!confirm(`Are you sure you want to delete "${course.code} - ${course.name}"?`)) return;

        try {
            await api.delete(`/courses/${course.id}`);
            setCourses(courses.filter(c => c.id !== course.id));
            showToast('success', 'Course deleted successfully');
        } catch (error: any) {
            console.error('Failed to delete course:', error);
            showToast('error', error.response?.data?.error || 'Failed to delete course');
        }
    };

    const filteredCourses = courses.filter(course =>
        course.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        course.code.toLowerCase().includes(searchQuery.toLowerCase()) ||
        course.college?.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

    // Group courses by college
    const unassignedCourses = filteredCourses.filter(c => !c.college);
    const groupedByCollege = filteredCourses.reduce((acc, course) => {
        if (course.college) {
            const collegeId = course.college.id;
            if (!acc[collegeId]) {
                acc[collegeId] = {
                    college: course.college,
                    courses: []
                };
            }
            acc[collegeId].courses.push(course);
        }
        return acc;
    }, {} as Record<string, { college: College; courses: Course[] }>);

    return (
        <div className="min-h-screen bg-[#0a0f1e] text-white p-6">
            <div className="max-w-7xl mx-auto">
                <div className="flex items-center justify-between mb-8">
                    <div>
                        <h1 className="text-4xl font-bold text-teal-400">
                            Course Management
                        </h1>
                        <p className="text-slate-400 mt-2">Manage university courses and assign them to colleges</p>
                    </div>
                    <button
                        onClick={() => handleOpenModal()}
                        className="px-6 py-3 bg-teal-600 hover:bg-teal-700 rounded-xl font-semibold flex items-center gap-2 transition-all shadow-lg hover:shadow-teal-500/30"
                    >
                        <Plus size={20} />
                        Add Course
                    </button>
                </div>

                <div className="mb-6 relative">
                    <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
                    <input
                        type="text"
                        placeholder="Search courses by name, code, or college..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pl-12 pr-4 py-3 bg-[#151d30] rounded-xl border border-slate-800 focus:border-teal-500 focus:outline-none text-white placeholder-slate-500 transition-colors"
                    />
                </div>

                {loading ? (
                    <div className="flex items-center justify-center py-16">
                        <Loader2 className="w-8 h-8 text-teal-500 animate-spin" />
                    </div>
                ) : filteredCourses.length === 0 ? (
                    <EmptyState
                        icon={BookOpen}
                        title={searchQuery ? "No courses found" : "No courses yet"}
                        description={searchQuery ? "Try a different search term" : "Add courses to the system for student registration"}
                        action={!searchQuery ? { label: "Add Course", onClick: () => handleOpenModal() } : undefined}
                    />
                ) : (
                    <div className="space-y-8">
                        {/* Unassigned Courses */}
                        {unassignedCourses.length > 0 && (
                            <div>
                                <div className="flex items-center gap-2 mb-4">
                                    <BookOpen className="w-5 h-5 text-slate-400" />
                                    <h2 className="text-xl font-semibold text-slate-300">Unassigned Courses</h2>
                                    <span className="text-sm text-slate-500">({unassignedCourses.length})</span>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                    {unassignedCourses.map((course) => (
                                        <CourseCard key={course.id} course={course} onEdit={handleOpenModal} onDelete={handleDelete} />
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Grouped by College */}
                        {Object.values(groupedByCollege).map(({ college, courses }) => (
                            <div key={college.id}>
                                <div className="flex items-center gap-2 mb-4">
                                    <Building className="w-5 h-5 text-teal-400" />
                                    <h2 className="text-xl font-semibold text-white">
                                        {college.code ? `${college.code} - ` : ''}{college.name}
                                    </h2>
                                    <span className="text-sm text-slate-500">({courses.length} course{courses.length !== 1 && 's'})</span>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                    {courses.map((course) => (
                                        <CourseCard key={course.id} course={course} onEdit={handleOpenModal} onDelete={handleDelete} />
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {/* Add/Edit Modal */}
                {isModalOpen && (
                    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-in fade-in duration-200">
                        <div className="bg-[#151d30] rounded-2xl p-8 max-w-md w-full border border-slate-800 shadow-xl">
                            <div className="flex items-center justify-between mb-6">
                                <h2 className="text-2xl font-bold text-white">
                                    {editingCourse ? 'Edit Course' : 'Add New Course'}
                                </h2>
                                <button onClick={handleCloseModal} className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400 hover:text-white">
                                    <X size={20} />
                                </button>
                            </div>

                            <form onSubmit={handleSubmit} className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-2">Course Code <span className="text-red-400">*</span></label>
                                    <input
                                        type="text"
                                        value={formData.code}
                                        onChange={(e) => setFormData({ ...formData, code: e.target.value.toUpperCase() })}
                                        placeholder="e.g. BSCS"
                                        className="w-full px-4 py-3 bg-[#0a0f1e] rounded-xl border border-slate-700 focus:border-teal-500 focus:outline-none text-white font-mono placeholder-slate-600 transition-colors"
                                        maxLength={10}
                                        required
                                    />
                                    <p className="text-xs text-slate-500 mt-1">Short identifier for the course</p>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-2">Course Name <span className="text-red-400">*</span></label>
                                    <input
                                        type="text"
                                        value={formData.name}
                                        onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                        placeholder="e.g. Bachelor of Science in Computer Science"
                                        className="w-full px-4 py-3 bg-[#0a0f1e] rounded-xl border border-slate-700 focus:border-teal-500 focus:outline-none text-white placeholder-slate-600 transition-colors"
                                        required
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-2">College (Optional)</label>
                                    <select
                                        value={formData.collegeId}
                                        onChange={(e) => setFormData({ ...formData, collegeId: e.target.value })}
                                        className="w-full px-4 py-3 bg-[#0a0f1e] rounded-xl border border-slate-700 focus:border-teal-500 focus:outline-none text-white transition-colors cursor-pointer"
                                    >
                                        <option value="">No College (Unassigned)</option>
                                        {colleges.map((college) => (
                                            <option key={college.id} value={college.id}>
                                                {college.code ? `${college.code} - ` : ''}{college.name}
                                            </option>
                                        ))}
                                    </select>
                                    <p className="text-xs text-slate-500 mt-1">Assign this course to a Makerere college</p>
                                </div>

                                <div className="flex gap-3 pt-4">
                                    <button
                                        type="button"
                                        onClick={handleCloseModal}
                                        className="flex-1 px-4 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-medium transition-colors text-slate-300"
                                    >
                                        Cancel
                                    </button>
                                    <button
                                        type="submit"
                                        disabled={submitting}
                                        className="flex-1 px-4 py-3 bg-teal-600 hover:bg-teal-700 rounded-xl font-medium transition-colors text-white disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                                    >
                                        {submitting ? (
                                            <>
                                                <Loader2 size={18} className="animate-spin" />
                                                Saving...
                                            </>
                                        ) : (
                                            editingCourse ? 'Update Course' : 'Create Course'
                                        )}
                                    </button>
                                </div>
                            </form>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

// Course Card Component
const CourseCard: React.FC<{ course: Course; onEdit: (course: Course) => void; onDelete: (course: Course) => void }> = ({ course, onEdit, onDelete }) => (
    <div className="glass-card p-6 group hover:border-teal-500/50 transition-colors">
        <div className="flex items-start justify-between mb-4">
            <div className="flex items-center gap-3">
                <div className="p-2 rounded-lg bg-teal-500/10 text-teal-400">
                    <BookOpen size={20} />
                </div>
                <div>
                    <span className="text-xs font-bold text-teal-400 bg-teal-500/10 px-2 py-0.5 rounded border border-teal-500/20">
                        {course.code}
                    </span>
                </div>
            </div>
            <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button
                    onClick={() => onEdit(course)}
                    className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white transition-colors"
                >
                    <Edit2 size={16} />
                </button>
                <button
                    onClick={() => onDelete(course)}
                    className="p-2 hover:bg-red-500/10 rounded-lg text-slate-400 hover:text-red-400 transition-colors"
                >
                    <Trash2 size={16} />
                </button>
            </div>
        </div>

        <h3 className="text-lg font-semibold text-white mb-2 line-clamp-2 h-14">
            {course.name}
        </h3>

        {course.college && (
            <div className="flex items-center gap-2 text-xs text-purple-400 mb-2 bg-purple-500/10 px-2 py-1 rounded border border-purple-500/20">
                <Building size={12} />
                <span>{course.college.code || course.college.name}</span>
            </div>
        )}

        <div className="flex items-center gap-2 text-sm text-slate-400 border-t border-slate-800 pt-4 mt-2">
            <GraduationCap size={16} />
            <span>{course.memberCount} student{course.memberCount !== 1 && 's'} enrolled</span>
        </div>
    </div>
);

export default CourseManagement;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api';
import { ArrowLeft, Filter, Users, TrendingUp, UserCheck, PieChart as PieChartIcon, MapPin, Download, ChevronDown, Heart, Tag } from 'lucide-react';
import {
    LineChart,
    Line,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
    PieChart,
    Pie,
    Cell,
    BarChart,
    Bar,
} from 'recharts';

interface CustomReportData {
    stats: {
        totalEvents: number;
        totalAttendance: number;
        averageAttendance: number;
        uniqueMembers: number;
        genderBreakdown: {
            MALE: number;
            FEMALE: number;
        };
        regionBreakdown: Record<string, number>;
        salvationBreakdown?: Record<string, number>;
        tagDistribution?: Record<string, number>;
        // Academic Statistics
        yearOfStudyBreakdown?: Record<string, number>;
        collegeBreakdown?: Record<string, number>;
        courseBreakdown?: Record<string, number>;
        // Organizational Statistics
        familyBreakdown?: Record<string, number>;
        teamBreakdown?: Record<string, number>;
        // Special Tags
        specialTagStats?: {
            finalists: number;
            alumni: number;
            volunteers: number;
        };
    };
    chartData: Array<{
        date: string;
        name: string;
        attendance: number;
    }>;
}

interface Region {
    id: string;
    name: string;
}

const CustomReport = () => {
    const navigate = useNavigate();
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [type, setType] = useState('');
    const [regionId, setRegionId] = useState('');
    const [regions, setRegions] = useState<Region[]>([]);
    const [data, setData] = useState<CustomReportData | null>(null);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        fetchRegions();
    }, []);

    const fetchRegions = async () => {
        try {
            const response = await api.get('/regions');
            setRegions(response.data);
        } catch (error) {
            console.error('Failed to fetch regions:', error);
        }
    };

    const fetchReport = async () => {
        if (!startDate || !endDate) return;

        // Validate date range
        const start = new Date(startDate);
        const end = new Date(endDate);
        const today = new Date();
        today.setHours(0, 0, 0, 0);

        if (start > today) {
            // Future date selected
            setData(null);
            setLoading(false);
            return;
        }

        setLoading(true);
        try {
            const response = await api.get('/reports/custom', {
                params: {
                    startDate,
                    endDate,
                    type: type || undefined,
                    regionId: regionId || undefined
                },
            });
            setData(response.data);
        } catch (error) {
            console.error('Failed to fetch custom report:', error);
            setData(null);
        } finally {
            setLoading(false);
        }
    };

    const handleQuickFilter = (period: '30days' | '3months' | 'ytd') => {
        const end = new Date();
        const start = new Date();

        if (period === '30days') {
            start.setDate(end.getDate() - 30);
        } else if (period === '3months') {
            start.setMonth(end.getMonth() - 3);
        } else if (period === 'ytd') {
            start.setMonth(0, 1);
        }

        setStartDate(start.toISOString().split('T')[0]);
        setEndDate(end.toISOString().split('T')[0]);
    };

    // Trigger fetch when filters change
    useEffect(() => {
        if (startDate && endDate) {
            fetchReport();
        }
    }, [startDate, endDate, type, regionId]);

    const handleExportPDF = async () => {
        if (!startDate || !endDate) return;
        try {
            const response = await api.get(`/reports/custom/export/pdf`, {
                params: {
                    startDate,
                    endDate,
                    ...(type && { type }),
                    ...(regionId && { regionId })
                },
                responseType: 'blob',
            });
            const blob = new Blob([response.data], { type: 'application/pdf' });
            const url = window.URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `Custom_Report_${startDate}_to_${endDate}.pdf`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            window.URL.revokeObjectURL(url);
        } catch (error) {
            console.error('PDF export error:', error);
            alert('Failed to export PDF. Please try again.');
        }
    };

    const handleExportExcel = async () => {
        if (!startDate || !endDate) return;
        try {
            const response = await api.get(`/reports/custom/export/excel`, {
                params: {
                    startDate,
                    endDate,
                    ...(type && { type }),
                    ...(regionId && { regionId })
                },
                responseType: 'blob',
            });
            const blob = new Blob([response.data], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
            const url = window.URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `Custom_Report_${startDate}_to_${endDate}.xlsx`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            window.URL.revokeObjectURL(url);
        } catch (error) {
            console.error('Excel export error:', error);
            alert('Failed to export Excel. Please try again.');
        }
    };

    const [showExportMenu, setShowExportMenu] = useState(false);

    // Helper function to check if date range is in the future
    const isFutureDateRange = () => {
        if (!startDate) return false;
        const start = new Date(startDate);
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        return start > today;
    };

    // Helper function to check if data is empty
    const isDataEmpty = () => {
        return data && (
            data.stats.totalEvents === 0 ||
            data.stats.totalAttendance === 0
        );
    };

    // Prepare region data for chart
    const regionChartData = data?.stats.regionBreakdown
        ? Object.entries(data.stats.regionBreakdown).map(([name, value]) => ({ name, value }))
        : [];

    return (
        <div className="min-h-screen bg-[#0a0f1e] p-6">
            <div className="max-w-7xl mx-auto">
                {/* Header */}
                <div className="flex items-center gap-4 mb-8">
                    <button
                        onClick={() => navigate('/events')}
                        className="p-2 rounded-lg bg-white/10 text-white hover:bg-white/20 transition-all"
                    >
                        <ArrowLeft size={24} />
                    </button>
                    <div>
                        <h1 className="text-3xl font-bold text-white">Custom Reports</h1>
                        <p className="text-slate-400">Generate insights across multiple events</p>
                    </div>

                    {data && (
                        <div className="relative">
                            <button
                                onClick={() => setShowExportMenu(!showExportMenu)}
                                className="ml-auto flex items-center gap-2 bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-lg transition-all"
                            >
                                <Download size={20} />
                                Export
                                <ChevronDown size={16} className={`transition-transform ${showExportMenu ? 'rotate-180' : ''}`} />
                            </button>

                            {showExportMenu && (
                                <div className="absolute right-0 mt-2 w-48 bg-[#1e293b] border border-slate-700 rounded-lg shadow-xl z-10">
                                    <button
                                        onClick={() => { handleExportPDF(); setShowExportMenu(false); }}
                                        className="w-full px-4 py-2 text-left text-white hover:bg-slate-700 rounded-t-lg transition-colors flex items-center gap-2"
                                    >
                                        <Download size={16} />
                                        Export as PDF
                                    </button>
                                    <button
                                        onClick={() => { handleExportExcel(); setShowExportMenu(false); }}
                                        className="w-full px-4 py-2 text-left text-white hover:bg-slate-700 rounded-b-lg transition-colors flex items-center gap-2"
                                    >
                                        <Download size={16} />
                                        Export as Excel
                                    </button>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                {/* Filters */}
                <div className="bg-[#151d30] p-6 rounded-2xl border border-slate-800 mb-8">
                    <div className="flex flex-wrap items-end gap-4">
                        <div>
                            <label className="block text-slate-400 text-sm mb-2">Start Date</label>
                            <input
                                type="date"
                                value={startDate}
                                onChange={(e) => setStartDate(e.target.value)}
                                className="px-4 py-2 rounded-xl bg-slate-900 border border-slate-700 text-white focus:outline-none focus:border-indigo-500"
                            />
                        </div>
                        <div>
                            <label className="block text-slate-400 text-sm mb-2">End Date</label>
                            <input
                                type="date"
                                value={endDate}
                                onChange={(e) => setEndDate(e.target.value)}
                                className="px-4 py-2 rounded-xl bg-slate-900 border border-slate-700 text-white focus:outline-none focus:border-indigo-500"
                            />
                        </div>
                        <div>
                            <label className="block text-slate-400 text-sm mb-2">Event Type</label>
                            <select
                                value={type}
                                onChange={(e) => setType(e.target.value)}
                                className="px-4 py-2 rounded-xl bg-slate-900 border border-slate-700 text-white focus:outline-none focus:border-indigo-500"
                            >
                                <option value="">All Types</option>
                                <option value="TUESDAY_FELLOWSHIP">Tuesday Fellowship</option>
                                <option value="THURSDAY_PHANEROO">Thursday Phaneroo</option>
                            </select>
                        </div>
                        <div>
                            <label className="block text-slate-400 text-sm mb-2">Region</label>
                            <select
                                value={regionId}
                                onChange={(e) => setRegionId(e.target.value)}
                                className="px-4 py-2 rounded-xl bg-slate-900 border border-slate-700 text-white focus:outline-none focus:border-indigo-500 min-w-[150px]"
                            >
                                <option value="">All Regions</option>
                                {regions.map((region) => (
                                    <option key={region.id} value={region.id}>
                                        {region.name}
                                    </option>
                                ))}
                            </select>
                        </div>

                        <div className="flex gap-2 ml-auto">
                            <button
                                onClick={() => handleQuickFilter('30days')}
                                className="px-4 py-2 rounded-xl bg-slate-800 text-slate-300 hover:bg-slate-700 hover:text-white transition-all text-sm"
                            >
                                Last 30 Days
                            </button>
                            <button
                                onClick={() => handleQuickFilter('3months')}
                                className="px-4 py-2 rounded-xl bg-slate-800 text-slate-300 hover:bg-slate-700 hover:text-white transition-all text-sm"
                            >
                                Last 3 Months
                            </button>
                            <button
                                onClick={() => handleQuickFilter('ytd')}
                                className="px-4 py-2 rounded-xl bg-slate-800 text-slate-300 hover:bg-slate-700 hover:text-white transition-all text-sm"
                            >
                                YTD
                            </button>
                        </div>
                    </div>
                </div>

                {loading ? (
                    <div className="text-center py-12">
                        <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
                        <p className="text-slate-400">Generating report...</p>
                    </div>
                ) : isFutureDateRange() ? (
                    <div className="text-center py-12 bg-[#151d30] rounded-2xl border border-slate-800">
                        <div className="mx-auto mb-4 w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center">
                            <svg className="w-8 h-8 text-amber-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                            </svg>
                        </div>
                        <h3 className="text-xl font-bold text-white mb-2">Future Date Selected</h3>
                        <p className="text-slate-400 mb-4">The selected start date is in the future.</p>
                        <p className="text-slate-500 text-sm">Reports can only be generated for past dates. Please select a date range up to today.</p>
                    </div>
                ) : isDataEmpty() ? (
                    <div className="text-center py-12 bg-[#151d30] rounded-2xl border border-slate-800">
                        <div className="mx-auto mb-4 w-16 h-16 bg-indigo-500/10 rounded-full flex items-center justify-center">
                            <svg className="w-8 h-8 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4" />
                            </svg>
                        </div>
                        <h3 className="text-xl font-bold text-white mb-2">No Events Found</h3>
                        <p className="text-slate-400 mb-4">No events occurred during the selected period.</p>
                        <div className="bg-slate-900/50 rounded-lg p-4 mt-4 text-left max-w-md mx-auto border border-slate-800">
                            <p className="text-slate-400 text-sm mb-2">Possible reasons:</p>
                            <ul className="text-slate-500 text-sm space-y-1 list-disc list-inside">
                                <li>No events held between {startDate} and {endDate}</li>
                                {type && <li>No {type.replace('_', ' ').toLowerCase()} events in this period</li>}
                                {regionId && <li>No events in the selected region</li>}
                            </ul>
                            <p className="text-slate-600 text-xs mt-3 pt-3 border-t border-slate-800">Try selecting a different date range or adjusting your filters.</p>
                        </div>
                    </div>
                ) : data ? (
                    <div className="animate-fade-in space-y-8">
                        {/* Key Metrics */}
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                            <div className="bg-[#151d30] p-6 rounded-2xl border border-slate-800">
                                <div className="flex items-center gap-3 mb-2">
                                    <div className="p-2 rounded-lg bg-indigo-500/20 text-indigo-400">
                                        <Users size={20} />
                                    </div>
                                    <span className="text-slate-400 font-medium">Total Attendance</span>
                                </div>
                                <p className="text-3xl font-bold text-white">{data.stats.totalAttendance}</p>
                                <p className="text-slate-500 text-sm mt-2">Across {data.stats.totalEvents} events</p>
                            </div>

                            <div className="bg-[#151d30] p-6 rounded-2xl border border-slate-800">
                                <div className="flex items-center gap-3 mb-2">
                                    <div className="p-2 rounded-lg bg-green-500/20 text-green-400">
                                        <TrendingUp size={20} />
                                    </div>
                                    <span className="text-slate-400 font-medium">Average Attendance</span>
                                </div>
                                <p className="text-3xl font-bold text-white">{data.stats.averageAttendance}</p>
                                <p className="text-slate-500 text-sm mt-2">Per event</p>
                            </div>

                            <div className="bg-[#151d30] p-6 rounded-2xl border border-slate-800">
                                <div className="flex items-center gap-3 mb-2">
                                    <div className="p-2 rounded-lg bg-purple-500/20 text-purple-400">
                                        <UserCheck size={20} />
                                    </div>
                                    <span className="text-slate-400 font-medium">Unique Members</span>
                                </div>
                                <p className="text-3xl font-bold text-white">{data.stats.uniqueMembers}</p>
                                <p className="text-slate-500 text-sm mt-2">Distinct individuals</p>
                            </div>

                            <div className="bg-[#151d30] p-6 rounded-2xl border border-slate-800">
                                <div className="flex items-center gap-3 mb-2">
                                    <div className="p-2 rounded-lg bg-blue-500/20 text-blue-400">
                                        <PieChartIcon size={20} />
                                    </div>
                                    <span className="text-slate-400 font-medium">Gender Ratio</span>
                                </div>
                                <div className="flex items-center gap-4 mt-1">
                                    <div>
                                        <p className="text-2xl font-bold text-white">{data.stats.genderBreakdown.MALE}</p>
                                        <p className="text-xs text-slate-500">Male</p>
                                    </div>
                                    <div className="h-8 w-px bg-slate-700"></div>
                                    <div>
                                        <p className="text-2xl font-bold text-white">{data.stats.genderBreakdown.FEMALE}</p>
                                        <p className="text-xs text-slate-500">Female</p>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Charts */}
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                            <div className="bg-[#151d30] p-6 rounded-2xl border border-slate-800">
                                <h3 className="text-xl font-bold text-white mb-6">Attendance Trend</h3>
                                <div className="h-80">
                                    <ResponsiveContainer width="100%" height="100%">
                                        <LineChart data={data.chartData}>
                                            <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                                            <XAxis dataKey="date" stroke="#94a3b8" />
                                            <YAxis stroke="#94a3b8" />
                                            <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }} />
                                            <Line type="monotone" dataKey="attendance" stroke="#8884d8" strokeWidth={2} />
                                        </LineChart>
                                    </ResponsiveContainer>
                                </div>
                            </div>

                            <div className="bg-[#151d30] p-6 rounded-2xl border border-slate-800">
                                <h3 className="text-xl font-bold text-white mb-6">Region Distribution</h3>
                                <div className="h-80">
                                    <ResponsiveContainer width="100%" height="100%">
                                        <BarChart data={regionChartData} layout="vertical">
                                            <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                                            <XAxis type="number" stroke="#94a3b8" />
                                            <YAxis dataKey="name" type="category" stroke="#94a3b8" width={100} />
                                            <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }} />
                                            <Bar dataKey="value" fill="#2dd4bf" radius={[0, 4, 4, 0]} />
                                        </BarChart>
                                    </ResponsiveContainer>
                                </div>
                            </div>
                        </div>

                        {/* Academic Statistics */}
                        {(data.stats.yearOfStudyBreakdown || data.stats.collegeBreakdown || data.stats.courseBreakdown) && (
                            <div className="mb-8">
                                <h2 className="text-2xl font-bold text-white mb-6">Academic Statistics</h2>
                                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                                    {/* Year of Study */}
                                    {data.stats.yearOfStudyBreakdown && Object.keys(data.stats.yearOfStudyBreakdown).length > 0 && (
                                        <div className="bg-[#151d30] p-6 rounded-2xl border border-slate-800">
                                            <h3 className="text-xl font-bold text-white mb-6">Year of Study</h3>
                                            <div className="h-64">
