import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Lock, ShieldCheck, ArrowRight } from 'lucide-react';
import api from '../api';
import logo from '../assets/logo.jpg';
import { ToastProvider, useToast } from '../components/ToastProvider';

const ForcePasswordChangeContent = () => {
    const { showToast } = useToast();
    const location = useLocation();
    const navigate = useNavigate();
    const { login } = useAuth();
    
    const [email, setEmail] = useState('');
    const [oldPassword, setOldPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        // Must come from the Login page trap with credentials
        if (!location.state || !location.state.email || !location.state.oldPassword) {
            navigate('/login', { replace: true });
            return;
        }
        setEmail(location.state.email);
        setOldPassword(location.state.oldPassword);
    }, [location, navigate]);

    const validateForm = () => {
        if (!newPassword || !confirmPassword) {
            setError('Please fill in both password fields');
            return false;
        }
        if (newPassword.length < 8) {
            setError('Password must be at least 8 characters long');
            return false;
        }
        if (newPassword === oldPassword) {
            setError('New password must be different from the old temporary password');
            return false;
        }
        if (newPassword !== confirmPassword) {
            setError('Passwords do not match');
            return false;
        }
        return true;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        
        if (!validateForm()) return;

        setLoading(true);

        try {
            const response = await api.post('/auth/force-change-password', {
                email,
                oldPassword,
                newPassword
            });

            const data = response.data;
            const { token, message, ...userData } = data;

            showToast('success', 'Password completely secured! Logging you in...');

            // Log them in using the returned token
            setTimeout(() => {
                login(token, {
                    id: userData.id,
                    fullName: userData.fullName,
                    email: userData.email,
                    role: userData.role,
                    fellowshipNumber: userData.fellowshipNumber,
                    qrCode: userData.qrCode,
                    tags: userData.tags || [],
                });
            }, 1000);
            
        } catch (err: any) {
            console.error('[FORCE_CHANGE_PW] Error:', err);
            setError(err.response?.data?.message || err.message || 'Failed to update password');
            setLoading(false);
        }
    };

    return (
        <div className="h-dvh overflow-hidden flex items-center justify-center px-3 sm:px-4 bg-slate-100">
            <div className="max-w-md w-full rounded-2xl sm:rounded-3xl p-5 sm:p-7 shadow-premium bg-premium-texture animate-slide-up relative z-10 max-h-[calc(100dvh-2rem)] overflow-y-auto">
                <div className="text-center mb-5 relative z-20">
                    <div className="mx-auto mb-3 w-16 h-16 rounded-full flex items-center justify-center shadow-md bg-amber-50">
                        <ShieldCheck size={32} className="text-amber-500 hover:scale-110 transition-transform" />
                    </div>
                    <h1 className="text-2xl font-bold text-slate-800 mb-2 tracking-tight">Security Update Required</h1>
                    <p className="text-slate-600 font-medium text-sm">
                        Please set a new, secure password for <strong className="text-slate-900">{email}</strong> to access your account.
                    </p>
                </div>

                {error && (
                    <div className="bg-red-50 border border-red-100 text-red-700 p-4 rounded-xl mb-6 text-sm relative z-20 animate-jiggle">
                        {error}
                    </div>
                )}

                <div className="bg-amber-50/50 border border-amber-200/50 rounded-xl p-4 mb-6 text-xs text-amber-800 relative z-20">
                    <strong>Why am I seeing this?</strong><br/>
                    You are logging in with a temporary password (your fellowship number). For your protection, you must choose a secret password before continuing to your dashboard.
                </div>

                <form onSubmit={handleSubmit} className="space-y-4 relative z-20">
                    <div>
                        <label className="block text-slate-700 mb-2 text-sm font-medium">New Password</label>
                        <div className="relative group">
                            <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-[#48A111] transition-colors" size={20} />
                            <input
                                type="password"
                                required
                                minLength={8}
                                value={newPassword}
                                onChange={(e) => setNewPassword(e.target.value)}
                                className="w-full pl-12 pr-4 py-3 bg-slate-50/50 border border-slate-200 rounded-xl text-slate-900 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#48A111]/20 focus:border-[#48A111] transition-all duration-200"
                                placeholder="Min. 8 characters"
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-slate-700 mb-2 text-sm font-medium">Confirm New Password</label>
                        <div className="relative group">
                            <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-[#48A111] transition-colors" size={20} />
                            <input
                                type="password"
                                required
                                value={confirmPassword}
                                onChange={(e) => setConfirmPassword(e.target.value)}
                                className="w-full pl-12 pr-4 py-3 bg-slate-50/50 border border-slate-200 rounded-xl text-slate-900 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#48A111]/20 focus:border-[#48A111] transition-all duration-200"
                                placeholder="Re-type your password"
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full mt-2 text-white font-semibold py-3 px-6 text-[15px] rounded-xl transition-all shadow-lg hover:shadow-xl disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                        style={{ backgroundColor: loading ? '#48A111' : '#48A111' }}
                        onMouseEnter={(e) => !loading && (e.currentTarget.style.backgroundColor = '#F2B50B')}
                        onMouseLeave={(e) => !loading && (e.currentTarget.style.backgroundColor = '#48A111')}
                    >
                        {loading ? (
                            <>
                                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                                Updating Security...
                            </>
                        ) : (
                            <>
                                Secure Account & Login
                                <ArrowRight size={20} />
                            </>
                        )}
                    </button>
                    
                    <button
                        type="button"
                        onClick={() => navigate('/login')}
                        className="w-full mt-2 py-2 text-sm text-slate-500 hover:text-slate-800 transition-colors"
                    >
                        Cancel & Return to Login
                    </button>
                </form>
            </div>
        </div>
    );
};

// Wrap with ToastProvider so we can show success toasts
const ForcePasswordChange = () => {
    return (
        <ToastProvider>
            <ForcePasswordChangeContent />
        </ToastProvider>
    );
};

export default ForcePasswordChange;

import React, { useState, useEffect } from 'react';
import api from '../api';
import { useToast } from '../components/ToastProvider';
import LoadingSpinner from '../components/LoadingSpinner';
import { UserPlus, Check, X } from 'lucide-react';
import EventSelector from '../components/EventSelector';
import type { Event } from '../types/event';

const GuestCheckIn = () => {
    const [activeEvents, setActiveEvents] = useState<Event[]>([]);
    const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);
    const [loading, setLoading] = useState(true);
    const [checking, setChecking] = useState(false);
    const [formData, setFormData] = useState({
        guestName: '',
        guestPhone: '',
        purpose: '',
    });
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState('');
    const toast = useToast();

    useEffect(() => {
        fetchActiveEvent();
    }, []);

    const fetchActiveEvent = async () => {
        try {
            const response = await api.get('/events/active');
            const events = Array.isArray(response.data) ? response.data : [response.data];
            setActiveEvents(events);
            // Auto-select first event if only one
            if (events.length === 1) {
                setSelectedEvent(events[0]);
            }
        } catch (error: any) {
            if (error.response?.status === 404) {
                setError('No active event at the moment');
            } else {
                setError('Failed to load event');
            }
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setChecking(true);
        setError('');

        try {
            await api.post('/attendance/guest-check-in', {
                eventId: selectedEvent?.id,
                ...formData,
            });

            setSuccess(true);
            setFormData({ guestName: '', guestPhone: '', purpose: '' });
            toast.success('Check-in successful! Welcome to ' + selectedEvent?.name);

            setTimeout(() => {
                setSuccess(false);
            }, 3000);
        } catch (error: any) {
            const errorMessage = error.response?.data?.error || 'Check-in failed';
            setError(errorMessage);
            toast.error(errorMessage);
        } finally {
            setChecking(false);
        }
    };

    if (loading) {
        return <LoadingSpinner message="Loading event information..." />;
    }

    if (activeEvents.length === 0 && !loading) {
        return (
            <div className="flex items-center justify-center min-h-[calc(100vh-12rem)]">
                <div className="premium-card p-8 max-w-md w-full text-center">
                    <X size={64} className="mx-auto mb-4 text-red-400" />
                    <h2 className="text-2xl font-bold text-white mb-2">No Active Event</h2>
                    <p className="text-slate-400">{error || 'There is no event currently accepting check-ins.'}</p>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-2xl mx-auto animate-fade-in">
            {/* Event Selector */}
            <EventSelector
                events={activeEvents}
                selectedEvent={selectedEvent}
                onEventChange={setSelectedEvent}
                loading={loading}
            />

            {/* Only show form if event is selected */}
            {selectedEvent && (
                <>
                    {/* Success Message */}
                    {success && (
                        <div className="bg-emerald-500/20 backdrop-blur-xl rounded-xl p-6 mb-6 border border-emerald-500/30 flex items-center gap-4 animate-bounce-in premium-card">
                            <Check size={48} className="text-emerald-400" />
                            <div>
                                <h3 className="text-xl font-bold text-white">Check-in Successful!</h3>
                                <p className="text-emerald-200">Welcome to {selectedEvent?.name}</p>
                            </div>
                        </div>
                    )}

                    {/* Error Message */}
                    {error && !success && (
                        <div className="bg-red-500/20 backdrop-blur-xl rounded-xl p-6 mb-6 border border-red-500/30 flex items-center gap-4 premium-card">
                            <X size={48} className="text-red-400" />
                            <div>
                                <h3 className="text-xl font-bold text-white">Check-in Failed</h3>
                                <p className="text-red-200">{error}</p>
                            </div>
                        </div>
                    )}

                    {/* Guest Check-in Form */}
                    <div className="premium-card corner-accent p-8">
                        <div className="flex items-center gap-3 mb-6">
                            <div className="w-12 h-12 rounded-xl bg-teal-600 flex items-center justify-center shadow-lg glow-primary">
                                <UserPlus size={24} className="text-white" />
                            </div>
                            <h2 className="text-2xl font-bold text-white">Guest Check-in</h2>
                        </div>

                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-slate-300 mb-2 font-semibold text-sm">Full Name *</label>
                                <input
                                    type="text"
                                    required
                                    value={formData.guestName}
                                    onChange={(e) => setFormData({ ...formData, guestName: e.target.value })}
                                    className="input"
                                    placeholder="John Doe"
                                />
                            </div>

                            <div>
                                <label className="block text-slate-300 mb-2 font-semibold text-sm">Phone Number (Optional)</label>
                                <input
                                    type="tel"
                                    value={formData.guestPhone}
                                    onChange={(e) => setFormData({ ...formData, guestPhone: e.target.value })}
                                    className="input"
                                    placeholder="+256 700 000 000"
                                />
                            </div>

                            <div>
                                <label className="block text-slate-300 mb-2 font-semibold text-sm">Purpose of Visit (Optional)</label>
                                <textarea
                                    value={formData.purpose}
                                    onChange={(e) => setFormData({ ...formData, purpose: e.target.value })}
                                    rows={3}
                                    className="input"
                                    placeholder="Guest speaker, visitor, etc."
                                />
                            </div>

                            <button
                                type="submit"
                                disabled={checking}
                                className="btn btn-primary w-full py-4 text-base font-semibold rounded-xl mt-6 shadow-lg"
                            >
                                {checking ? 'Checking In...' : 'Check In'}
                            </button>
                        </form>
                    </div>
                </>
            )}
        </div>
    );
};

export default GuestCheckIn;

import React, { useState, useEffect } from 'react';
import { Users, Plus, Loader2, UserCheck, Home, UserX, ChevronDown, ChevronUp, Mail, Phone, Hash } from 'lucide-react';
import { toast } from 'react-hot-toast';
import api from '../../api';
import FamilyCard from '../../components/Leadership/FamilyCard';
import CreateFamilyModal from '../../components/Leadership/CreateFamilyModal';
import AssignFamilyHeadModal from '../../components/Leadership/AssignFamilyHeadModal';
import { useAuth } from '../../context/AuthContext';

interface FamilyMember {
