                                    </div>
                                    <div className="min-w-0">
                                        <div className="flex items-center gap-1.5 flex-wrap">
                                            <p className="text-slate-900 font-semibold text-sm truncate">{fm.member.fullName}</p>
                                            {family.familyHead?.id === fm.member.id && (
