};

/* ΓöÇΓöÇΓöÇ Stat card ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
interface StatCardProps {
    label: string;
    value: number;
    icon: React.ReactNode;
    active: boolean;
    onClick: () => void;
    accent?: string;
}
const StatCard: React.FC<StatCardProps> = ({ label, value, icon, active, onClick, accent = '#48A111' }) => (
    <button
        onClick={onClick}
        className={`bg-white rounded-2xl border-2 shadow-xl p-5 flex items-center justify-between w-full text-left transition-all hover:scale-[1.02] cursor-pointer ${active ? 'border-[#48A111] shadow-[0_0_0_3px_rgba(72,161,17,0.15)]' : 'border-slate-200 hover:border-slate-300'
            }`}
    >
        <div>
            <p className="text-slate-500 text-sm mb-1">{label}</p>
            <p className="text-4xl font-bold text-slate-900">{value}</p>
        </div>
        <div
            className="w-12 h-12 rounded-xl flex items-center justify-center shrink-0"
            style={{ backgroundColor: active ? accent + '22' : '#f1f5f9' }}
        >
            <span style={{ color: active ? accent : '#94a3b8' }}>{icon}</span>
        </div>
    </button>
);

/* ΓöÇΓöÇΓöÇ Main component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
const FamiliesManagement = () => {
    const { user } = useAuth();
    const [families, setFamilies] = useState<Family[]>([]);
    const [loading, setLoading] = useState(true);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
    const [showAssignHeadModal, setShowAssignHeadModal] = useState(false);
    const [view, setView] = useState<ViewMode>('all');

    const isFellowshipManager = user?.role === 'FELLOWSHIP_MANAGER';

    useEffect(() => { fetchFamilies(); }, []);

    const fetchFamilies = async () => {
        try {
            const response = await api.get('/families');
            setFamilies(response.data);
        } catch {
            toast.error('Failed to load families');
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteFamily = async (familyId: string) => {
        const family = families.find(f => f.id === familyId);
        if (!family) return;
        if (!confirm(`Delete "${family.name}"?\n\nThis will:\n- Remove all members\n- Deactivate family tags\n- Preserve history`)) return;
        try {
            await api.delete(`/families/${familyId}`);
            toast.success(`${family.name} deleted successfully`);
            fetchFamilies();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to delete family');
        }
    };

    const handleAssignHead = (family: Family) => {
        setSelectedFamily(family);
        setShowAssignHeadModal(true);
    };

    const handleStatClick = (newView: ViewMode) => {
        // Clicking the active card resets to 'all', clicking another card sets it
        setView((prev) => (prev === newView ? 'all' : newView));
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center py-24">
                <Loader2 className="animate-spin mr-3" style={{ color: '#48A111' }} size={36} />
                <span className="text-slate-500">Loading families...</span>
            </div>
        );
    }

    const totalMembers = families.reduce((sum, f) => sum + f._count.members, 0);
    const familiesWithHeads = families.filter(f => f.familyHead).length;
    const familiesWithoutHeads = families.filter(f => !f.familyHead).length;

    // Derive displayed list based on active view
    const displayedFamilies =
        view === 'with-heads' ? families.filter(f => f.familyHead)
            : view === 'no-heads' ? families.filter(f => !f.familyHead)
                : families;

    // View label for subheading
    const viewLabels: Record<ViewMode, string> = {
        all: 'All Families',
        'with-heads': 'Families with Heads',
        'no-heads': 'Families without Heads',
        members: 'Members by Family',
    };

    return (
        <div className="max-w-6xl mx-auto animate-fade-in">
            {/* Page header */}
            <div className="flex items-start justify-between mb-8">
                <div className="flex items-center gap-3">
                    <div className="p-3 rounded-xl relative overflow-hidden" style={{ backgroundColor: '#e9f5e1' }}>
                        <div className="absolute inset-0 opacity-30 rounded-xl" style={{ backgroundColor: '#48A111' }} />
                        <Home className="w-6 h-6 relative z-10" style={{ color: '#48A111' }} />
                    </div>
                    <div>
                        <div className="flex items-center gap-2">
                            <h1 className="text-3xl font-bold text-slate-900">Families</h1>
                            <span className="w-2 h-2 rounded-full" style={{ backgroundColor: '#F2B50B' }} />
                        </div>
                        <p className="text-slate-500 text-sm mt-0.5">Manage small groups and discipleship families</p>
                    </div>
                </div>

                {isFellowshipManager && view !== 'members' && (
                    <button
                        onClick={() => setShowCreateModal(true)}
                        className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-white font-semibold shadow-lg transition-all hover:scale-[1.02] active:scale-[0.98] cursor-pointer"
                        style={{ backgroundColor: '#48A111' }}
                        onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = '#F2B50B')}
                        onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = '#48A111')}
                    >
                        <Plus size={18} />
                        Create Family
                    </button>
                )}
            </div>

            {/* Stat cards ΓÇö 4 columns */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
                <StatCard
                    label="Total Families"
                    value={families.length}
                    icon={<Home size={22} />}
                    active={view === 'all'}
                    onClick={() => handleStatClick('all')}
                />
                <StatCard
                    label="Families with Heads"
                    value={familiesWithHeads}
                    icon={<UserCheck size={22} />}
                    active={view === 'with-heads'}
                    onClick={() => handleStatClick('with-heads')}
                />
                <StatCard
                    label="Without Heads"
                    value={familiesWithoutHeads}
                    icon={<UserX size={22} />}
                    active={view === 'no-heads'}
                    onClick={() => handleStatClick('no-heads')}
                    accent="#F2B50B"
                />
                <StatCard
                    label="Total Members"
                    value={totalMembers}
                    icon={<Users size={22} />}
                    active={view === 'members'}
                    onClick={() => handleStatClick('members')}
                />
            </div>

            {/* View label */}
            <div className="flex items-center gap-2 mb-5">
                <h2 className="text-lg font-bold text-slate-700">{viewLabels[view]}</h2>
                <span className="text-sm text-slate-400">
                    ({view === 'members' ? families.length : displayedFamilies.length})
                </span>
                {view !== 'all' && (
                    <button
                        onClick={() => setView('all')}
                        className="ml-auto text-xs text-slate-400 hover:text-slate-600 cursor-pointer underline"
                    >
                        Clear filter
                    </button>
                )}
            </div>

            {/* ΓöÇΓöÇ Members accordion view ΓöÇΓöÇ */}
            {view === 'members' ? (
                families.length === 0 ? (
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-xl p-16 text-center text-slate-400">
                        No families yet
                    </div>
                ) : (
                    <div className="space-y-3">
                        {families.map((family) => (
                            <FamilyAccordionRow key={family.id} family={family} />
                        ))}
                    </div>
                )
            ) : (
                /* ΓöÇΓöÇ Card grid view ΓöÇΓöÇ */
                displayedFamilies.length === 0 ? (
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-xl p-16 text-center">
                        <div className="w-20 h-20 rounded-full mx-auto mb-5 flex items-center justify-center" style={{ backgroundColor: '#e9f5e1' }}>
                            <Home size={36} style={{ color: '#48A111' }} />
                        </div>
                        <h3 className="text-xl font-bold text-slate-900 mb-2">
                            {view === 'with-heads' ? 'No families have a head assigned' :
                                view === 'no-heads' ? 'All families have heads ΓÇö great work!' :
                                    'No Families Yet'}
                        </h3>
                        <p className="text-slate-500 mb-6 text-sm">
                            {view === 'all' ? 'Create your first family to get started' : ''}
                        </p>
                        {view === 'all' && isFellowshipManager && (
                            <button
                                onClick={() => setShowCreateModal(true)}
                                className="px-6 py-3 rounded-xl text-white font-semibold inline-flex items-center gap-2 shadow-lg transition-all hover:scale-[1.02] cursor-pointer"
                                style={{ backgroundColor: '#48A111' }}
                                onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = '#F2B50B')}
                                onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = '#48A111')}
                            >
                                <Plus size={18} />
                                Create Family
                            </button>
                        )}
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
                        {displayedFamilies.map((family) => (
                            <FamilyCard
                                key={family.id}
                                family={family}
                                onDelete={isFellowshipManager ? handleDeleteFamily : undefined}
                                onAssignHead={handleAssignHead}
                            />
                        ))}
                    </div>
                )
            )}

            {/* Modals */}
            {isFellowshipManager && (
                <CreateFamilyModal
                    isOpen={showCreateModal}
                    onClose={() => setShowCreateModal(false)}
                    onSuccess={fetchFamilies}
                />
            )}

            {selectedFamily && (
                <AssignFamilyHeadModal
                    isOpen={showAssignHeadModal}
                    onClose={() => {
                        setShowAssignHeadModal(false);
                        setSelectedFamily(null);
                    }}
                    onSuccess={fetchFamilies}
                    family={selectedFamily}
                />
            )}
        </div>
    );
};

export default FamiliesManagement;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import {
    ArrowLeft, Users, UserPlus, Trash2, Loader2, Calendar,
    Clock, MapPin, Edit2, Save, X, UserCheck, UserX
} from 'lucide-react';
import { toast } from 'react-hot-toast';
import api from '../../api';
import AddFamilyMemberModal from '../../components/Leadership/AddFamilyMemberModal';
import { useAuth } from '../../context/AuthContext';

interface FamilyMember {
    id: string;
    member: {
        id: string;
        fullName: string;
        email: string;
        phoneNumber: string;
        fellowshipNumber: string;
    };
    joinedAt: string;
}

interface FamilyDetails {
    id: string;
    name: string;
    region: {
        id: string;
        name: string;
    };
    familyHead?: {
        id: string;
        fullName: string;
    } | null;
    meetingDay?: string | null;
    meetingTime?: string | null;
    meetingVenue?: string | null;
    members: FamilyMember[];
}

const DAYS_OF_WEEK = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

const inputClass = "w-full px-4 py-2.5 rounded-xl bg-slate-50 border-2 border-slate-200 text-slate-900 placeholder-slate-400 focus:outline-none transition-all text-sm";
const inputFocus = {
    onFocus: (e: React.FocusEvent<HTMLInputElement | HTMLSelectElement>) => {
        e.currentTarget.style.borderColor = '#48A111';
        e.currentTarget.style.boxShadow = '0 0 0 3px rgba(72,161,17,0.12)';
    },
    onBlur: (e: React.FocusEvent<HTMLInputElement | HTMLSelectElement>) => {
        e.currentTarget.style.borderColor = '#e2e8f0';
        e.currentTarget.style.boxShadow = 'none';
    },
};

const FamilyDetailsPage = () => {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const { user } = useAuth();

    const [family, setFamily] = useState<FamilyDetails | null>(null);
    const [loading, setLoading] = useState(true);
    const [showAddMemberModal, setShowAddMemberModal] = useState(false);

    const [editingSchedule, setEditingSchedule] = useState(false);
    const [scheduleForm, setScheduleForm] = useState({
        meetingDay: '',
        meetingTime: '',
        meetingVenue: '',
    });

    useEffect(() => {
        if (id) fetchFamilyDetails();
    }, [id]);

    const fetchFamilyDetails = async () => {
        try {
            const response = await api.get(`/families/${id}`);
            setFamily(response.data);
            setScheduleForm({
                meetingDay: response.data.meetingDay || '',
                meetingTime: response.data.meetingTime || '',
                meetingVenue: response.data.meetingVenue || '',
            });
        } catch (error) {
            console.error('Failed to fetch family:', error);
            toast.error('Failed to load family details');
            navigate('/leadership/families');
        } finally {
            setLoading(false);
        }
    };

    const handleRemoveMember = async (memberId: string, memberName: string) => {
        if (!confirm(`Remove ${memberName} from ${family?.name}?\n\nThis will deactivate their family member tag.`)) return;
        try {
            await api.delete(`/families/${id}/members/${memberId}`);
            toast.success(`${memberName} removed from family`);
            fetchFamilyDetails();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to remove member');
        }
    };

    const handleSaveSchedule = async () => {
        try {
            await api.put(`/families/${id}`, scheduleForm);
            toast.success('Meeting schedule updated');
            setEditingSchedule(false);
            fetchFamilyDetails();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to update schedule');
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center py-24">
                <div className="text-center">
                    <Loader2 className="animate-spin mx-auto mb-4" style={{ color: '#48A111' }} size={40} />
                    <p className="text-slate-500">Loading family details...</p>
                </div>
            </div>
        );
    }

    if (!family) return null;

    return (
        <div className="max-w-5xl mx-auto animate-fade-in">
            {/* Back link */}
            <Link
                to="/leadership/families"
                className="inline-flex items-center gap-2 text-slate-500 hover:text-slate-800 mb-6 transition-colors text-sm font-medium"
            >
                <ArrowLeft size={16} />
                Back to Families
            </Link>

            {/* Page header */}
            <div className="flex items-start justify-between mb-8">
                <div className="flex items-center gap-3">
                    <div className="p-3 rounded-xl" style={{ backgroundColor: '#e9f5e1', color: '#48A111' }}>
                        <Users className="w-6 h-6" />
                    </div>
                    <div>
                        <h1 className="text-3xl font-bold text-slate-900">{family.name}</h1>
                        <div className="flex items-center gap-1.5 text-slate-500 text-sm mt-0.5">
                            <MapPin size={13} style={{ color: '#48A111' }} />
                            {family.region.name}
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Left column */}
                <div className="space-y-5">
                    {/* Family Head card */}
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-xl p-5">
                        <h2 className="text-base font-bold text-slate-900 mb-3">Family Head</h2>
                        {family.familyHead ? (
                            <div
                                className="flex items-center gap-3 p-3 rounded-xl border"
                                style={{ backgroundColor: '#e9f5e1', borderColor: '#c5e3b0' }}
                            >
                                <UserCheck size={18} style={{ color: '#48A111' }} />
                                <span className="font-semibold text-slate-900 text-sm">{family.familyHead.fullName}</span>
                            </div>
                        ) : (
                            <div className="flex items-center gap-3 p-3 rounded-xl bg-slate-50 border border-slate-200">
                                <UserX size={18} className="text-slate-400" />
                                <span className="text-slate-400 italic text-sm">No head assigned</span>
                            </div>
                        )}
                    </div>

                    {/* Meeting Schedule card */}
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-xl p-5">
                        <div className="flex items-center justify-between mb-3">
                            <h2 className="text-base font-bold text-slate-900">Meeting Schedule</h2>
                            {!editingSchedule ? (
                                <button
                                    onClick={() => setEditingSchedule(true)}
                                    className="p-1.5 rounded-xl bg-slate-100 text-slate-500 hover:bg-slate-200 transition-colors cursor-pointer"
                                >
                                    <Edit2 size={15} />
                                </button>
                            ) : (
                                <div className="flex gap-1.5">
                                    <button
                                        onClick={handleSaveSchedule}
                                        className="p-1.5 rounded-xl cursor-pointer transition-all"
                                        style={{ backgroundColor: '#e9f5e1', color: '#48A111' }}
                                    >
                                        <Save size={15} />
                                    </button>
                                    <button
                                        onClick={() => {
                                            setEditingSchedule(false);
                                            setScheduleForm({
                                                meetingDay: family.meetingDay || '',
                                                meetingTime: family.meetingTime || '',
                                                meetingVenue: family.meetingVenue || '',
                                            });
                                        }}
                                        className="p-1.5 rounded-xl bg-slate-100 text-slate-500 hover:bg-slate-200 transition-colors cursor-pointer"
                                    >
                                        <X size={15} />
                                    </button>
                                </div>
                            )}
                        </div>

                        {!editingSchedule ? (
                            <div className="space-y-2.5">
                                {family.meetingDay && (
                                    <div className="flex items-center gap-2.5 text-sm text-slate-600">
                                        <Calendar size={14} style={{ color: '#48A111' }} />
                                        <span>{family.meetingDay}s</span>
                                    </div>
                                )}
                                {family.meetingTime && (
                                    <div className="flex items-center gap-2.5 text-sm text-slate-600">
                                        <Clock size={14} style={{ color: '#48A111' }} />
                                        <span>{family.meetingTime}</span>
                                    </div>
                                )}
                                {family.meetingVenue && (
                                    <div className="flex items-center gap-2.5 text-sm text-slate-600">
                                        <MapPin size={14} style={{ color: '#48A111' }} />
                                        <span>{family.meetingVenue}</span>
                                    </div>
                                )}
                                {!family.meetingDay && !family.meetingTime && !family.meetingVenue && (
                                    <p className="text-slate-400 italic text-sm">No schedule set</p>
                                )}
                            </div>
                        ) : (
                            <div className="space-y-3">
                                <div>
                                    <label className="block text-xs font-semibold text-slate-500 mb-1">Day</label>
                                    <select
                                        value={scheduleForm.meetingDay}
                                        onChange={(e) => setScheduleForm({ ...scheduleForm, meetingDay: e.target.value })}
                                        className={inputClass}
                                        {...inputFocus}
                                    >
                                        <option value="">Select day...</option>
                                        {DAYS_OF_WEEK.map(day => (
                                            <option key={day} value={day}>{day}</option>
                                        ))}
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-xs font-semibold text-slate-500 mb-1">Time</label>
                                    <input
                                        type="time"
                                        value={scheduleForm.meetingTime}
                                        onChange={(e) => setScheduleForm({ ...scheduleForm, meetingTime: e.target.value })}
                                        className={inputClass}
                                        {...inputFocus}
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-semibold text-slate-500 mb-1">Venue</label>
                                    <input
                                        type="text"
                                        value={scheduleForm.meetingVenue}
                                        onChange={(e) => setScheduleForm({ ...scheduleForm, meetingVenue: e.target.value })}
                                        placeholder="e.g., Block A, Room 101"
                                        className={inputClass}
                                        {...inputFocus}
                                    />
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                {/* Right column ΓÇö Members */}
                <div className="lg:col-span-2">
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-xl p-6">
                        <div className="flex items-center justify-between mb-5">
                            <div className="flex items-center gap-2">
                                <Users size={20} style={{ color: '#48A111' }} />
                                <h2 className="text-xl font-bold text-slate-900">
                                    Members
                                    <span className="ml-2 text-base font-normal text-slate-400">({family.members.length})</span>
                                </h2>
                            </div>
                            <button
                                onClick={() => setShowAddMemberModal(true)}
                                className="flex items-center gap-2 px-4 py-2 rounded-xl text-white text-sm font-semibold shadow-lg transition-all hover:scale-[1.02] cursor-pointer"
                                style={{ backgroundColor: '#48A111' }}
                                onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = '#F2B50B')}
                                onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = '#48A111')}
                            >
                                <UserPlus size={16} />
                                Add Member
                            </button>
                        </div>

                        {family.members.length === 0 ? (
                            <div className="text-center py-16">
                                <div className="w-16 h-16 rounded-full mx-auto mb-4 flex items-center justify-center" style={{ backgroundColor: '#e9f5e1' }}>
                                    <Users size={28} style={{ color: '#48A111' }} />
                                </div>
                                <p className="text-slate-500 mb-4 text-sm">No members in this family yet</p>
                                <button
                                    onClick={() => setShowAddMemberModal(true)}
                                    className="px-4 py-2 rounded-xl text-white text-sm font-semibold cursor-pointer transition-all hover:scale-[1.02]"
                                    style={{ backgroundColor: '#48A111' }}
                                    onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = '#F2B50B')}
                                    onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = '#48A111')}
                                >
                                    Add Your First Member
                                </button>
                            </div>
                        ) : (
                            <div className="space-y-2.5">
                                {family.members.map((familyMember) => (
                                    <div
                                        key={familyMember.id}
                                        className="bg-slate-50 border border-slate-200 rounded-xl p-4 hover:border-slate-300 transition-colors"
                                    >
                                        <div className="flex items-center justify-between gap-3">
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center gap-2 flex-wrap">
                                                    <h3 className="text-slate-900 font-semibold text-sm">
                                                        {familyMember.member.fullName}
                                                    </h3>
                                                    {family.familyHead?.id === familyMember.member.id && (
                                                        <span
                                                            className="text-xs px-2 py-0.5 rounded-full font-bold"
                                                            style={{ backgroundColor: '#e9f5e1', color: '#48A111' }}
                                                        >
                                                            Head
                                                        </span>
                                                    )}
                                                </div>
                                                <div className="flex flex-wrap gap-x-3 gap-y-0.5 text-xs text-slate-400 mt-1">
                                                    <span>{familyMember.member.email}</span>
                                                    {familyMember.member.phoneNumber && (
                                                        <span>{familyMember.member.phoneNumber}</span>
                                                    )}
                                                    <span>#{familyMember.member.fellowshipNumber}</span>
                                                </div>
                                                <p className="text-xs text-slate-400 mt-1">
                                                    Joined {new Date(familyMember.joinedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                                                </p>
                                            </div>
                                            <button
                                                onClick={() => handleRemoveMember(familyMember.member.id, familyMember.member.fullName)}
                                                className="p-2 rounded-xl bg-red-50 text-red-400 hover:bg-red-100 transition-colors cursor-pointer shrink-0"
                                                title="Remove from family"
                                            >
                                                <Trash2 size={15} />
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <AddFamilyMemberModal
                isOpen={showAddMemberModal}
                onClose={() => setShowAddMemberModal(false)}
                onSuccess={fetchFamilyDetails}
                family={family}
            />
        </div>
    );
};

export default FamilyDetailsPage;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Users, Calendar, MapPin, Mail, Phone, Hash, Loader2, User2, AlertCircle } from 'lucide-react';
import { Link } from 'react-router-dom';
import { toast } from 'react-hot-toast';
import { formatDistanceToNow } from 'date-fns';
import api from '../../api';
import { useAuth } from '../../context/AuthContext';
import FamilyTransferManagementPanel from './components/FamilyTransferManagementPanel';

interface Member {
    id: string;
    fullName: string;
    email: string;
    phoneNumber: string;
    fellowshipNumber: string;
    gender: 'MALE' | 'FEMALE';
    joinedAt: string;
}

interface FamilyData {
    id: string;
    name: string;
    region: {
        id: string;
        name: string;
    };
    familyHead: {
        id: string;
        fullName: string;
        email: string;
        phoneNumber: string;
    };
    meetingDay: string | null;
    meetingTime: string | null;
    meetingVenue: string | null;
    members: Member[];
    stats: {
        totalMembers: number;
        maleCount: number;
        femaleCount: number;
    };
}

const FamilyHeadDashboard = () => {
    const navigate = useNavigate();
    const { hasTag, hasFamilyMemberTag } = useAuth();
    const [family, setFamily] = useState<FamilyData | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        fetchFamilyData();
    }, []);

    const fetchFamilyData = async () => {
        try {
            setLoading(true);

            // Check if user is a family head or just a member
            if (hasTag('FAMILY_HEAD')) {
                // Head - fetch from head dashboard endpoint
                const response = await api.get('/families/my-family');
                setFamily(response.data);
                setError(null);
            } else if (hasFamilyMemberTag()) {
                // Regular member - fetch from member endpoint and redirect to detail page
                const response = await api.get('/families/my-family-member');
                const familyData = response.data;
                // Redirect to family detail page
                navigate(`/leadership/families/${familyData.id}`, { replace: true });
                return;
            } else {
                // Not assigned to any family
                setError('You are not currently assigned to any family');
            }
        } catch (error: any) {
            console.error('Failed to fetch family:', error);
            if (error.response?.status === 404) {
                setError('You are not assigned as a family head');
            } else {
                setError('Failed to load family data');
                toast.error('Failed to load family data');
            }
        } finally {
            setLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <div className="text-center">
                    <Loader2 className="animate-spin text-teal-500 mx-auto mb-4" size={48} />
                    <p className="text-gray-400">Loading your family...</p>
                </div>
            </div>
        );
    }

    if (error || !family) {
        return (
            <div className="min-h-screen p-6">
                <div className="max-w-4xl mx-auto">
                    <div className="bg-white border border-slate-200 rounded-2xl shadow-sm p-12 text-center">
                        <AlertCircle className="text-amber-500 mx-auto mb-4" size={64} />
                        <h2 className="text-2xl font-bold text-slate-900 mb-2">No Family Assigned</h2>
                        <p className="text-slate-500 mb-6">
                            {error || 'You are not currently assigned as a family head'}
                        </p>
                        <Link
                            to="/profile"
                            className="inline-block px-6 py-3 rounded-xl text-white font-semibold shadow-md transition-all hover:scale-[1.02]"
                            style={{ backgroundColor: '#48A111' }}
                        >
                            Go to Profile
                        </Link>
                    </div>
                </div>
            </div>
        );
    }

    const formatDay = (day: string | null) => {
        if (!day) return 'Not set';
        return day.charAt(0) + day.slice(1).toLowerCase();
    };

    return (
        <div className="min-h-screen p-6">
            <div className="max-w-7xl mx-auto">
                {/* Header */}
                <div className="mb-8">
                    <h1 className="text-3xl font-bold text-slate-900 mb-2 tracking-tight">My Family Dashboard</h1>
                    <p className="text-slate-600 font-medium text-lg">
                        {family.name} ΓÇó {family.region.name}
                    </p>
                    <p className="text-slate-400 text-xs mt-1.5">
                        Last updated: {new Date().toLocaleTimeString()}
                    </p>
                </div>

                {/* Stats Cards */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                        <div className="flex items-center justify-between mb-4">
                            <div className="w-12 h-12 rounded-full bg-[#e9f5e1] flex items-center justify-center">
                                <Users size={24} style={{ color: '#48A111' }} />
                            </div>
                        </div>
                        <p className="text-3xl font-bold text-slate-900">{family.stats.totalMembers}</p>
                        <p className="text-slate-500 font-medium text-sm mt-1">Total Members</p>
                    </div>

                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                        <div className="flex items-center justify-between mb-4">
                            <div className="w-12 h-12 rounded-full bg-blue-50 flex items-center justify-center">
                                <User2 className="text-blue-500" size={24} />
                            </div>
                        </div>
                        <p className="text-3xl font-bold text-slate-900">{family.stats.maleCount}</p>
                        <p className="text-slate-500 font-medium text-sm mt-1">Male Members</p>
                    </div>

                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                        <div className="flex items-center justify-between mb-4">
                            <div className="w-12 h-12 rounded-full bg-pink-50 flex items-center justify-center">
                                <User2 className="text-pink-500" size={24} />
                            </div>
                        </div>
                        <p className="text-3xl font-bold text-slate-900">{family.stats.femaleCount}</p>
                        <p className="text-slate-500 font-medium text-sm mt-1">Female Members</p>
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    {/* Meeting Schedule */}
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                        <h2 className="text-xl font-bold text-slate-900 mb-6 flex items-center gap-2">
                            <Calendar size={24} style={{ color: '#48A111' }} />
                            Meeting Schedule
                        </h2>
                        <div className="space-y-4">
                            <div className="flex items-start gap-4 p-4 bg-slate-50 border border-slate-200 rounded-xl">
                                <Calendar className="text-slate-400 mt-1" size={20} />
                                <div>
                                    <p className="text-slate-500 text-xs font-bold uppercase tracking-wide">Day</p>
                                    <p className="text-slate-900 font-bold">{formatDay(family.meetingDay)}</p>
                                </div>
                            </div>
                            <div className="flex items-start gap-4 p-4 bg-slate-50 border border-slate-200 rounded-xl">
                                <Calendar className="text-slate-400 mt-1" size={20} />
                                <div>
                                    <p className="text-slate-500 text-xs font-bold uppercase tracking-wide">Time</p>
                                    <p className="text-slate-900 font-bold">{family.meetingTime || 'Not set'}</p>
                                </div>
                            </div>
                            <div className="flex items-start gap-4 p-4 bg-slate-50 border border-slate-200 rounded-xl">
                                <MapPin className="text-slate-400 mt-1" size={20} />
                                <div>
                                    <p className="text-slate-500 text-xs font-bold uppercase tracking-wide">Venue</p>
                                    <p className="text-slate-900 font-bold">{family.meetingVenue || 'Not set'}</p>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Family Head Info */}
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                        <h2 className="text-xl font-bold text-slate-900 mb-6 flex items-center gap-2">
                            <Users size={24} style={{ color: '#48A111' }} />
                            Family Head
                        </h2>
                        <div className="space-y-4">
                            <div className="p-5 bg-slate-50 border border-slate-200 rounded-xl relative overflow-hidden">
                                <div className="absolute top-0 left-0 w-1 h-full" style={{ backgroundColor: '#48A111' }}></div>
                                <p className="text-sm font-bold uppercase tracking-wide mb-2" style={{ color: '#48A111' }}>You are the head of this family</p>
                                <p className="text-slate-900 font-bold text-lg mb-4">{family.familyHead.fullName}</p>
                                <div className="space-y-2.5">
                                    <div className="flex items-center gap-2.5 text-slate-500">
                                        <Mail size={16} />
                                        <span className="text-sm font-medium">{family.familyHead.email}</span>
                                    </div>
                                    <div className="flex items-center gap-2.5 text-slate-500">
                                        <Phone size={16} />
                                        <span className="text-sm font-medium">{family.familyHead.phoneNumber}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <FamilyTransferManagementPanel currentFamilyId={family.id} />

                {/* Members List */}
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 mt-8">
                    <h2 className="text-xl font-bold text-slate-900 mb-6">
                        Family Members <span className="text-slate-400 font-normal">({family.members.length})</span>
                    </h2>
                    {family.members.length > 0 ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
                            {family.members.map((member) => (
                                <div
                                    key={member.id}
                                    className="p-5 bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-md hover:border-slate-300 transition-all group"
                                >
                                    <div className="flex items-start justify-between mb-4">
                                        <div className="flex-1">
                                            <Link
                                                to={`/members/${member.id}`}
                                                className="text-slate-900 font-bold group-hover:text-[#48A111] transition-colors"
                                            >
                                                {member.fullName}
                                            </Link>
                                            <p className="text-slate-400 text-xs mt-0.5">#{member.fellowshipNumber}</p>
                                            <p className="text-slate-400 text-xs mt-1.5">
                                                Joined {formatDistanceToNow(new Date(member.joinedAt), { addSuffix: true })}
                                            </p>
                                        </div>
                                        <span className={`text-xs px-2.5 py-1 rounded-full font-semibold ${member.gender === 'MALE' ? 'bg-blue-50 text-blue-600 border border-blue-100' : 'bg-pink-50 text-pink-600 border border-pink-100'
                                            }`}>
                                            {member.gender}
                                        </span>
                                    </div>
                                    <div className="space-y-2 mb-4">
                                        <div className="flex items-center gap-2.5 text-slate-500 text-sm">
                                            <Mail size={14} className="text-slate-400" />
                                            <span className="truncate">{member.email}</span>
                                        </div>
                                        <div className="flex items-center gap-2.5 text-slate-500 text-sm">
                                            <Phone size={14} className="text-slate-400" />
                                            <span>{member.phoneNumber}</span>
                                        </div>
                                    </div>
                                    {/* Quick Actions */}
                                    <div className="flex items-center gap-2 pt-4 border-t border-slate-100">
                                        <a
                                            href={`tel:${member.phoneNumber}`}
                                            className="flex-1 text-center text-xs font-semibold px-3 py-2 bg-slate-50 border border-slate-200 text-slate-600 rounded-xl hover:bg-slate-100 transition-colors"
                                        >
                                            ≡ƒô₧ Call
                                        </a>
                                        <a
                                            href={`mailto:${member.email}`}
                                            className="flex-1 text-center text-xs font-semibold px-3 py-2 bg-slate-50 border border-slate-200 text-slate-600 rounded-xl hover:bg-slate-100 transition-colors"
                                        >
                                            Γ£ë∩╕Å Email
                                        </a>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="text-center py-16 bg-slate-50 rounded-2xl border border-slate-200">
                            <Users className="mx-auto mb-4 text-slate-400" size={48} />
                            <p className="text-slate-500">No members in this family yet</p>
                        </div>
                    )}
                </div>

                {/* Gender Distribution */}
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 mt-8">
                    <h2 className="text-xl font-bold text-slate-900 mb-6">Member Distribution</h2>
                    <div className="space-y-5">
                        <div>
                            <div className="flex justify-between mb-2">
                                <span className="text-sm font-medium text-slate-500">Male</span>
                                <span className="text-sm text-slate-900 font-bold">
                                    {family.stats.maleCount} ({Math.round((family.stats.maleCount / family.stats.totalMembers) * 100) || 0}%)
                                </span>
                            </div>
                            <div className="w-full h-3 bg-slate-100 rounded-full overflow-hidden">
                                <div
                                    className="h-full bg-blue-500 transition-all duration-500"
                                    style={{ width: `${(family.stats.maleCount / family.stats.totalMembers) * 100 || 0}%` }}
                                />
                            </div>
                        </div>
                        <div>
                            <div className="flex justify-between mb-2">
                                <span className="text-sm font-medium text-slate-500">Female</span>
                                <span className="text-sm text-slate-900 font-bold">
                                    {family.stats.femaleCount} ({Math.round((family.stats.femaleCount / family.stats.totalMembers) * 100) || 0}%)
                                </span>
                            </div>
                            <div className="w-full h-3 bg-slate-100 rounded-full overflow-hidden">
                                <div
                                    className="h-full bg-pink-500 transition-all duration-500"
                                    style={{ width: `${(family.stats.femaleCount / family.stats.totalMembers) * 100 || 0}%` }}
                                />
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default FamilyHeadDashboard;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../api';
import { useAuth } from '../../context/AuthContext';
import LoadingSpinner from '../../components/LoadingSpinner';
import { FileText, Calendar, Users, AlertCircle, Eye } from 'lucide-react';
import { toast } from 'react-hot-toast';

interface PublishedReport {
    id: string;
    eventId: string;
    isPublished: boolean;
    publishedAt: string;
    event: {
        id: string;
        name: string;
        date: string;
        type: string;
        venue?: string;
    };
    publisher: {
        fullName: string;
    } | null;
}

const LeaderReports: React.FC = () => {
    const { user } = useAuth();
    const [reports, setReports] = useState<PublishedReport[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchPublishedReports();
    }, []);

    const fetchPublishedReports = async () => {
        try {
            setLoading(true);
            const response = await api.get('/reports/published');
            setReports(response.data);
        } catch (error: any) {
            console.error('Failed to fetch reports:', error);
            toast.error('Failed to load reports');
        } finally {
            setLoading(false);
        }
    };

    if (loading) return <LoadingSpinner message="Loading reportsΓÇª" />;

    return (
        <div className="min-h-screen p-6">
            <div className="max-w-5xl mx-auto">
                {/* Header */}
                <div className="mb-8">
                    <h1 className="text-4xl font-bold text-slate-900 mb-2 tracking-tight">Event Reports</h1>
                    <p className="text-slate-500">
                        Dispatched reports from the Fellowship Manager
                    </p>
                </div>

                {reports.length === 0 ? (
                    <div className="bg-white border border-slate-200 rounded-2xl shadow-sm p-16 text-center">
                        <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-[#e9f5e1] mb-4">
                            <FileText size={32} style={{ color: '#48A111' }} />
                        </div>
                        <h2 className="text-2xl font-bold text-slate-900 mb-2">No Reports Yet</h2>
                        <p className="text-slate-500">
                            No event reports have been dispatched to leaders yet.
                        </p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {reports.map((report) => (
                            <Link
                                key={report.id}
                                to={`/events/${report.eventId}/report`}
                                className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 block hover:shadow-md hover:border-slate-300 transition-all group"
                            >
                                {/* Event name */}
                                <h3 className="text-lg font-bold text-slate-900 group-hover:text-[#48A111] transition-colors mb-2">
                                    {report.event.name}
                                </h3>

                                {/* Tags */}
                                <div className="flex items-center gap-2 mb-4 flex-wrap">
                                    <span className="text-xs px-2.5 py-1 bg-sky-50 text-sky-600 rounded-xl border border-sky-100 font-medium">
                                        {report.event.type.replace('_', ' ')}
                                    </span>
                                    <span className="text-xs px-2.5 py-1 bg-[#e9f5e1] text-[#48A111] rounded-xl border border-[#48A111]/20 flex items-center gap-1.5 font-medium">
                                        <span className="w-1.5 h-1.5 rounded-full bg-[#48A111] inline-block" />
                                        Dispatched
                                    </span>
                                </div>

                                {/* Details */}
                                <div className="space-y-2.5 text-sm text-slate-500">
                                    <div className="flex items-center gap-2.5">
                                        <Calendar size={14} className="text-slate-400" />
                                        <span>
                                            {new Date(report.event.date).toLocaleDateString('en-UG', {
                                                weekday: 'long',
                                                year: 'numeric',
                                                month: 'long',
                                                day: 'numeric',
                                            })}
                                        </span>
                                    </div>
                                    {report.event.venue && (
                                        <div className="flex items-center gap-2.5">
                                            <AlertCircle size={14} className="text-slate-400" />
                                            <span>{report.event.venue}</span>
                                        </div>
                                    )}
                                    {report.publisher && (
                                        <div className="flex items-center gap-2.5">
                                            <Users size={14} className="text-slate-400" />
                                            <span>Dispatched by {report.publisher.fullName}</span>
                                        </div>
                                    )}
                                    <div className="flex items-center gap-2.5 text-slate-400 text-xs pt-1">
                                        <span>
                                            Dispatched on {new Date(report.publishedAt).toLocaleDateString('en-UG', {
                                                day: 'numeric',
                                                month: 'short',
                                                year: 'numeric',
                                            })}
                                        </span>
                                    </div>
                                </div>

                                {/* View CTA */}
                                <div className="mt-5 pt-4 border-t border-slate-100 flex items-center justify-between">
                                    <span className="text-xs font-medium text-slate-400">Click to view full report</span>
                                    <Eye size={16} className="text-slate-400 group-hover:text-[#48A111] group-hover:scale-110 transition-all" />
                                </div>
                            </Link>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
};

export default LeaderReports;

import React, { useState, useEffect } from 'react';
import {
    Users, UserCheck, Building2, TrendingUp, UserPlus, UserMinus,
    ChevronRight, Crown, Shield, Home
} from 'lucide-react';
import { Link } from 'react-router-dom';
import { toast } from 'react-hot-toast';
import api from '../../api';
import AssignRegionalHeadModal from '../../components/Leadership/AssignRegionalHeadModal';
import LoadingSpinner from '../../components/LoadingSpinner';

interface Region {
    id: string;
    name: string;
    regionalHead?: { id: string; fullName: string } | null;
    families: Array<{
        id: string;
        name: string;
        familyHead?: { id: string; fullName: string } | null;
        _count: { members: number };
    }>;
    _count: { members: number };
}

interface MinistryTeam {
    id: string;
    name: string;
    leader?: { id: string; fullName: string } | null;
    _count: { members: number };
}

interface Stats {
    totalMembers: number;
    totalRegions: number;
    totalFamilies: number;
    totalTeams: number;
}

const StatCard = ({
    value, label, icon: Icon, iconBg, iconColor, to
}: {
    value: number; label: string; icon: React.ElementType;
    iconBg: string; iconColor: string; to?: string;
}) => {
    const inner = (
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 flex items-center gap-5 hover:shadow-md transition-all">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 ${iconBg}`}>
                <Icon size={24} className={iconColor} />
            </div>
            <div>
                <p className="text-3xl font-bold text-slate-900 leading-none">{value}</p>
                <p className="text-sm text-slate-500 mt-1">{label}</p>
            </div>
        </div>
    );
    return to ? <Link to={to} className="group">{inner}</Link> : <div>{inner}</div>;
};

const LeadershipOverview = () => {
    const [regions, setRegions] = useState<Region[]>([]);
    const [ministryTeams, setMinistryTeams] = useState<MinistryTeam[]>([]);
    const [stats, setStats] = useState<Stats>({ totalMembers: 0, totalRegions: 0, totalFamilies: 0, totalTeams: 0 });
    const [loading, setLoading] = useState(true);
    const [selectedRegion, setSelectedRegion] = useState<Region | null>(null);
    const [showAssignModal, setShowAssignModal] = useState(false);

    useEffect(() => { fetchOrgStructure(); }, []);

    const fetchOrgStructure = async () => {
        try {
            const response = await api.get('/leadership/structure');
            setRegions(response.data.regions);
            setMinistryTeams(response.data.ministryTeams);
            setStats(response.data.stats);
        } catch {
            toast.error('Failed to load organizational structure');
        } finally {
            setLoading(false);
        }
    };

    const handleRemoveRegionalHead = async (regionId: string) => {
        if (!confirm('Remove this regional head?')) return;
        try {
            await api.delete(`/leadership/regional-heads/${regionId}/remove`);
            toast.success('Regional head removed');
            fetchOrgStructure();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to remove regional head');
        }
    };

    if (loading) return <LoadingSpinner message="Loading structure..." />;

    return (
        <div className="max-w-7xl mx-auto animate-fade-in">
            {/* Page Header */}
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Leadership Structure</h1>
                    <p className="text-slate-500 mt-1 text-sm">Organizational hierarchy and ministry overview</p>
                </div>
                <div className="flex gap-3">
                    <Link
                        to="/leadership/teams"
                        className="flex items-center gap-2 px-4 py-2.5 rounded-xl border-2 border-slate-200 text-slate-600 font-semibold text-sm hover:bg-slate-50 transition-all"
                    >
                        <Shield size={16} />
                        Manage Teams
                    </Link>
                    <Link
                        to="/leadership/families"
                        className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-white font-semibold text-sm shadow-lg transition-all hover:scale-[1.02]"
                        style={{ backgroundColor: '#48A111' }}
                        onMouseEnter={e => (e.currentTarget.style.backgroundColor = '#F2B50B')}
                        onMouseLeave={e => (e.currentTarget.style.backgroundColor = '#48A111')}
                    >
                        <Home size={16} />
                        Manage Families
                    </Link>
                </div>
            </div>

            {/* Stats Row */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
                <StatCard value={stats.totalMembers} label="Total Members" icon={Users} iconBg="bg-[#e9f5e1]" iconColor="text-[#48A111]" />
                <StatCard value={stats.totalRegions} label="Regions" icon={Building2} iconBg="bg-blue-50" iconColor="text-blue-500" to="/regions" />
                <StatCard value={stats.totalFamilies} label="Families" icon={UserCheck} iconBg="bg-yellow-50" iconColor="text-yellow-600" to="/leadership/families" />
                <StatCard value={stats.totalTeams} label="Ministry Teams" icon={TrendingUp} iconBg="bg-purple-50" iconColor="text-purple-500" to="/leadership/teams" />
            </div>

            {/* Main content 2-col */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* ΓöÇΓöÇ Pastoral Structure ΓöÇΓöÇ */}
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                    <div className="px-6 py-5 border-b border-slate-100 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="p-2.5 rounded-xl bg-[#e9f5e1]">
                                <Crown size={18} className="text-[#48A111]" />
                            </div>
                            <div>
                                <h2 className="font-bold text-slate-900 text-base">Pastoral Structure</h2>
                                <p className="text-xs text-slate-500">{regions.length} regions</p>
                            </div>
                        </div>
                    </div>

                    <div className="p-4 space-y-3 max-h-[600px] overflow-y-auto">
                        {regions.length === 0 ? (
                            <div className="text-center py-10 text-slate-400 text-sm">
                                No regions configured yet
                            </div>
                        ) : regions.map(region => (
                            <div key={region.id} className="rounded-xl border border-slate-100 bg-slate-50 overflow-hidden">
                                {/* Region header */}
                                <div className="px-4 py-3 flex items-center justify-between bg-white border-b border-slate-100">
                                    <div className="flex items-center gap-2.5">
                                        <div className="w-8 h-8 rounded-lg bg-blue-50 flex items-center justify-center shrink-0">
                                            <Building2 size={14} className="text-blue-500" />
                                        </div>
                                        <div>
                                            <p className="font-semibold text-slate-900 text-sm">{region.name}</p>
                                            <p className="text-xs text-slate-400">{region._count.members} members</p>
                                        </div>
                                    </div>
                                    <span className="text-xs font-semibold text-slate-500 bg-slate-100 px-2.5 py-1 rounded-full">
                                        {region.families.length} {region.families.length === 1 ? 'family' : 'families'}
                                    </span>
                                </div>

                                <div className="px-4 py-3 space-y-2">
                                    {/* Regional Head */}
                                    {region.regionalHead ? (
                                        <div className="flex items-center justify-between bg-white rounded-lg px-3 py-2.5 border border-slate-200">
                                            <div className="flex items-center gap-2.5">
                                                <div className="w-7 h-7 rounded-full bg-purple-100 flex items-center justify-center">
                                                    <Crown size={12} className="text-purple-500" />
                                                </div>
                                                <div>
                                                    <p className="text-xs font-semibold text-purple-700">Regional Head</p>
                                                    <p className="text-sm text-slate-800 font-medium">{region.regionalHead.fullName}</p>
                                                </div>
                                            </div>
                                            <div className="flex gap-1.5">
                                                <button
                                                    onClick={() => { setSelectedRegion(region); setShowAssignModal(true); }}
