import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LogIn, User, Lock, Shield, Clock } from 'lucide-react';
import api from '../api';
import logo from '../assets/logo.jpg';
import OTPInput from '../components/OTPInput';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const { login } = useAuth();
    const location = useLocation();
    const navigate = useNavigate();

    // Check for elevation redirect
    useEffect(() => {
        const queryParams = new URLSearchParams(location.search);
        if (queryParams.get('reason') === 'elevated') {
            setError('Your account permissions have changed (e.g., leadership assignment). Please sign in again with two-factor authentication to verify your identity.');
            // Clean up the URL
            navigate('/login', { replace: true });
        }
    }, [location, navigate]);

    // MFA state
    const [showOTPScreen, setShowOTPScreen] = useState(false);
    const [tempToken, setTempToken] = useState('');
    const [otpLoading, setOtpLoading] = useState(false);
    const [resendCooldown, setResendCooldown] = useState(0);
    const [isSuccess, setIsSuccess] = useState(false);
    const [isShaking, setIsShaking] = useState(false);

    // Forgot Password State
    const [showForgotModal, setShowForgotModal] = useState(false);
    const [forgotEmail, setForgotEmail] = useState('');
    const [forgotLoading, setForgotLoading] = useState(false);
    const [forgotStatus, setForgotStatus] = useState<{type: 'success' | 'error', msg: string} | null>(null);

    // Audio context for sound effects
    const playErrorSound = () => {
        try {
            const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
            if (!AudioContext) return;

            const ctx = new AudioContext();
            const oscillators = [220, 110]; // Low frequency "buzz"

            oscillators.forEach((freq, i) => {
                const osc = ctx.createOscillator();
                const gain = ctx.createGain();

                osc.type = 'sawtooth';
                osc.frequency.setValueAtTime(freq, ctx.currentTime);

                gain.gain.setValueAtTime(0.1, ctx.currentTime);
                gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.3);

                osc.connect(gain);
                gain.connect(ctx.destination);

                osc.start(ctx.currentTime);
                osc.stop(ctx.currentTime + 0.3);
            });
        } catch (e) {
            console.error('Audio playback failed', e);
        }
    };

    const getErrorMessage = (error: any) => {
        if (!error.response) {
            return 'Network error. Please check your connection.';
        }

        const status = error.response.status;
        const data = error.response.data;

        if (data && data.message) return data.message;

        switch (status) {
            case 400:
                return 'Invalid request. Please try again.';
            case 401:
                return 'Incorrect verification code. Please try again.';
            case 403:
                return 'Access denied. Please contact support.';
            case 404:
                return 'User not found.';
            case 429:
                return 'Too many attempts. Please try again later.';
            case 500:
                return 'Server error. Please try again later.';
            default:
                return 'Something went wrong. Please try again.';
        }
    };

    // No body scroll lock ΓÇö the login card must be scrollable on short screens

    // Handle initial login (Step 1: Email/Password)
    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            const response = await api.post('/auth/login', { email, password });
            const data = response.data;

            // Check if MFA is required
            if (data.requiresOTP) {
                console.log('[LOGIN] MFA required - showing OTP screen');
                setTempToken(data.tempToken);
                setShowOTPScreen(true);
                setError(''); // Clear any previous errors
            } else {
                // Regular member - direct login
                console.log('[LOGIN] Regular member - direct login');
                const { token, message, ...userData } = data;

                if (message && message !== 'Login successful') {
                    setError(message);
                }

                if (userData.forcePasswordChange) {
                    navigate('/force-change-password', { 
                        state: { 
                            email: userData.email, 
                            oldPassword: password 
                        } 
                    });
                    return;
                }

                login(token, {
                    id: userData.id,
                    fullName: userData.fullName,
                    email: userData.email,
                    role: userData.role,
                    fellowshipNumber: userData.fellowshipNumber,
                    qrCode: userData.qrCode,
                    tags: userData.tags || [],
                });
            }
        } catch (err: any) {
            console.error('[LOGIN] Error:', err);
            setError(err.response?.data?.message || err.message || 'Login failed');
        } finally {
            setLoading(false);
        }
    };

    // Handle OTP verification (Step 2: For privileged accounts)
    const handleOTPVerification = async (otp: string) => {
        setError('');
        setOtpLoading(true);

        try {
            const response = await api.post('/auth/verify-otp', {
                tempToken,
                otp,
            });

            const { token, message, ...userData } = response.data;

            console.log('[OTP] Verification successful');
            setIsSuccess(true);

            // Add slight delay to show success state
            setTimeout(() => {
                if (userData.forcePasswordChange) {
                    navigate('/force-change-password', { 
                        state: { 
                            email: userData.email, 
                            // During OTP flow we still have the original password in state
                            oldPassword: password 
                        } 
                    });
                    return;
                }

                login(token, {
                    id: userData.id,
                    fullName: userData.fullName,
                    email: userData.email,
                    role: userData.role,
                    fellowshipNumber: userData.fellowshipNumber,
                    qrCode: userData.qrCode,
                    tags: userData.tags || [],
                });
            }, 800);
        } catch (err: any) {
            console.error('[OTP] Verification error:', err);

            // Visual feedback
            setIsSuccess(false);
            setIsShaking(true);
            setTimeout(() => setIsShaking(false), 500); // Reset shake after animation

            // Audio feedback
            playErrorSound();

            // Helpful error message
            setError(getErrorMessage(err));
        } finally {
            setOtpLoading(false);
        }
    };

    // Handle OTP resend
    const handleResendOTP = async () => {
        if (resendCooldown > 0) return;

        setError('');
        setLoading(true);

        try {
            await api.post('/auth/resend-otp', { tempToken });
            setError(''); // Clear errors

            // Show success message
            setError('Γ£à New code sent to your email');

            // Start cooldown (60 seconds)
            setResendCooldown(60);
            const interval = setInterval(() => {
                setResendCooldown((prev) => {
                    if (prev <= 1) {
                        clearInterval(interval);
                        return 0;
                    }
                    return prev - 1;
                });
            }, 1000);
        } catch (err: any) {
            console.error('[RESEND OTP] Error:', err);
            setError(err.response?.data?.message || 'Failed to resend code');
        } finally {
            setLoading(false);
        }
    };

    // Go back to login screen
    const handleBackToLogin = () => {
        setShowOTPScreen(false);
        setTempToken('');
        setError('');
    };

    // Handle Forgot Password submission
    const handleForgotPassword = async (e: React.FormEvent) => {
        e.preventDefault();
        setForgotLoading(true);
        setForgotStatus(null);
        
        try {
            const res = await api.post('/auth/forgot-password', { email: forgotEmail });
            setForgotStatus({ type: 'success', msg: res.data.message });
        } catch (err: any) {
            setForgotStatus({ 
                type: 'error', 
                msg: err.response?.data?.message || 'Failed to send reset email. Please try again.' 
            });
        } finally {
            setForgotLoading(false);
        }
    };

    if (showOTPScreen) {
        return (
            <div className="h-dvh overflow-hidden flex items-center justify-center px-3 sm:px-4 bg-slate-100">
                <div className="max-w-md w-full rounded-2xl sm:rounded-3xl p-4 sm:p-6 shadow-premium bg-premium-texture animate-slide-up relative z-10 max-h-[calc(100dvh-2rem)] overflow-y-auto">
                    <div className="text-center mb-4 relative z-20">
                        <div className="mx-auto mb-3 w-12 h-12 rounded-full flex items-center justify-center shadow-sm" style={{ backgroundColor: 'rgba(72, 161, 17, 0.1)' }}>
                            <Shield size={24} style={{ color: '#48A111' }} />
                        </div>
                        <h1 className="text-xl sm:text-2xl font-bold text-black mb-1 tracking-tight">Verify Your Identity</h1>
                        <p className="text-slate-500 font-medium text-sm">
                            We've sent a 6-digit code to <strong className="text-slate-900">{email}</strong>
                        </p>
                        <p className="text-slate-400 text-xs mt-1">
                            Please check your inbox. If you don't see the email, kindly check your spam or junk folder.
                        </p>
                    </div>

                    {error && (
                        <div className={`p-4 rounded-xl mb-6 text-sm ${error.startsWith('Γ£à')
                            ? 'bg-green-50 border border-green-200 text-green-700'
                            : 'bg-red-50 border border-red-100 text-red-700'
                            } relative z-20`}>
                            {error}
                        </div>
                    )}

                    <div className={`mb-4 relative z-20 ${isShaking ? 'animate-shake' : ''}`}>
                        <label className="block text-slate-700 mb-2 text-sm font-medium text-center">
                            Enter Verification Code
                        </label>
                        <OTPInput
                            onComplete={handleOTPVerification}
                            loading={otpLoading}
                            isError={!!error}
                            isSuccess={isSuccess}
                        />
                    </div>

                    <div className="flex items-center justify-center gap-2 text-xs text-slate-500 mb-4 relative z-20">
                        <Clock size={14} />
                        <span>Code expires in 5 minutes</span>
                    </div>

                    <div className="space-y-2 relative z-20">
                        <button
                            onClick={handleResendOTP}
                            disabled={resendCooldown > 0 || loading}
                            className="w-full py-3 rounded-xl text-white transition-all disabled:opacity-50 disabled:cursor-not-allowed text-sm font-medium shadow-sm hover:shadow-md"
                            style={{ backgroundColor: '#48A111' }}
                            onMouseEnter={(e) => !e.currentTarget.disabled && (e.currentTarget.style.backgroundColor = '#F2B50B')}
                            onMouseLeave={(e) => !e.currentTarget.disabled && (e.currentTarget.style.backgroundColor = '#48A111')}
                        >
                            {resendCooldown > 0 ? `Resend code in ${resendCooldown}s` : 'Resend Code'}
                        </button>

                        <button
                            onClick={handleBackToLogin}
                            className="w-full py-3 rounded-xl transition-all text-sm font-medium hover:bg-slate-50"
                            style={{ color: '#F2B50B' }}
                        >
                            ΓåÉ Back to Login
                        </button>
                    </div>

                    <div className="mt-4 p-3 border rounded-xl relative z-20" style={{ backgroundColor: 'rgba(72, 161, 17, 0.05)', borderColor: 'rgba(72, 161, 17, 0.1)' }}>
                        <p className="text-xs text-center" style={{ color: '#48A111' }}>
                            <Shield size={14} className="inline mr-1" />
                            Your account requires two-factor authentication for enhanced security
                        </p>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="h-dvh overflow-hidden flex items-center justify-center px-3 sm:px-4 bg-slate-100">
            <div className="max-w-md w-full rounded-2xl sm:rounded-3xl p-5 sm:p-7 shadow-premium bg-premium-texture animate-slide-up relative z-10 max-h-[calc(100dvh-2rem)] overflow-y-auto">
                <div className="text-center mb-5 sm:mb-7 relative z-20">
                    <div className="w-16 h-16 sm:w-20 sm:h-20 rounded-2xl mx-auto mb-3 sm:mb-5 p-1 bg-white shadow-lg rotate-3 hover:rotate-0 transition-transform duration-500 ease-out">
                        <img
                            src={logo}
                            alt="Fellowship Logo"
                            className="w-full h-full rounded-xl object-cover"
                        />
                    </div>
                    <h1 className="text-2xl sm:text-3xl font-bold text-black mb-2 tracking-tight">Welcome Back</h1>
                    <p className="text-slate-500 font-medium">Sign in to access your account</p>
                </div>

                {error && (
                    <div className="bg-red-50 border border-red-100 text-red-700 p-4 rounded-xl mb-6 text-sm relative z-20">
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-3 sm:space-y-5 relative z-20">
                    <div>
                        <label className="block text-black mb-2 text-sm font-medium">Email Address</label>
                        <div className="relative group">
                            <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-[#48A111] transition-colors" size={20} />
                            <input
                                type="email"
                                required
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                className="w-[90%] mx-auto pl-12 pr-4 py-2 bg-slate-50/50 border border-slate-200 rounded-xl text-slate-900 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#48A111]/20 focus:border-[#48A111] transition-all duration-200 shadow-sm hover:bg-white hover:scale-[1.015] focus:scale-[1.015] hover:shadow-md focus:shadow-md"
                                placeholder="Enter your email"
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-black mb-2 text-sm font-medium">Password</label>
                        <div className="relative group">
                            <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-[#48A111] transition-colors" size={20} />
                            <input
                                type="password"
                                required
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                className="w-[90%] mx-auto pl-12 pr-4 py-2 bg-slate-50/50 border border-slate-200 rounded-xl text-slate-900 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#48A111]/20 focus:border-[#48A111] transition-all duration-200 shadow-sm hover:bg-white hover:scale-[1.015] focus:scale-[1.015] hover:shadow-md focus:shadow-md"
                                placeholder="Enter your password"
                            />
                        </div>
                        <div className="flex justify-end mt-2">
                            <button
                                type="button"
                                onClick={() => setShowForgotModal(true)}
                                className="text-sm font-medium hover:underline transition-all"
                                style={{ color: '#48A111' }}
                            >
                                Forgot Password?
                            </button>
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full text-white font-semibold py-3 px-6 text-[15px] rounded-xl transition-all transform hover:scale-[1.02] active:scale-[0.98] shadow-lg disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                        style={{ backgroundColor: loading ? '#48A111' : '#48A111' }}
                        onMouseEnter={(e) => !loading && (e.currentTarget.style.backgroundColor = '#F2B50B')}
                        onMouseLeave={(e) => !loading && (e.currentTarget.style.backgroundColor = '#48A111')}
                    >
                        {loading ? (
                            <>
                                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                                Signing in...
                            </>
                        ) : (
                            <>
                                <LogIn size={20} />
                                Sign In
                            </>
                        )}
                    </button>
                </form>
            </div>

            {/* Forgot Password Modal */}
            {showForgotModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-md p-6 relative animate-scale-up">
                        <div className="mb-5">
                            <h2 className="text-xl font-bold text-slate-900">Reset Password</h2>
                            <p className="text-sm text-slate-500 mt-1">Enter your email address and we'll send you a link to reset your password.</p>
                        </div>
                        
                        {forgotStatus && (
                            <div className={`p-4 rounded-xl mb-5 text-sm ${
                                forgotStatus.type === 'success' 
                                    ? 'bg-green-50 border border-green-200 text-green-700' 
                                    : 'bg-red-50 border border-red-100 text-red-700'
                            }`}>
                                {forgotStatus.msg}
                            </div>
                        )}

                        <form onSubmit={handleForgotPassword}>
                            <label className="block text-slate-700 mb-2 text-sm font-medium">Email Address</label>
                            <input
                                type="email"
                                required
                                value={forgotEmail}
                                onChange={(e) => setForgotEmail(e.target.value)}
                                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-slate-900 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#48A111]/20 focus:border-[#48A111] transition-all"
                                placeholder="Enter your email"
                                disabled={forgotLoading || forgotStatus?.type === 'success'}
                            />

                            <div className="mt-6 flex gap-3">
                                <button
                                    type="button"
                                    onClick={() => {
                                        setShowForgotModal(false);
                                        setForgotStatus(null);
                                        setForgotEmail('');
                                    }}
                                    className="flex-1 py-2.5 rounded-xl font-medium text-slate-600 bg-slate-100 hover:bg-slate-200 transition-colors"
                                >
                                    Close
                                </button>
                                <button
                                    type="submit"
                                    disabled={forgotLoading || forgotStatus?.type === 'success' || !forgotEmail}
                                    className="flex-1 py-2.5 rounded-xl font-medium text-white transition-all disabled:opacity-50 flex items-center justify-center"
                                    style={{ backgroundColor: '#48A111' }}
                                >
                                    {forgotLoading ? (
                                        <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                                    ) : (
                                        'Send Reset Link'
                                    )}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Login;

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api';
import { useAuth } from '../context/AuthContext';
import { ArrowLeft, Search, Filter, CheckCircle, XCircle, User, MapPin, Users, Loader2 } from 'lucide-react';
import { useToast } from '../components/ToastProvider';

interface Member {
    id: string;
    fullName: string;
    fellowshipNumber: string;
    email: string;
    phoneNumber: string;
    gender: 'MALE' | 'FEMALE';
    region: {
        id: string;
        name: string;
    };
    isCheckedIn: boolean;
    checkInTime: string | null;
    checkInMethod: string | null;
}

interface Region {
    id: string;
    name: string;
}

const ManualCheckIn = () => {
    const { id: eventId } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const { user } = useAuth();
    const toast = useToast();

    const [members, setMembers] = useState<Member[]>([]);
    const [regions, setRegions] = useState<Region[]>([]);
    const [loading, setLoading] = useState(true);
    const [eventName, setEventName] = useState('');

    // Filters
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedRegion, setSelectedRegion] = useState('');
    const [selectedGender, setSelectedGender] = useState('');
    const [selectedStatus, setSelectedStatus] = useState('');

    // Check-in state
    const [checkingInMemberId, setCheckingInMemberId] = useState<string | null>(null);

    // Pagination state
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const [totalMembers, setTotalMembers] = useState(0);

    // Stats
    const [checkInStats, setCheckInStats] = useState({ total: 0, checkedIn: 0, notCheckedIn: 0 });

    useEffect(() => {
        // Check if user is a manager
        if (user?.role !== 'FELLOWSHIP_MANAGER') {
            toast.error('Access denied. Only Fellowship Managers can access this page.');
            navigate('/');
            return;
        }
        fetchRegions();
    }, [user, eventId, navigate, toast]);

    useEffect(() => {
        if (user?.role !== 'FELLOWSHIP_MANAGER') return;

        const to = setTimeout(() => {
            fetchMembers(page, searchTerm);
        }, 300);
        return () => clearTimeout(to);
    }, [searchTerm, selectedRegion, selectedGender, selectedStatus, eventId, user, page]);

    const fetchRegions = async () => {
        try {
            const response = await api.get('/regions');
            setRegions(response.data);
        } catch (error) {
            console.error('Failed to fetch regions:', error);
        }
    };

    const fetchMembers = async (currentPage = page, search = searchTerm) => {
        setLoading(true);
        try {
            const params = new URLSearchParams();
            if (search) params.append('search', search);
            if (selectedRegion) params.append('regionId', selectedRegion);
            if (selectedGender) params.append('gender', selectedGender);
            if (selectedStatus) params.append('status', selectedStatus);
            params.append('page', currentPage.toString());
            params.append('limit', '50');

            const response = await api.get(`/attendance/${eventId}/members?${params.toString()}`);
            setMembers(response.data.data || []);
            setTotalPages(response.data.meta?.totalPages || 1);
            setTotalMembers(response.data.meta?.total || 0);
            setEventName(response.data.eventName || 'Event');
            if (response.data.stats) {
                setCheckInStats(response.data.stats);
            }
        } catch (error: any) {
            console.error('Failed to fetch members:', error);
            toast.error(error?.response?.data?.error || 'Failed to load members');
        } finally {
            setLoading(false);
        }
    };

    const handleCheckIn = async (memberId: string, fellowshipNumber: string) => {
        setCheckingInMemberId(memberId);

        try {
            await api.post('/attendance/check-in', {
                fellowshipNumber,
                method: 'MANUAL',
                eventId,
            });

            toast.success('Check-in successful!');

            // Update the member in the list
            setMembers(members.map(m =>
                m.id === memberId
                    ? { ...m, isCheckedIn: true, checkInTime: new Date().toISOString(), checkInMethod: 'MANUAL' }
                    : m
            ));

            setCheckInStats(prev => ({
                ...prev,
                checkedIn: prev.checkedIn + 1,
                notCheckedIn: Math.max(0, prev.notCheckedIn - 1)
            }));
        } catch (error: any) {
            console.error('Check-in failed:', error);
            toast.error(error?.response?.data?.error || 'Check-in failed');
        } finally {
            setCheckingInMemberId(null);
        }
    };

    const stats = checkInStats;

    return (
        <div className="min-h-screen bg-slate-50 p-6 animate-in fade-in duration-300">
            <div className="max-w-7xl mx-auto">
                {/* Header */}
                <div className="flex items-center gap-4 mb-8">
                    <button
                        onClick={() => navigate('/events')}
                        className="p-2.5 rounded-xl bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-all shadow-sm"
                    >
                        <ArrowLeft size={22} />
                    </button>
                    <div className="flex-1">
                        <h1 className="text-3xl font-bold text-slate-900">Manual Check-in</h1>
                        <p className="text-slate-500 mt-1">{eventName}</p>
                    </div>
                </div>

                {/* Stats Cards */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                    <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm transition-shadow hover:shadow-md">
                        <div className="flex items-center gap-3 mb-3">
                            <div className="p-2.5 rounded-xl bg-blue-50 text-blue-600">
                                <Users size={22} />
                            </div>
                            <span className="text-slate-500 font-semibold text-sm uppercase tracking-wider">Total Members</span>
                        </div>
                        <p className="text-4xl font-bold text-slate-900">{stats.total}</p>
                    </div>

                    <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm transition-shadow hover:shadow-md">
                        <div className="flex items-center gap-3 mb-3">
                            <div className="p-2.5 rounded-xl bg-green-50 text-[#48A111]">
                                <CheckCircle size={22} />
                            </div>
                            <span className="text-slate-500 font-semibold text-sm uppercase tracking-wider">Checked In</span>
                        </div>
                        <p className="text-4xl font-bold text-slate-900">{stats.checkedIn}</p>
                    </div>

                    <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm transition-shadow hover:shadow-md">
                        <div className="flex items-center gap-3 mb-3">
                            <div className="p-2.5 rounded-xl bg-orange-50 text-orange-600">
                                <XCircle size={22} />
                            </div>
                            <span className="text-slate-500 font-semibold text-sm uppercase tracking-wider">Not Checked In</span>
                        </div>
                        <p className="text-4xl font-bold text-slate-900">{stats.notCheckedIn}</p>
                    </div>
                </div>

                {/* Filters */}
                <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm mb-6">
                    <div className="flex items-center gap-2 mb-5">
                        <Filter size={20} className="text-[#48A111]" />
                        <h2 className="text-lg font-bold text-slate-900">Filters</h2>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-4 gap-5">
                        {/* Search */}
                        <div className="md:col-span-2">
                            <label className="block text-slate-600 text-sm font-medium mb-2">Search</label>
                            <div className="relative">
                                <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                                <input
                                    type="text"
                                    value={searchTerm}
                                    onChange={(e) => {
                                        setSearchTerm(e.target.value);
                                        setPage(1);
                                    }}
                                    placeholder="Name, fellowship number, or email..."
                                    className="w-full pl-10 pr-4 py-2.5 rounded-xl bg-slate-50 border border-slate-200 text-slate-900 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#48A111]/20 focus:border-[#48A111] transition-all"
                                />
                            </div>
                        </div>

                        {/* Region Filter */}
                        <div>
                            <label className="block text-slate-600 text-sm font-medium mb-2">Region</label>
                            <select
                                value={selectedRegion}
                                onChange={(e) => {
                                    setSelectedRegion(e.target.value);
                                    setPage(1);
                                }}
                                className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-200 text-slate-900 focus:outline-none focus:ring-2 focus:ring-[#48A111]/20 focus:border-[#48A111] transition-all appearance-none cursor-pointer"
                            >
                                <option value="">All Regions</option>
                                {regions.map((region) => (
                                    <option key={region.id} value={region.id}>
                                        {region.name}
                                    </option>
                                ))}
                            </select>
                        </div>

                        {/* Gender Filter */}
                        <div>
                            <label className="block text-slate-600 text-sm font-medium mb-2">Gender</label>
                            <select
                                value={selectedGender}
                                onChange={(e) => {
                                    setSelectedGender(e.target.value);
                                    setPage(1);
                                }}
                                className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-200 text-slate-900 focus:outline-none focus:ring-2 focus:ring-[#48A111]/20 focus:border-[#48A111] transition-all appearance-none cursor-pointer"
                            >
                                <option value="">All Genders</option>
                                <option value="MALE">Male</option>
                                <option value="FEMALE">Female</option>
                            </select>
                        </div>

                        {/* Status Filter - Full width on new row */}
                        <div className="md:col-span-4">
                            <label className="block text-slate-600 text-sm font-medium mb-2">Check-in Status</label>
                            <div className="flex gap-3">
                                <button
                                    onClick={() => {
                                        setSelectedStatus('');
                                        setPage(1);
                                    }}
                                    className={`flex-1 px-4 py-2.5 rounded-xl font-semibold transition-all shadow-sm ${selectedStatus === ''
                                        ? 'bg-slate-800 text-white'
                                        : 'bg-slate-50 text-slate-600 border border-slate-200 hover:bg-slate-100'
                                        }`}
                                >
                                    All
                                </button>
                                <button
                                    onClick={() => {
                                        setSelectedStatus('checked-in');
                                        setPage(1);
                                    }}
                                    className={`flex-1 px-4 py-2.5 rounded-xl font-semibold transition-all shadow-sm ${selectedStatus === 'checked-in'
                                        ? 'bg-[#48A111] text-white'
                                        : 'bg-slate-50 text-slate-600 border border-slate-200 hover:bg-slate-100'
                                        }`}
                                >
                                    Checked In
                                </button>
                                <button
                                    onClick={() => {
                                        setSelectedStatus('not-checked-in');
                                        setPage(1);
                                    }}
                                    className={`flex-1 px-4 py-2.5 rounded-xl font-semibold transition-all shadow-sm ${selectedStatus === 'not-checked-in'
                                        ? 'bg-orange-500 text-white'
                                        : 'bg-slate-50 text-slate-600 border border-slate-200 hover:bg-slate-100'
                                        }`}
                                >
                                    Not Checked In
                                </button>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Members Table */}
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden mb-12">
                    <div className="overflow-x-auto">
                        {loading ? (
                            <div className="flex items-center justify-center py-20">
                                <Loader2 className="animate-spin text-[#48A111]" size={40} />
                            </div>
                        ) : members.length === 0 ? (
                            <div className="text-center py-20 bg-slate-50/50">
                                <Users className="mx-auto mb-4 text-slate-300" size={56} />
                                <p className="text-slate-900 font-semibold text-lg mb-1">No members found</p>
                                <p className="text-slate-500">Try adjusting your filters</p>
                            </div>
                        ) : (
                            <table className="w-full text-left border-collapse">
                                <thead className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider font-semibold border-b border-slate-200">
                                    <tr>
                                        <th className="px-6 py-4">Fellowship #</th>
                                        <th className="px-6 py-4">Name</th>
                                        <th className="px-6 py-4">Region</th>
