                                        <tr key={member.id} className="text-slate-600 hover:bg-slate-50 transition-colors">
                                            <td className="px-6 py-4">
                                                <span className="font-mono font-medium text-[#48A111] bg-[#48A111]/10 px-2.5 py-1 rounded-md text-sm">
                                                    {member.fellowshipNumber}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div>
                                                    <p className="font-bold text-slate-900">{member.fullName}</p>
                                                    <p className="text-sm text-slate-500 mt-0.5">{member.phoneNumber}</p>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-1.5 text-sm">
                                                    <MapPin size={14} className="text-slate-400" />
                                                    {member.region.name}
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <span className={`px-2.5 py-1 rounded-full text-xs font-bold ${member.gender === 'MALE'
                                                    ? 'bg-blue-50 text-blue-600 border border-blue-100'
                                                    : 'bg-pink-50 text-pink-600 border border-pink-100'
                                                    }`}>
                                                    {member.gender}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4">
                                                {member.isCheckedIn ? (
                                                    <div>
                                                        <div className="flex items-center gap-1.5 text-[#48A111] mb-1">
                                                            <CheckCircle size={16} />
                                                            <span className="font-bold text-sm">Checked In</span>
                                                        </div>
                                                        <p className="text-xs text-slate-400 font-medium">
                                                            {new Date(member.checkInTime!).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} ΓÇó {member.checkInMethod}
                                                        </p>
                                                    </div>
                                                ) : (
                                                    <span className="text-orange-500 flex items-center gap-1.5 font-bold text-sm">
                                                        <XCircle size={16} />
                                                        Not Checked In
                                                    </span>
                                                )}
                                            </td>
                                            <td className="px-6 py-4">
                                                {member.isCheckedIn ? (
                                                    <button
                                                        disabled
                                                        className="px-4 py-2 rounded-xl bg-slate-100 text-slate-400 cursor-not-allowed flex items-center gap-2 font-medium shadow-sm border border-slate-200/50"
                                                    >
                                                        <CheckCircle size={16} />
                                                        Done
                                                    </button>
                                                ) : (
                                                    <button
                                                        onClick={() => handleCheckIn(member.id, member.fellowshipNumber)}
                                                        disabled={checkingInMemberId === member.id}
                                                        className="px-4 py-2 rounded-xl bg-[#48A111] text-white hover:bg-[#3d8b0e] transition-all disabled:opacity-50 flex items-center gap-2 font-semibold shadow-sm hover:shadow-md"
                                                    >
                                                        {checkingInMemberId === member.id ? (
                                                            <>
                                                                <Loader2 size={16} className="animate-spin" />
                                                                Checking In...
                                                            </>
                                                        ) : (
                                                            <>
                                                                <User size={16} />
                                                                Check In
                                                            </>
                                                        )}
                                                    </button>
                                                )}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        )}
                    </div>
                </div>

                {/* Pagination Footer */}
                <div className="mt-4 px-6 py-4 bg-white rounded-2xl border border-slate-200 shadow-sm flex flex-col sm:flex-row items-center justify-between gap-4 transition-all">
                    <div className="text-sm text-slate-500">
                        Showing <span className="font-semibold text-slate-700">{totalMembers > 0 ? (page - 1) * 50 + 1 : 0}</span> to <span className="font-semibold text-slate-700">{Math.min(page * 50, totalMembers)}</span> of <span className="font-semibold text-slate-700">{totalMembers}</span> members
                    </div>

                    <div className="flex gap-2">
                        <button
                            onClick={() => setPage(p => Math.max(1, p - 1))}
                            disabled={page === 1}
                            className="px-4 py-2 rounded-xl border border-slate-200 text-sm font-semibold text-slate-600 bg-slate-50 hover:bg-slate-100 disabled:opacity-50 transition-all shadow-sm"
                        >
                            Previous
                        </button>
                        <div className="px-4 py-2 flex items-center justify-center text-sm font-semibold text-slate-700">
                            {page} / {totalPages}
                        </div>
                        <button
                            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                            disabled={page >= totalPages}
                            className="px-4 py-2 rounded-xl border border-slate-200 text-sm font-semibold text-slate-600 bg-slate-50 hover:bg-slate-100 disabled:opacity-50 transition-all shadow-sm"
                        >
                            Next
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ManualCheckIn;

import React, { useState, useEffect, useRef } from 'react';
import api from '../api';
import { useToast } from '../components/ToastProvider';
import {
    Users, Search, Tag as TagIcon, X, Loader2, Check,
    Trash2, UserCheck, Hash, Mail, Phone, MapPin, BookOpen, Pencil,
    Edit2, ChevronDown, ChevronUp, CheckCircle, XCircle, Download, FileText
} from 'lucide-react';
import TagBadge from '../components/TagBadge';
import EmptyState from '../components/EmptyState';
import LoadingSpinner from '../components/LoadingSpinner';
import CustomSelect from '../components/CustomSelect';

interface Member {
    id: string;
    fullName: string;
    email: string;
    fellowshipNumber: string;
    phoneNumber: string;
    gender: string;
    region: { id: string; name: string };
    courseRelation?: { id: string; name: string; durationYears: number };
    residenceId?: string;
    hostelName?: string;
    initialYearOfStudy?: number;
    initialSemester?: number;
    tags: Tag[];
}

interface Tag {
    id: string;
    name: string;
    color: string;
    type: 'SYSTEM' | 'CUSTOM';
    isSystem: boolean;
}

interface EditChange { field: string; oldValue: string; newValue: string; }
interface EditRequest {
    id: string;
    status: 'PENDING' | 'APPROVED' | 'REJECTED';
    changes: EditChange[];
    reason: string;
    createdAt: string;
    member: { id: string; fullName: string; fellowshipNumber: string; email: string; region?: { name: string } | null; };
}

interface RefData { id: string; name: string; }

/* ΓöÇΓöÇ Edit modal ΓöÇΓöÇ */
function EditMemberModal({
    member, regions, colleges, courses, residences, onClose, onSaved,
}: {
    member: Member;
    regions: RefData[]; colleges: RefData[]; courses: RefData[]; residences: RefData[];
    onClose: () => void;
    onSaved: (updated: Partial<Member>) => void;
}) {
    const { showToast } = useToast();
    const [form, setForm] = useState({
        fullName: member.fullName,
        email: member.email,
        phoneNumber: member.phoneNumber,
        gender: member.gender,
        regionId: member.region?.id ?? '',
        courseId: member.courseRelation?.id ?? '',
        initialYearOfStudy: member.initialYearOfStudy?.toString() ?? '',
        initialSemester: member.initialSemester?.toString() ?? '',
        residenceId: member.residenceId ?? '',
        hostelName: member.hostelName ?? '',
    });
    const [saving, setSaving] = useState(false);
    const set = (k: keyof typeof form) => (v: string) => setForm(p => ({ ...p, [k]: v }));

    const handleSave = async () => {
        if (!form.fullName.trim()) { showToast('error', 'Full name is required'); return; }
        if (!form.email.trim()) { showToast('error', 'Email is required'); return; }
        if (!form.regionId) { showToast('error', 'Region is required'); return; }
        try {
            setSaving(true);
            const res = await api.patch(`/members/${member.id}`, {
                fullName: form.fullName.trim(),
                email: form.email.trim(),
                phoneNumber: form.phoneNumber.trim(),
                gender: form.gender,
                regionId: form.regionId,
                courseId: form.courseId || null,
                initialYearOfStudy: form.initialYearOfStudy ? parseInt(form.initialYearOfStudy, 10) : null,
                initialSemester: form.initialSemester ? parseInt(form.initialSemester, 10) : null,
                residenceId: form.residenceId || null,
                hostelName: form.hostelName.trim() || null,
            });
            showToast('success', `${form.fullName} updated`);
            onSaved(res.data.member);
        } catch (err: any) {
            showToast('error', err.response?.data?.message ?? 'Update failed');
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl border border-slate-100 shadow-2xl w-full max-w-lg max-h-[90dvh] overflow-y-auto">
                <div className="flex items-center justify-between px-6 py-5 border-b border-slate-100 sticky top-0 bg-white rounded-t-2xl z-10">
                    <div>
                        <h2 className="font-bold text-slate-900 flex items-center gap-2"><Pencil size={14} className="text-[#48A111]" /> Edit Member</h2>
                        <p className="text-xs text-slate-400 mt-0.5">{member.fellowshipNumber}</p>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-xl hover:bg-slate-100 text-slate-400"><X size={18} /></button>
                </div>

                <div className="p-6 space-y-5">
                    {/* Personal */}
                    <div>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-wide mb-3">Personal</p>
                        <div className="space-y-3">
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Full Name</label>
                                <input className="input" value={form.fullName} onChange={e => set('fullName')(e.target.value)} />
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Email</label>
                                <input className="input" type="email" value={form.email} onChange={e => set('email')(e.target.value)} />
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Phone</label>
                                <input className="input" type="tel" value={form.phoneNumber} onChange={e => set('phoneNumber')(e.target.value)} />
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Gender</label>
                                <CustomSelect value={form.gender} onChange={set('gender')}
                                    options={[{ value: 'MALE', label: 'Male' }, { value: 'FEMALE', label: 'Female' }]} />
                            </div>
                        </div>
                    </div>

                    {/* Academic */}
                    <div>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-wide mb-3">Academic</p>
                        <div className="space-y-3">
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Course</label>
                                <CustomSelect value={form.courseId} onChange={set('courseId')}
                                    options={[{ value: '', label: 'None' }, ...courses.map(c => ({ value: c.id, label: c.name }))]} />
                            </div>
                            <div className="grid grid-cols-2 gap-3">
                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Year of Study</label>
                                    <CustomSelect value={form.initialYearOfStudy} onChange={set('initialYearOfStudy')}
                                        options={[{ value: '', label: 'Not set' }, ...[1,2,3,4,5,6,7].map(y => ({ value: String(y), label: `Year ${y}` }))]} />
                                </div>
                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Semester</label>
                                    <CustomSelect value={form.initialSemester} onChange={set('initialSemester')}
                                        options={[{ value: '', label: 'Not set' }, { value: '1', label: 'Sem 1' }, { value: '2', label: 'Sem 2' }]} />
                                </div>
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Residence</label>
                                <CustomSelect value={form.residenceId} onChange={set('residenceId')}
                                    options={[{ value: '', label: 'None' }, ...residences.map(r => ({ value: r.id, label: r.name }))]} />
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Hostel / Hall</label>
                                <input className="input" value={form.hostelName} onChange={e => set('hostelName')(e.target.value)} placeholder="e.g. Complex Hall" />
                            </div>
                        </div>
                    </div>

                    {/* Assignment */}
                    <div>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-wide mb-3">Assignment</p>
                        <div className="space-y-1.5">
                            <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Region <span className="text-red-400">*</span></label>
                            <CustomSelect value={form.regionId} onChange={set('regionId')}
                                options={[{ value: '', label: 'Select region', disabled: true }, ...regions.map(r => ({ value: r.id, label: r.name }))]} />
                        </div>
                    </div>

                    <div className="flex gap-3 pt-1">
                        <button onClick={onClose} className="flex-1 px-5 py-2.5 rounded-xl border-2 border-slate-200 text-slate-600 font-semibold text-sm hover:bg-slate-50 transition-all">Cancel</button>
                        <button onClick={handleSave} disabled={saving}
                            className="flex-1 px-5 py-2.5 rounded-xl text-white font-semibold text-sm shadow-lg transition-all disabled:opacity-50 flex items-center justify-center gap-2"
                            style={{ backgroundColor: '#48A111' }}>
                            {saving ? <><Loader2 size={14} className="animate-spin" /> SavingΓÇª</> : <><Check size={14} /> Save Changes</>}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}


/* ΓöÇΓöÇ Avatar initials ΓöÇΓöÇ */
const Avatar = ({ name }: { name: string }) => {
    const initials = name.split(' ').map(n => n[0]).slice(0, 2).join('').toUpperCase();
    return (
        <div className="w-9 h-9 rounded-full flex items-center justify-center text-sm font-bold shrink-0"
            style={{ backgroundColor: '#e9f5e1', color: '#48A111' }}>
            {initials}
        </div>
    );
};

const MemberManagement = () => {
    const { showToast } = useToast();
    const [members, setMembers] = useState<Member[]>([]);
    const [allTags, setAllTags] = useState<Tag[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [filterRegion, setFilterRegion] = useState('');
    const [filterTag, setFilterTag] = useState('');
    const [filterFamily, setFilterFamily] = useState('');
    const [filterTeam, setFilterTeam] = useState('');
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const [totalMembers, setTotalMembers] = useState(0);

    const [families, setFamilies] = useState<RefData[]>([]);
    const [teams, setTeams] = useState<RefData[]>([]);
    const [exporting, setExporting] = useState(false);
    const [showExportMenu, setShowExportMenu] = useState(false);
    const exportRef = useRef<HTMLDivElement>(null);

    const [selectedMembers, setSelectedMembers] = useState<Set<string>>(new Set());
    const [showBulkTagModal, setShowBulkTagModal] = useState(false);
    const [bulkAction, setBulkAction] = useState<'assign' | 'remove'>('assign');
    const [selectedTag, setSelectedTag] = useState('');
    const [bulkNotes, setBulkNotes] = useState('');
    const [submitting, setSubmitting] = useState(false);

    // Edit modal
    const [editTarget, setEditTarget] = useState<Member | null>(null);

    // Reference data for edit modal
    const [regions, setRegions] = useState<RefData[]>([]);
    const [colleges, setColleges] = useState<RefData[]>([]);
    const [courses, setCourses] = useState<RefData[]>([]);
    const [residences, setResidences] = useState<RefData[]>([]);

    // Tabs
    const [activeTab, setActiveTab] = useState<'members' | 'editRequests'>('members');

    // Edit requests
    const [editRequests, setEditRequests] = useState<EditRequest[]>([]);
    const [loadingRequests, setLoadingRequests] = useState(false);
    const [expandedReqId, setExpandedReqId] = useState<string | null>(null);
    const [reviewNote, setReviewNote] = useState('');
    const [reviewingId, setReviewingId] = useState<string | null>(null);

    useEffect(() => {
        const handler = (e: MouseEvent) => {
            if (exportRef.current && !exportRef.current.contains(e.target as Node))
                setShowExportMenu(false);
        };
        document.addEventListener('mousedown', handler);
        return () => document.removeEventListener('mousedown', handler);
    }, []);

    useEffect(() => {
        const to = setTimeout(() => {
            fetchData(page, searchQuery, filterRegion, filterTag, filterFamily, filterTeam);
        }, 300);
        return () => clearTimeout(to);
    }, [searchQuery, page, filterRegion, filterTag, filterFamily, filterTeam]);

    useEffect(() => {
        // Load reference data once for the edit modal
        Promise.all([
            api.get('/regions').then(r => setRegions(r.data)),
            api.get('/colleges').then(r => setColleges(r.data)),
            api.get('/courses').then(r => setCourses(r.data)),
            api.get('/residences').then(r => setResidences(r.data)),
            api.get('/families').then(r => setFamilies(r.data)),
            api.get('/ministry-teams').then(r => setTeams(r.data.data || r.data)),
        ]).catch(() => {});
    }, []);

    const fetchEditRequests = async () => {
        try {
            setLoadingRequests(true);
            const res = await api.get('/members/edit-requests?status=PENDING');
            setEditRequests(res.data);
        } catch { /* silent */ }
        finally { setLoadingRequests(false); }
    };

    useEffect(() => {
        if (activeTab === 'editRequests') fetchEditRequests();
    }, [activeTab]);

    const handleReview = async (reqId: string, status: 'APPROVED' | 'REJECTED') => {
        try {
            setReviewingId(reqId);
            await api.patch(`/members/edit-requests/${reqId}`, { status, reviewNote: reviewNote.trim() || undefined });
            showToast('success', `Request ${status.toLowerCase()}`);
            setReviewNote('');
            setExpandedReqId(null);
            setEditRequests(prev => prev.filter(r => r.id !== reqId));
        } catch (err: any) {
            showToast('error', err.response?.data?.message ?? 'Action failed');
        } finally {
            setReviewingId(null);
        }
    };

    const fetchData = async (currentPage = page, search = searchQuery, region = filterRegion, tag = filterTag, fam = filterFamily, team = filterTeam) => {
        try {
            setLoading(true);
            const params: any = { page: currentPage, limit: 50 };
            if (search) params.search = search;
            if (region) params.regionId = region;
            if (tag) params.tags = tag;
            if (fam) params.familyId = fam;
            if (team) params.teamId = team;
            
            const [membersRes, tagsRes] = await Promise.all([
                api.get('/members', { params }),
                api.get('/tags'),
            ]);
            setMembers(membersRes.data.data || []);
            setTotalPages(membersRes.data.meta?.totalPages || 1);
            setTotalMembers(membersRes.data.meta?.total || 0);
            setAllTags(tagsRes.data);
        } catch {
            showToast('error', 'Failed to load data');
        } finally {
            setLoading(false);
        }
    };

    const handleExport = async () => {
        try {
            setExporting(true);
            const params: any = {};
            if (searchQuery) params.search = searchQuery;
            if (filterRegion) params.regionId = filterRegion;
            if (filterTag) params.tags = filterTag;
            if (filterFamily) params.familyId = filterFamily;
            if (filterTeam) params.teamId = filterTeam;

            const res = await api.get('/members/export', {
                params,
                responseType: 'blob'
            });
            const url = window.URL.createObjectURL(new Blob([res.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', 'members_export.xlsx');
            document.body.appendChild(link);
            link.click();
            link.remove();
            showToast('success', 'Export successful');
        } catch (error) {
            showToast('error', 'Export failed');
        } finally {
            setExporting(false);
        }
    };

    const handleSelectAll = () => {
        if (selectedMembers.size === members.length && members.length > 0) {
            setSelectedMembers(new Set());
        } else {
            setSelectedMembers(new Set(members.map(m => m.id)));
        }
    };

    const handleSelectMember = (id: string) => {
        const next = new Set(selectedMembers);
        next.has(id) ? next.delete(id) : next.add(id);
        setSelectedMembers(next);
    };

    const openBulkTagModal = (action: 'assign' | 'remove') => {
        if (selectedMembers.size === 0) { showToast('error', 'Select at least one member'); return; }
        setBulkAction(action);
        setSelectedTag('');
        setBulkNotes('');
        setShowBulkTagModal(true);
    };

    const handleBulkTagOperation = async () => {
        if (!selectedTag) { showToast('error', 'Please select a tag'); return; }
        try {
            setSubmitting(true);
            const endpoint = bulkAction === 'assign'
                ? '/tags/members/tags/bulk-assign'
                : '/tags/members/tags/bulk-remove';
            await api.post(endpoint, {
                memberIds: Array.from(selectedMembers),
                tagId: selectedTag,
                notes: bulkNotes || undefined,
            });
            showToast('success', `Tag ${bulkAction === 'assign' ? 'assigned to' : 'removed from'} ${selectedMembers.size} member(s)`);
            setShowBulkTagModal(false);
            setSelectedMembers(new Set());
            fetchData();
        } catch (error: any) {
            showToast('error', error.response?.data?.error || 'Operation failed');
        } finally {
            setSubmitting(false);
        }
    };

    const handleDelete = async (memberId: string, memberName: string) => {
        if (!window.confirm(`Delete ${memberName}? Their history will be preserved.`)) return;
        try {
            await api.delete(`/members/${memberId}`);
            showToast('success', 'Member deleted');
            fetchData();
            if (selectedMembers.has(memberId)) {
                const next = new Set(selectedMembers);
                next.delete(memberId);
                setSelectedMembers(next);
            }
        } catch {
            showToast('error', 'Failed to delete member');
        }
    };

    const handleBulkDelete = async () => {
        if (selectedMembers.size === 0) return;
        if (!window.confirm(`Delete ${selectedMembers.size} members? Their history will be preserved.`)) return;
        try {
            await api.post('/members/bulk-delete', { memberIds: Array.from(selectedMembers) });
            showToast('success', `${selectedMembers.size} members deleted`);
            setSelectedMembers(new Set());
            fetchData();
        } catch {
            showToast('error', 'Failed to delete members');
        }
    };

    const customTags = allTags.filter(t => !t.isSystem);
    const allSelected = selectedMembers.size === members.length && members.length > 0;

    // Use a skeleton/spinner just for the table when paginating instead of full page block
    // if (loading && members.length === 0) return <LoadingSpinner message="Loading members..." />;

    return (
        <div className="max-w-7xl mx-auto animate-fade-in relative">
            {loading && members.length > 0 && (
                <div className="absolute inset-0 bg-white/50 backdrop-blur-[1px] z-10 flex items-center justify-center rounded-2xl">
                    <Loader2 className="animate-spin text-[#48A111] w-8 h-8" />
                </div>
            )}

            {/* Page header */}
            <div className="flex items-center justify-between mb-6">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Member Management</h1>
                    <p className="text-slate-500 mt-1 text-sm">Manage member details, tags, and review edit requests</p>
                </div>
                <div className="flex flex-col sm:flex-row items-end sm:items-center gap-3">
                    <div className="flex items-center gap-2 bg-white border border-slate-200 rounded-2xl px-5 py-3 shadow-sm">
                        <Users size={18} className="text-[#48A111]" />
                        <span className="font-bold text-slate-900 text-lg">{totalMembers}</span>
                        <span className="text-slate-500 text-sm">total match{totalMembers === 1 ? '' : 'es'}</span>
                    </div>
                    {activeTab === 'members' && totalMembers > 0 && (
                        <div className="relative" ref={exportRef}>
                            <button
                                onClick={() => setShowExportMenu(v => !v)}
                                disabled={exporting}
                                className="flex items-center gap-2 px-3 py-2 rounded-lg border border-slate-300 bg-white text-slate-700 hover:bg-slate-50 transition-colors text-sm font-medium cursor-pointer shadow-sm disabled:opacity-50"
                            >
                                {exporting ? <Loader2 size={15} className="animate-spin" /> : <Download size={15} />}
                                Export
                                <ChevronDown size={13} className={`transition-transform ${showExportMenu ? 'rotate-180' : ''}`} />
                            </button>
                            {showExportMenu && (
                                <div className="absolute right-0 mt-1 w-44 bg-white border border-slate-200 rounded-xl shadow-lg z-20 py-1">
                                    <button 
                                        onClick={() => { handleExport(); setShowExportMenu(false); }}
                                        className="w-full flex items-center gap-2 px-4 py-2.5 text-sm text-slate-700 hover:bg-slate-50 transition-colors cursor-pointer text-left"
                                    >
                                        <FileText size={14} className="text-slate-400" /> Export as Excel
                                    </button>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {/* Tab bar */}
            <div className="flex gap-1 bg-slate-100 p-1 rounded-xl mb-6 w-fit">
                <button
                    onClick={() => setActiveTab('members')}
                    className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all ${
                        activeTab === 'members'
                            ? 'bg-white text-slate-900 shadow-sm'
                            : 'text-slate-500 hover:text-slate-700'
                    }`}
                >
                    <span className="flex items-center gap-2"><Users size={14} /> Members</span>
                </button>
                <button
                    onClick={() => setActiveTab('editRequests')}
                    className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all ${
                        activeTab === 'editRequests'
                            ? 'bg-white text-slate-900 shadow-sm'
                            : 'text-slate-500 hover:text-slate-700'
                    }`}
                >
                    <span className="flex items-center gap-2">
                        <Edit2 size={14} /> Edit Requests
                        {editRequests.length > 0 && (
                            <span className="ml-1 px-2 py-0.5 rounded-full bg-amber-100 text-amber-700 text-xs font-bold">{editRequests.length}</span>
                        )}
                    </span>
                </button>
            </div>
            {/* ΓöÇΓöÇ Members Tab ΓöÇΓöÇ */}
            {activeTab === 'members' && (<>
            <div className="flex flex-col lg:flex-row gap-3 mb-6 items-start lg:items-center">
                {/* Search */}
                <div className="relative flex-1 w-full lg:w-auto">
                    <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                    <input
                        type="text"
                        placeholder="Search by name, email or numberΓÇª"
                        value={searchQuery}
                        onChange={e => {
                            setSearchQuery(e.target.value);
                            setPage(1);
                        }}
                        className="w-full pl-10 pr-4 py-2.5 rounded-xl bg-white border-2 border-slate-200 text-slate-900 text-sm placeholder-slate-400 focus:outline-none transition-all"
                        onFocus={e => { e.currentTarget.style.borderColor = '#48A111'; e.currentTarget.style.boxShadow = '0 0 0 3px rgba(72,161,17,0.12)'; }}
                        onBlur={e => { e.currentTarget.style.borderColor = '#e2e8f0'; e.currentTarget.style.boxShadow = 'none'; }}
                    />
                </div>

                {/* Filters */}
                {selectedMembers.size === 0 && (
                    <div className="flex flex-wrap gap-2 w-full lg:w-auto">
                        <div className="w-[48%] lg:w-40">
                            <CustomSelect value={filterRegion} onChange={(v) => { setFilterRegion(v); setPage(1); }}
                                options={[{ value: '', label: 'All Regions' }, ...regions.map(r => ({ value: r.id, label: r.name }))]} />
                        </div>
                        <div className="w-[48%] lg:w-40">
                            <CustomSelect value={filterTag} onChange={(v) => { setFilterTag(v); setPage(1); }}
                                options={[{ value: '', label: 'All Tags' }, ...allTags.map(t => ({ value: t.id, label: t.name.replace(/_/g, ' ') }))]} />
                        </div>
                        <div className="w-[48%] lg:w-40">
                            <CustomSelect value={filterFamily} onChange={(v) => { setFilterFamily(v); setPage(1); }}
                                options={[{ value: '', label: 'All Families' }, ...families.map(f => ({ value: f.id, label: f.name }))]} />
                        </div>
                        <div className="w-[48%] lg:w-40">
                            <CustomSelect value={filterTeam} onChange={(v) => { setFilterTeam(v); setPage(1); }}
                                options={[{ value: '', label: 'All Teams' }, ...teams.map(t => ({ value: t.id, label: t.name }))]} />
                        </div>
                    </div>
                )}

                {/* Bulk action buttons (contextual) */}
                {selectedMembers.size > 0 && (
                    <div className="flex items-center gap-2 bg-[#e9f5e1] border border-[#48A111]/20 rounded-xl px-4 py-2">
                        <span className="text-sm font-semibold text-[#48A111] mr-1">
                            {selectedMembers.size} selected
                        </span>
                        <button
                            onClick={() => openBulkTagModal('assign')}
                            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-white border border-slate-200 text-slate-700 text-xs font-semibold hover:bg-slate-50 transition-all"
                        >
                            <TagIcon size={13} /> Assign Tag
                        </button>
                        <button
                            onClick={() => openBulkTagModal('remove')}
                            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-white border border-slate-200 text-slate-700 text-xs font-semibold hover:bg-slate-50 transition-all"
                        >
                            <X size={13} /> Remove Tag
                        </button>
                        <button
                            onClick={handleBulkDelete}
                            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-red-50 border border-red-100 text-red-500 text-xs font-semibold hover:bg-red-100 transition-all"
                        >
                            <Trash2 size={13} /> Delete
                        </button>
                        <button
                            onClick={() => setSelectedMembers(new Set())}
                            className="p-1.5 rounded-lg text-slate-400 hover:text-slate-600 hover:bg-white transition-all"
                            title="Clear selection"
                        >
                            <X size={14} />
                        </button>
                    </div>
                )}
            </div>

            {/* Table */}
            {members.length === 0 && !loading ? (
                <EmptyState
                    icon={Users}
                    title={searchQuery ? 'No members match' : 'No members yet'}
                    description={searchQuery ? 'Try a different search term' : 'Register members to get started'}
                />
            ) : members.length === 0 && loading ? (
                <LoadingSpinner message="Loading members..." />
            ) : (
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead>
                                <tr className="bg-slate-50 border-b border-slate-100">
                                    <th className="py-3.5 px-4 w-10">
                                        {/* Custom checkbox ΓÇö select all */}
                                        <button
                                            onClick={handleSelectAll}
                                            className={`w-5 h-5 rounded-md border-2 flex items-center justify-center transition-all ${allSelected
                                                ? 'border-[#48A111] bg-[#48A111]'
                                                : 'border-slate-300 bg-white hover:border-[#48A111]'
                                                }`}
                                        >
                                            {allSelected && <Check size={12} className="text-white" strokeWidth={3} />}
                                        </button>
                                    </th>
                                    <th className="text-left py-3.5 px-4 text-xs font-semibold text-slate-500 uppercase tracking-wide">Member</th>
                                    <th className="text-left py-3.5 px-4 text-xs font-semibold text-slate-500 uppercase tracking-wide">Contact</th>
                                    <th className="text-left py-3.5 px-4 text-xs font-semibold text-slate-500 uppercase tracking-wide">Region</th>
                                    <th className="text-left py-3.5 px-4 text-xs font-semibold text-slate-500 uppercase tracking-wide">Academic</th>
                                    <th className="text-left py-3.5 px-4 text-xs font-semibold text-slate-500 uppercase tracking-wide">Tags</th>
                                    <th className="py-3.5 px-4 w-12" />
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {members.map((member: any) => {
                                    const isSelected = selectedMembers.has(member.id);
                                    return (
                                        <tr
                                            key={member.id}
                                            className={`transition-colors ${isSelected ? 'bg-[#e9f5e1]/40' : 'hover:bg-slate-50'}`}
                                        >
                                            {/* Checkbox */}
                                            <td className="py-3 px-4">
                                                <button
                                                    onClick={() => handleSelectMember(member.id)}
                                                    className={`w-5 h-5 rounded-md border-2 flex items-center justify-center transition-all ${isSelected
                                                        ? 'border-[#48A111] bg-[#48A111]'
                                                        : 'border-slate-300 bg-white hover:border-[#48A111]'
                                                        }`}
                                                >
                                                    {isSelected && <Check size={12} className="text-white" strokeWidth={3} />}
                                                </button>
                                            </td>

                                            {/* Member */}
                                            <td className="py-3 px-4">
                                                <div className="flex items-center gap-3">
                                                    <Avatar name={member.fullName} />
                                                    <div>
                                                        <p className="font-semibold text-slate-900 text-sm">{member.fullName}</p>
                                                        <p className="text-xs text-slate-400 flex items-center gap-1 mt-0.5">
                                                            <Hash size={10} />{member.fellowshipNumber}
                                                        </p>
                                                    </div>
                                                </div>
                                            </td>

                                            {/* Contact */}
                                            <td className="py-3 px-4">
                                                <div className="space-y-0.5">
                                                    <p className="text-xs text-slate-700 flex items-center gap-1.5">
                                                        <Mail size={11} className="text-slate-400 shrink-0" />
                                                        <span className="truncate max-w-[160px]">{member.email}</span>
                                                    </p>
                                                    {member.phoneNumber && (
                                                        <p className="text-xs text-slate-500 flex items-center gap-1.5">
                                                            <Phone size={11} className="text-slate-400 shrink-0" />{member.phoneNumber}
                                                        </p>
                                                    )}
                                                </div>
                                            </td>

                                            {/* Region */}
                                            <td className="py-3 px-4">
                                                <span className="inline-flex items-center gap-1.5 text-xs font-medium text-slate-600 bg-slate-100 px-2.5 py-1 rounded-full">
                                                    <MapPin size={10} className="text-slate-400" />
                                                    {member.region.name}
                                                </span>
                                            </td>

                                            {/* Academic */}
                                            <td className="py-3 px-4">
                                                {member.initialYearOfStudy && member.initialSemester ? (
                                                    <div>
                                                        <span className="text-xs font-semibold text-blue-600">
                                                            Yr {member.initialYearOfStudy}, Sem {member.initialSemester}
                                                        </span>
                                                        {member.courseRelation && (
                                                            <p className="text-[10px] text-slate-400 flex items-center gap-1 mt-0.5">
                                                                <BookOpen size={9} />{member.courseRelation.name}
                                                            </p>
                                                        )}
                                                    </div>
                                                ) : (
                                                    <span className="text-xs text-slate-400">ΓÇö</span>
                                                )}
                                            </td>

                                            {/* Tags */}
                                            <td className="py-3 px-4">
                                                {member.tags && member.tags.length > 0 ? (
                                                    <div className="flex flex-wrap gap-1">
                                                        {member.tags.map((tag: Tag) => (
                                                            <TagBadge key={tag.id} tag={tag} size="sm" showIcon={false} />
                                                        ))}
                                                    </div>
                                                ) : (
                                                    <span className="text-xs text-slate-400 italic">No tags</span>
                                                )}
                                            </td>

                                            {/* Edit */}
                                            <td className="py-3 px-4">
                                                <div className="flex items-center gap-1">
                                                    <button
                                                        onClick={() => setEditTarget(member)}
                                                        className="p-1.5 rounded-lg text-slate-400 hover:bg-[#e9f5e1] hover:text-[#48A111] transition-all"
                                                        title="Edit member"
                                                    >
                                                        <Pencil size={15} />
                                                    </button>
                                                    <button
                                                        onClick={() => handleDelete(member.id, member.fullName)}
                                                        className="p-1.5 rounded-lg text-slate-400 hover:bg-red-50 hover:text-red-500 transition-all"
                                                        title="Delete member"
                                                    >
                                                        <Trash2 size={15} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>

                    {/* Pagination Footer */}
                    <div className="px-6 py-4 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row items-center justify-between gap-4">
                        <div className="text-sm text-slate-500">
                            Showing <span className="font-semibold text-slate-700">{totalMembers > 0 ? (page - 1) * 50 + 1 : 0}</span> to <span className="font-semibold text-slate-700">{Math.min(page * 50, totalMembers)}</span> of <span className="font-semibold text-slate-700">{totalMembers}</span> members
                            {selectedMembers.size > 0 && (
                                <span className="ml-2 text-[#48A111] font-semibold">┬╖ {selectedMembers.size} selected</span>
                            )}
                        </div>

                        <div className="flex gap-2">
                            <button
                                onClick={() => { setPage(p => Math.max(1, p - 1)); }}
                                disabled={page === 1}
                                className="px-4 py-2 rounded-xl border border-slate-200 text-sm font-semibold text-slate-600 bg-white hover:bg-slate-50 disabled:opacity-50 transition-all shadow-sm"
                            >
                                Previous
                            </button>
                            <div className="px-4 py-2 flex items-center justify-center text-sm font-semibold text-slate-700">
                                {page} / {totalPages}
                            </div>
                            <button
                                onClick={() => { setPage(p => Math.min(totalPages, p + 1)); }}
                                disabled={page >= totalPages}
                                className="px-4 py-2 rounded-xl border border-slate-200 text-sm font-semibold text-slate-600 bg-white hover:bg-slate-50 disabled:opacity-50 transition-all shadow-sm"
                            >
                                Next
                            </button>
                        </div>
                    </div>
                </div>
            )}
            </>)}

            {/* ΓöÇΓöÇ Edit Requests Tab ΓöÇΓöÇ */}
            {activeTab === 'editRequests' && (
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                    <div className="flex items-center justify-between mb-6">
                        <h2 className="text-xl font-bold text-slate-900 flex items-center gap-3">
                            <div className="p-2 rounded-xl bg-amber-50"><Edit2 className="text-amber-500" size={20} /></div>
                            Profile Edit Requests
                            {editRequests.length > 0 && (
                                <span className="text-sm px-2.5 py-1 rounded-full bg-amber-50 text-amber-600 border border-amber-200 font-semibold">
                                    {editRequests.length} pending
                                </span>
                            )}
                        </h2>
                        <button onClick={fetchEditRequests} className="text-xs text-slate-400 hover:text-slate-600 flex items-center gap-1 transition-colors">
                            <Loader2 size={12} className={loadingRequests ? 'animate-spin' : ''} /> Refresh
                        </button>
                    </div>

                    {loadingRequests ? (
                        <div className="text-center py-10 text-slate-400"><Loader2 className="animate-spin mx-auto" size={28} /></div>
                    ) : editRequests.length === 0 ? (
                        <div className="text-center py-14 bg-slate-50 border border-slate-200 rounded-2xl">
                            <CheckCircle className="mx-auto mb-3" style={{ color: '#48A111' }} size={40} />
                            <p className="text-slate-500 font-medium">No pending edit requests</p>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {editRequests.map(req => (
                                <div key={req.id} className="border border-slate-200 rounded-xl overflow-hidden shadow-sm">
                                    {/* Header row */}
                                    <button
                                        className="w-full flex items-center justify-between p-4 text-left hover:bg-slate-50 transition-colors"
                                        onClick={() => setExpandedReqId(expandedReqId === req.id ? null : req.id)}
                                    >
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 rounded-full bg-amber-50 flex items-center justify-center text-amber-600 font-bold text-sm border border-amber-100">
                                                {req.member.fullName.charAt(0)}
                                            </div>
                                            <div>
                                                <p className="text-slate-900 font-bold">{req.member.fullName}</p>
                                                <p className="text-xs text-slate-500 font-mono mt-0.5">{req.member.fellowshipNumber}</p>
                                                {req.member.region && (
                                                    <p className="text-xs text-slate-400 flex items-center gap-1 mt-0.5"><MapPin size={9} /> {req.member.region.name}</p>
                                                )}
                                            </div>
                                            <div className="flex flex-wrap gap-1.5 ml-2">
                                                {req.changes.map((c, i) => (
                                                    <span key={i} className="text-xs px-2.5 py-1 bg-slate-100 text-slate-600 border border-slate-200 rounded-full font-medium capitalize">
                                                        {c.field.replace(/([A-Z])/g, ' $1')}
                                                    </span>
                                                ))}
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-3 text-slate-400 shrink-0">
                                            <span className="text-xs">{new Date(req.createdAt).toLocaleDateString()}</span>
                                            {expandedReqId === req.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                                        </div>
                                    </button>

                                    {/* Expanded body */}
                                    {expandedReqId === req.id && (
                                        <div className="px-5 pb-5 pt-4 border-t border-slate-100 bg-slate-50 space-y-4">
                                            {/* Changes diff */}
                                            <div className="space-y-2">
                                                <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Changes Requested</p>
                                                {req.changes.map((c, i) => (
                                                    <div key={i} className="flex items-center gap-3 p-3 bg-white border border-slate-200 rounded-xl text-sm shadow-sm">
                                                        <span className="font-semibold text-slate-700 capitalize w-32 shrink-0">{c.field.replace(/([A-Z])/g, ' $1')}</span>
                                                        <span className="text-slate-400 line-through truncate max-w-[150px]">{c.oldValue || 'ΓÇö'}</span>
                                                        <span className="font-bold shrink-0" style={{ color: '#48A111' }}>ΓåÆ {c.newValue}</span>
                                                    </div>
                                                ))}
                                            </div>

                                            {/* Reason */}
                                            <div className="p-4 bg-amber-50 border border-amber-100 rounded-xl">
                                                <p className="text-xs font-bold text-amber-600 mb-1.5 uppercase tracking-wider">Member's Reason</p>
                                                <p className="text-sm text-amber-900 leading-relaxed font-medium">{req.reason}</p>
                                            </div>

                                            {/* Review note */}
                                            <div>
                                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 block">Review Note (optional)</label>
                                                <textarea
                                                    value={reviewNote}
                                                    onChange={e => setReviewNote(e.target.value)}
                                                    placeholder="Leave a note for the memberΓÇª"
                                                    rows={2}
                                                    maxLength={500}
                                                    className="input resize-none"
                                                />
                                            </div>

                                            {/* Actions */}
                                            <div className="flex gap-3">
                                                <button
                                                    onClick={() => handleReview(req.id, 'APPROVED')}
                                                    disabled={reviewingId === req.id}
                                                    className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-white text-sm font-bold shadow-md transition-all disabled:opacity-60"
                                                    style={{ backgroundColor: '#48A111' }}
                                                >
                                                    <CheckCircle size={16} />
                                                    {reviewingId === req.id ? 'ProcessingΓÇª' : 'Approve'}
                                                </button>
                                                <button
                                                    onClick={() => handleReview(req.id, 'REJECTED')}
                                                    disabled={reviewingId === req.id}
                                                    className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl bg-white border-2 border-slate-200 hover:border-red-200 hover:bg-red-50 text-slate-700 hover:text-red-600 text-sm font-bold transition-all disabled:opacity-60"
                                                >
                                                    <XCircle size={16} /> Reject
                                                </button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}

            {editTarget && (
                <EditMemberModal
                    member={editTarget}
                    regions={regions} colleges={colleges} courses={courses} residences={residences}
                    onClose={() => setEditTarget(null)}
                    onSaved={(updated) => {
                        setMembers(ms => ms.map(m => m.id === editTarget.id ? { ...m, ...updated } : m));
                        setEditTarget(null);
                    }}
                />
            )}

            {/* ΓöÇΓöÇ Bulk Tag Modal ΓöÇΓöÇ */}
            {showBulkTagModal && (
                <div className="fixed inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                    <div className="bg-white rounded-2xl border border-slate-100 shadow-2xl w-full max-w-md">
                        {/* Modal header */}
                        <div className="flex items-center justify-between px-6 py-5 border-b border-slate-100">
                            <div className="flex items-center gap-3">
                                <div className={`p-2.5 rounded-xl ${bulkAction === 'assign' ? 'bg-[#e9f5e1]' : 'bg-red-50'}`}>
                                    {bulkAction === 'assign'
                                        ? <UserCheck size={18} className="text-[#48A111]" />
                                        : <X size={18} className="text-red-500" />
                                    }
                                </div>
                                <div>
                                    <h2 className="text-base font-bold text-slate-900">
                                        {bulkAction === 'assign' ? 'Assign Tag' : 'Remove Tag'}
                                    </h2>
                                    <p className="text-xs text-slate-500 mt-0.5">
                                        {selectedMembers.size} member{selectedMembers.size !== 1 ? 's' : ''} selected
                                    </p>
                                </div>
                            </div>
                            <button
                                onClick={() => setShowBulkTagModal(false)}
                                className="p-2 rounded-xl hover:bg-slate-100 text-slate-400 hover:text-slate-600 transition-all"
                            >
                                <X size={17} />
                            </button>
                        </div>

                        <div className="p-6 space-y-4">
                            {/* Tag select */}
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wide mb-2">
                                    Select Tag <span className="text-red-400 normal-case">*</span>
                                </label>
                                <select
                                    value={selectedTag}
                                    onChange={e => setSelectedTag(e.target.value)}
                                    className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border-2 border-slate-200 text-slate-900 text-sm focus:outline-none transition-all"
                                    onFocus={e => { e.currentTarget.style.borderColor = '#48A111'; e.currentTarget.style.boxShadow = '0 0 0 3px rgba(72,161,17,0.12)'; }}
                                    onBlur={e => { e.currentTarget.style.borderColor = '#e2e8f0'; e.currentTarget.style.boxShadow = 'none'; }}
                                    required
                                >
                                    <option value="">Choose a tagΓÇª</option>
                                    {customTags.map(tag => (
                                        <option key={tag.id} value={tag.id}>{tag.name}</option>
                                    ))}
                                </select>
                            </div>

                            {/* Notes */}
                            <div>
                                <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wide mb-2">
                                    Notes <span className="font-normal normal-case text-slate-400">(optional)</span>
                                </label>
                                <textarea
                                    value={bulkNotes}
                                    onChange={e => setBulkNotes(e.target.value)}
                                    placeholder={`Reason for ${bulkAction === 'assign' ? 'assigning' : 'removing'} this tagΓÇª`}
                                    className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border-2 border-slate-200 text-slate-900 text-sm placeholder-slate-400 focus:outline-none transition-all resize-none"
                                    onFocus={e => { e.currentTarget.style.borderColor = '#48A111'; e.currentTarget.style.boxShadow = '0 0 0 3px rgba(72,161,17,0.12)'; }}
                                    onBlur={e => { e.currentTarget.style.borderColor = '#e2e8f0'; e.currentTarget.style.boxShadow = 'none'; }}
                                    rows={3}
                                    maxLength={500}
                                />
                            </div>

                            {/* Actions */}
                            <div className="flex gap-3 pt-1">
                                <button
                                    type="button"
                                    onClick={() => setShowBulkTagModal(false)}
                                    className="flex-1 px-5 py-2.5 rounded-xl border-2 border-slate-200 text-slate-600 font-semibold text-sm hover:bg-slate-50 transition-all"
                                >
                                    Cancel
                                </button>
                                <button
                                    onClick={handleBulkTagOperation}
                                    disabled={submitting || !selectedTag}
                                    className="flex-1 px-5 py-2.5 rounded-xl text-white font-semibold text-sm shadow-lg transition-all hover:scale-[1.02] active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                                    style={{ backgroundColor: bulkAction === 'assign' ? '#48A111' : '#ef4444' }}
                                    onMouseEnter={e => { if (!e.currentTarget.disabled && bulkAction === 'assign') e.currentTarget.style.backgroundColor = '#F2B50B'; }}
                                    onMouseLeave={e => { if (!e.currentTarget.disabled) e.currentTarget.style.backgroundColor = bulkAction === 'assign' ? '#48A111' : '#ef4444'; }}
                                >
                                    {submitting ? (
                                        <><Loader2 size={15} className="animate-spin" /> ProcessingΓÇª</>
                                    ) : (
                                        <><Check size={15} /> {bulkAction === 'assign' ? 'Assign Tag' : 'Remove Tag'}</>
                                    )}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MemberManagement;

import React, { useState, useEffect, useCallback } from 'react';
import api from '../api';
import { useToast } from '../components/ToastProvider';
import {
    CheckCircle, XCircle, ChevronDown, ChevronUp, Loader2,
    MapPin, AlertTriangle,
    ThumbsUp, ThumbsDown, Building, BookOpen,
    Copy, Sparkles, Edit3, User, Phone, Mail
} from 'lucide-react';
import LoadingSpinner from '../components/LoadingSpinner';
import CustomSelect from '../components/CustomSelect';

interface Region { id: string; name: string; }
interface College { id: string; name: string; }
interface Course { id: string; name: string; }
interface Residence { id: string; name: string; type: string; }

interface PendingMember {
    id: string;
    fullName: string;
    email: string;
    phoneNumber: string;
    gender: string;
    registrationMode: string;
    isMakerereStudent: boolean;
    regionId?: string;
    region?: Region;
    collegeId?: string;
    collegeSuggestion?: string;
    courseId?: string;
    courseSuggestion?: string;
    initialYearOfStudy?: number;
    initialSemester?: number;
    residenceId?: string;
    residenceSuggestion?: string;
    hostelName?: string;
    familyId?: string;
    status: 'PENDING' | 'APPROVED' | 'REJECTED';
    submittedAt: string;
    token: { label?: string; token: string };
}

interface CreatedCredentials {
    fullName: string;
    fellowshipNumber: string;
    defaultPassword?: string;
}

// ΓöÇΓöÇ Field badge (resolved vs. suggestion vs. missing) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function FieldBadge({ resolved, suggestion, label }: { resolved?: string | null; suggestion?: string | null; label: string }) {
    if (resolved) return <span className="inline-flex items-center gap-1 text-xs text-[#48A111] bg-[#e9f5e1] px-2 py-0.5 rounded-full"><CheckCircle size={10} />{label}: {resolved}</span>;
    if (suggestion) return <span className="inline-flex items-center gap-1 text-xs text-amber-600 bg-amber-50 px-2 py-0.5 rounded-full"><AlertTriangle size={10} />{label}: "{suggestion}" (unresolved)</span>;
    return <span className="inline-flex items-center gap-1 text-xs text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">{label}: not provided</span>;
}

// ΓöÇΓöÇ Inline input helper ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function EditField({ label, icon, value, onChange, type = 'text', readOnly = false }: {
    label: string; icon: React.ReactNode; value: string;
    onChange: (v: string) => void; type?: string; readOnly?: boolean;
}) {
    return (
        <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wide flex items-center gap-1.5">
                {icon} {label}
            </label>
            <input
                type={type}
                value={value}
                onChange={e => onChange(e.target.value)}
                readOnly={readOnly}
                className={`w-full px-3 py-2 rounded-xl border-2 text-sm text-slate-800 transition-all outline-none
                    ${readOnly
                        ? 'bg-slate-50 border-slate-100 text-slate-400 cursor-not-allowed'
                        : 'bg-white border-slate-200 focus:border-[#48A111] focus:ring-2 focus:ring-[#48A111]/10'}`}
            />
        </div>
    );
}

// ΓöÇΓöÇ Approval modal ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ApproveModal({
    pending, regions, colleges, courses, residences,
    onApprove, onClose,
}: {
    pending: PendingMember;
    regions: Region[]; colleges: College[]; courses: Course[]; residences: Residence[];
    onApprove: () => void; onClose: () => void;
}) {
    const { showToast } = useToast();
    const [edits, setEdits] = useState({
        // Personal
        fullName: pending.fullName,
        email: pending.email,
        phoneNumber: pending.phoneNumber,
        gender: pending.gender,
        // Academic
        collegeId: pending.collegeId ?? '',
        courseId: pending.courseId ?? '',
        initialYearOfStudy: pending.initialYearOfStudy?.toString() ?? '',
        initialSemester: pending.initialSemester?.toString() ?? '',
        residenceId: pending.residenceId ?? '',
        hostelName: pending.hostelName ?? '',
        // Assignment
        regionId: pending.regionId ?? '',
        familyId: pending.familyId ?? '',
    });
    const set = (k: keyof typeof edits) => (v: string) => setEdits(p => ({ ...p, [k]: v }));
    const [saving, setSaving] = useState(false);
    const [createdCredentials, setCreatedCredentials] = useState<{ fullName: string; fellowshipNumber: string; defaultPassword?: string; email?: string } | null>(null);

    const handleApprove = async () => {
        if (!edits.regionId) { showToast('error', 'Region must be assigned before approving'); return; }
        if (!edits.fullName.trim()) { showToast('error', 'Full name is required'); return; }
        if (!edits.email.trim()) { showToast('error', 'Email is required'); return; }
        try {
            setSaving(true);
            await api.patch(`/pending-members/${pending.id}`, {
                fullName: edits.fullName.trim(),
                email: edits.email.trim(),
                phoneNumber: edits.phoneNumber.trim(),
                gender: edits.gender,
                regionId: edits.regionId || null,
                collegeId: edits.collegeId || null,
                courseId: edits.courseId || null,
                initialYearOfStudy: edits.initialYearOfStudy ? parseInt(edits.initialYearOfStudy, 10) : null,
                initialSemester: edits.initialSemester ? parseInt(edits.initialSemester, 10) : null,
                residenceId: edits.residenceId || null,
                hostelName: edits.hostelName.trim() || null,
                familyId: edits.familyId || null,
            });
            // Detect if FM changed any personal field so the email can include a notice
            const editedByFM =
                edits.fullName.trim() !== pending.fullName ||
                edits.email.trim() !== pending.email ||
                edits.phoneNumber.trim() !== pending.phoneNumber ||
                edits.gender !== pending.gender ||
                (edits.initialYearOfStudy || '') !== (pending.initialYearOfStudy?.toString() ?? '') ||
                (edits.initialSemester || '') !== (pending.initialSemester?.toString() ?? '') ||
                (edits.hostelName.trim() || '') !== (pending.hostelName ?? '');
            const res = await api.post(`/pending-members/${pending.id}/approve`, { editedByFM });
            showToast('success', `${edits.fullName} approved and activated!`);
            if (res.data?.member) {
                setCreatedCredentials(res.data.member);
            } else {
                onApprove();
            }
        } catch (err: any) {
            showToast('error', err.response?.data?.error ?? 'Approval failed');
        } finally {
            setSaving(false);
        }
    };

    // ΓöÇΓöÇ Credentials success screen ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (createdCredentials) {
        const urlObj = new URL(window.location.href);
        const frontendUrl = `${urlObj.protocol}//${urlObj.host}`;
        const whatsappMsg = `Hello ${createdCredentials.fullName},\n\nYour Makerere Manifest Fellowship registration is approved! ≡ƒÄë\n\nHere are your login credentials:\n≡ƒôº Email: *${createdCredentials.email || '(check your inbox)'}*\n≡ƒöæ Fellowship ID: *${createdCredentials.fellowshipNumber}*\n≡ƒöÉ Temporary Password: *${createdCredentials.defaultPassword || createdCredentials.fellowshipNumber}*\n\nPlease log in at ${frontendUrl} and change your password on first login.\n\n_God bless you! ΓÇö Makerere Manifest Fellowship_`;
        const whatsappLink = `https://wa.me/?text=${encodeURIComponent(whatsappMsg)}`;

        return (
            <div className="fixed inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                <div className="bg-white rounded-2xl border border-slate-100 shadow-2xl w-full max-w-md overflow-hidden text-center">
                    <div className="bg-[#e9f5e1] py-8 flex items-center justify-center">
                        <div className="w-16 h-16 bg-white rounded-full shadow-sm flex items-center justify-center text-[#48A111]">
                            <Sparkles size={32} />
                        </div>
                    </div>

                    <div className="p-6 space-y-6">
                        <div>
                            <h2 className="text-xl font-bold text-slate-900 mb-2">Member Approved!</h2>
                            <p className="text-sm text-slate-500 leading-relaxed">
                                {createdCredentials.fullName} is now registered. A welcome email has been sent. You can also share credentials directly via WhatsApp.
                            </p>
                        </div>

                        <div className="bg-slate-50 border border-slate-200 rounded-xl p-4 text-left space-y-3">
                            {createdCredentials.email && (
                                <div>
                                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-0.5">Email</p>
                                    <p className="text-sm font-mono text-slate-700">{createdCredentials.email}</p>
                                </div>
                            )}
                            <div>
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-0.5">Fellowship Number</p>
                                <p className="text-lg font-mono font-bold text-slate-900">{createdCredentials.fellowshipNumber}</p>
                            </div>
                            {createdCredentials.defaultPassword && (
                                <div>
                                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-0.5">Default Password</p>
                                    <p className="text-sm font-mono font-semibold text-slate-700">{createdCredentials.defaultPassword}</p>
                                </div>
                            )}
                        </div>

                        <div className="flex flex-col gap-3">
                            <a
                                href={whatsappLink}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="w-full flex items-center justify-center gap-2 py-3 px-4 bg-[#25D366] hover:bg-[#20BE5C] text-white font-semibold rounded-xl shadow-lg transition-all"
                            >
                                {/* Official WhatsApp logo */}
                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 48 48" width="20" height="20" fill="white">
                                    <path d="M24 4C12.95 4 4 12.95 4 24c0 3.55.94 6.9 2.59 9.77L4 44l10.52-2.55A19.85 19.85 0 0 0 24 44c11.05 0 20-8.95 20-20S35.05 4 24 4zm0 36c-3.17 0-6.13-.85-8.67-2.33l-.62-.37-6.25 1.52 1.57-5.98-.4-.65A15.93 15.93 0 0 1 8 24c0-8.82 7.18-16 16-16s16 7.18 16 16-7.18 16-16 16zm8.85-11.65c-.48-.24-2.84-1.4-3.28-1.56-.44-.16-.76-.24-1.08.24-.32.48-1.24 1.56-1.52 1.88-.28.32-.56.36-1.04.12-.48-.24-2.03-.75-3.87-2.38-1.43-1.27-2.4-2.84-2.68-3.32-.28-.48-.03-.74.21-.98.22-.22.48-.56.72-.84.24-.28.32-.48.48-.8.16-.32.08-.6-.04-.84-.12-.24-1.08-2.6-1.48-3.56-.4-.96-.8-.84-1.08-.84l-.92-.02c-.32 0-.84.12-1.28.6-.44.48-1.68 1.64-1.68 4s1.72 4.64 1.96 4.96c.24.32 3.38 5.16 8.2 7.24 1.14.48 2.04.76 2.74.98 1.15.36 2.2.3 3.03.18.92-.14 2.84-1.16 3.24-2.28.4-1.12.4-2.08.28-2.28-.12-.2-.44-.32-.92-.56z" />
                                </svg>
                                Send via WhatsApp
                            </a>
                            <button
                                onClick={() => {
                                    navigator.clipboard.writeText(whatsappMsg);
                                    showToast('success', 'Message copied to clipboard');
                                }}
                                className="w-full flex items-center justify-center gap-2 py-3 px-4 bg-white border-2 border-slate-200 text-slate-700 font-semibold rounded-xl hover:bg-slate-50 transition-all"
                            >
                                <Copy size={18} /> Copy Message
                            </button>
                            <button
                                onClick={() => onApprove()}
                                className="w-full py-3 px-4 text-slate-400 hover:text-slate-600 font-semibold text-sm transition-colors"
                            >
                                Done, close this
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    // ΓöÇΓöÇ Approval + edit form ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    return (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl border border-slate-100 shadow-2xl w-full max-w-lg max-h-[90dvh] overflow-y-auto">
                <div className="flex items-center justify-between px-6 py-5 border-b border-slate-100 sticky top-0 bg-white rounded-t-2xl z-10">
                    <div>
                        <h2 className="font-bold text-slate-900 flex items-center gap-2"><Edit3 size={15} className="text-[#48A111]" /> Review &amp; Approve</h2>
                        <p className="text-xs text-slate-400 mt-0.5">Correct any field, then approve</p>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-xl hover:bg-slate-100 text-slate-400"><XCircle size={18} /></button>
                </div>

                <div className="p-6 space-y-5">

                    {/* ΓöÇΓöÇ Personal Info ΓöÇΓöÇ */}
                    <div>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-wide mb-3 flex items-center gap-1.5"><User size={11} /> Personal Information</p>
                        <div className="space-y-3">
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Full Name</label>
                                <input className="input" value={edits.fullName} onChange={e => set('fullName')(e.target.value)} placeholder="Full name" />
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Email</label>
                                <input className="input" type="email" value={edits.email} onChange={e => set('email')(e.target.value)} placeholder="Email address" />
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Phone Number</label>
                                <input className="input" type="tel" value={edits.phoneNumber} onChange={e => set('phoneNumber')(e.target.value)} placeholder="Phone number" />
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Gender</label>
                                <CustomSelect value={edits.gender} onChange={set('gender')}
                                    options={[{ value: 'MALE', label: 'Male' }, { value: 'FEMALE', label: 'Female' }]} />
                            </div>
                        </div>
                    </div>

                    {/* ΓöÇΓöÇ Academic ΓöÇΓöÇ */}
                    {pending.isMakerereStudent && (
                        <div>
                            <p className="text-xs font-bold text-slate-400 uppercase tracking-wide mb-3 flex items-center gap-1.5"><BookOpen size={11} /> Academic</p>
                            <div className="space-y-3">
                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide flex items-center gap-1.5"><Building size={11} /> College</label>
                                    {pending.collegeSuggestion && !pending.collegeId && (
                                        <p className="text-xs text-amber-600 bg-amber-50 px-3 py-2 rounded-lg">
                                            Suggestion: <strong>"{pending.collegeSuggestion}"</strong> ΓÇö select a match or leave blank to auto-create.
                                        </p>
                                    )}
                                    <CustomSelect value={edits.collegeId} onChange={set('collegeId')}
                                        placeholder="Match college"
                                        options={[{ value: '', label: 'Leave blank (use suggestion or skip)' }, ...colleges.map(c => ({ value: c.id, label: c.name }))]} />
                                </div>
                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide flex items-center gap-1.5"><BookOpen size={11} /> Course</label>
                                    {pending.courseSuggestion && !pending.courseId && (
                                        <p className="text-xs text-amber-600 bg-amber-50 px-3 py-2 rounded-lg">
                                            Suggestion: <strong>"{pending.courseSuggestion}"</strong> ΓÇö select a match or leave blank to auto-create.
                                        </p>
                                    )}
                                    <CustomSelect value={edits.courseId} onChange={set('courseId')}
                                        placeholder="Match course"
                                        options={[{ value: '', label: 'Leave blank (use suggestion or skip)' }, ...courses.map(c => ({ value: c.id, label: c.name }))]} />
                                </div>
                                <div className="grid grid-cols-2 gap-3">
                                    <div className="space-y-1.5">
                                        <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Year of Study</label>
                                        <CustomSelect value={edits.initialYearOfStudy} onChange={set('initialYearOfStudy')}
                                            options={[
                                                { value: '', label: 'Not set' },
                                                ...[1,2,3,4,5,6,7].map(y => ({ value: String(y), label: `Year ${y}` })),
                                            ]} />
                                    </div>
                                    <div className="space-y-1.5">
                                        <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Semester</label>
                                        <CustomSelect value={edits.initialSemester} onChange={set('initialSemester')}
                                            options={[
                                                { value: '', label: 'Not set' },
                                                { value: '1', label: 'Semester 1' },
                                                { value: '2', label: 'Semester 2' },
                                            ]} />
                                    </div>
                                </div>
                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Residence</label>
                                    {pending.residenceSuggestion && !pending.residenceId && (
                                        <p className="text-xs text-amber-600 bg-amber-50 px-3 py-2 rounded-lg">
                                            Suggestion: <strong>"{pending.residenceSuggestion}"</strong>
                                        </p>
                                    )}
                                    <CustomSelect value={edits.residenceId} onChange={set('residenceId')}
                                        placeholder="Match residence"
                                        options={[{ value: '', label: 'Leave blank (auto-create or skip)' }, ...residences.map(r => ({ value: r.id, label: r.name }))]} />
                                </div>
                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Hostel / Hall</label>
                                    <input className="input" value={edits.hostelName} onChange={e => set('hostelName')(e.target.value)} placeholder="e.g. Complex Hall" />
                                </div>
                            </div>
                        </div>
                    )}

                    {/* ΓöÇΓöÇ Assignment ΓöÇΓöÇ */}
                    <div>
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-wide mb-3 flex items-center gap-1.5"><MapPin size={11} /> Assignment</p>
                        <div className="space-y-1.5">
                            <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Region <span className="text-red-400">*</span></label>
                            <CustomSelect value={edits.regionId} onChange={set('regionId')} required
                                placeholder="Assign region"
                                options={[{ value: '', label: 'Select region', disabled: true }, ...regions.map(r => ({ value: r.id, label: r.name }))]} />
                            {!edits.regionId && <p className="text-xs text-red-400">Region must be set before approval.</p>}
                        </div>
                    </div>

                    <div className="flex gap-3 pt-2">
                        <button onClick={onClose} className="flex-1 px-5 py-2.5 rounded-xl border-2 border-slate-200 text-slate-600 font-semibold text-sm hover:bg-slate-50 transition-all">
                            Cancel
                        </button>
                        <button onClick={handleApprove} disabled={saving || !edits.regionId}
                            className="flex-1 px-5 py-2.5 rounded-xl text-white font-semibold text-sm shadow-lg transition-all disabled:opacity-50 flex items-center justify-center gap-2"
                            style={{ backgroundColor: '#48A111' }}>
                            {saving ? <><Loader2 size={14} className="animate-spin" /> ApprovingΓÇª</> : <><ThumbsUp size={14} /> Approve</>}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

// ΓöÇΓöÇ Main Page ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const PendingMembers = () => {
    const { showToast } = useToast();
    const [pending, setPending] = useState<PendingMember[]>([]);
    const [loading, setLoading] = useState(true);
    const [expanded, setExpanded] = useState<string | null>(null);
    const [approveTarget, setApproveTarget] = useState<PendingMember | null>(null);

    // Reject state
    const [rejectTarget, setRejectTarget] = useState<PendingMember | null>(null);
    const [rejectNote, setRejectNote] = useState('');
    const [rejecting, setRejecting] = useState(false);

    // Reference data
    const [regions, setRegions] = useState<Region[]>([]);
    const [colleges, setColleges] = useState<College[]>([]);
    const [courses, setCourses] = useState<Course[]>([]);
    const [residences, setResidences] = useState<Residence[]>([]);

    const fetchPending = useCallback(async () => {
        try {
            setLoading(true);
            const res = await api.get('/pending-members');
            setPending(res.data);
        } catch {
            showToast('error', 'Failed to load pending registrations');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchPending();
        Promise.all([
            api.get('/regions').then(r => setRegions(r.data)),
            api.get('/colleges').then(r => setColleges(r.data)),
            api.get('/courses').then(r => setCourses(r.data)),
            api.get('/residences').then(r => setResidences(r.data)),
        ]).catch(() => { });
    }, []);

    const handleReject = async () => {
        if (!rejectTarget) return;
        try {
            setRejecting(true);
            await api.post(`/pending-members/${rejectTarget.id}/reject`, { reviewNote: rejectNote });
            showToast('success', 'Registration rejected');
            setRejectTarget(null); setRejectNote('');
            fetchPending();
        } catch {
            showToast('error', 'Failed to reject');
        } finally {
            setRejecting(false);
        }
    };

    if (loading) return <LoadingSpinner message="Loading pending registrationsΓÇª" />;

    return (
        <div className="max-w-5xl mx-auto animate-fade-in">
            {/* Header */}
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Pending Registrations</h1>
                    <p className="text-slate-500 mt-1 text-sm">{pending.length} submission{pending.length !== 1 ? 's' : ''} awaiting review</p>
                </div>
                {pending.length > 0 && (
                    <div className="flex items-center gap-2 px-4 py-2 bg-amber-50 text-amber-700 rounded-xl text-sm font-semibold border border-amber-200">
                        <AlertTriangle size={14} /> {pending.length} pending
                    </div>
                )}
            </div>

            {pending.length === 0 ? (
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-12 text-center">
                    <CheckCircle size={32} className="text-[#48A111] mx-auto mb-3" />
                    <p className="text-slate-600 font-medium">All caught up!</p>
                    <p className="text-slate-400 text-sm mt-1">No pending registrations to review.</p>
                </div>
            ) : (
                <div className="space-y-3">
                    {pending.map(p => {
                        const isExpanded = expanded === p.id;
                        const hasUnresolved = (!p.regionId) || (p.collegeSuggestion && !p.collegeId) || (p.courseSuggestion && !p.courseId);
                        return (
                            <div key={p.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                                {/* Summary row */}
                                <div className="p-5 flex items-center gap-4">
                                    {/* Avatar */}
                                    <div className="w-10 h-10 rounded-xl font-bold text-white flex items-center justify-center shrink-0 text-sm"
                                        style={{ backgroundColor: '#48A111' }}>
                                        {p.fullName.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase()}
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-center gap-2 flex-wrap">
                                            <span className="font-semibold text-slate-900">{p.fullName}</span>
                                            <span className={`text-xs px-2 py-0.5 rounded-full font-semibold ${p.registrationMode === 'READMISSION' ? 'bg-amber-50 text-amber-600' : 'bg-[#e9f5e1] text-[#48A111]'}`}>
                                                {p.registrationMode === 'READMISSION' ? '≡ƒöä Returning' : '≡ƒîƒ New'}
                                            </span>
                                            {hasUnresolved && <span className="text-xs px-2 py-0.5 rounded-full bg-red-50 text-red-500 flex items-center gap-1"><AlertTriangle size={9} /> Needs attention</span>}
                                        </div>
                                        <p className="text-sm text-slate-500 mt-0.5 truncate">{p.email} ┬╖ {p.gender} ┬╖ submitted {new Date(p.submittedAt).toLocaleDateString()}</p>
                                    </div>
                                    <div className="flex items-center gap-2 shrink-0">
                                        <button onClick={() => setApproveTarget(p)}
                                            className="px-3.5 py-1.5 rounded-xl text-white text-xs font-semibold flex items-center gap-1.5 transition-all hover:scale-[1.03]"
                                            style={{ backgroundColor: '#48A111' }}>
                                            <ThumbsUp size={12} /> Approve
                                        </button>
                                        <button onClick={() => setRejectTarget(p)}
                                            className="px-3.5 py-1.5 rounded-xl bg-red-50 text-red-500 text-xs font-semibold flex items-center gap-1.5 hover:bg-red-100 transition-all">
                                            <ThumbsDown size={12} /> Reject
                                        </button>
                                        <button onClick={() => setExpanded(isExpanded ? null : p.id)}
                                            className="p-2 rounded-xl hover:bg-slate-100 text-slate-400 transition-all">
                                            {isExpanded ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                                        </button>
                                    </div>
                                </div>

                                {/* Expanded details */}
                                {isExpanded && (
                                    <div className="px-5 pb-5 border-t border-slate-100 pt-4 space-y-3">
                                        <div className="flex flex-wrap gap-1.5">
                                            <FieldBadge label="Region" resolved={p.region?.name} />
                                            <FieldBadge label="College" resolved={p.collegeId ? colleges.find(c => c.id === p.collegeId)?.name : undefined} suggestion={p.collegeSuggestion} />
                                            <FieldBadge label="Course" resolved={p.courseId ? courses.find(c => c.id === p.courseId)?.name : undefined} suggestion={p.courseSuggestion} />
                                            {p.initialYearOfStudy && <span className="text-xs text-slate-600 bg-slate-100 px-2 py-0.5 rounded-full">Year {p.initialYearOfStudy}, Sem {p.initialSemester}</span>}
                                            {p.hostelName && <span className="text-xs text-slate-600 bg-slate-100 px-2 py-0.5 rounded-full">Hostel: {p.hostelName}</span>}
                                        </div>
                                        <p className="text-xs text-slate-400">Phone: {p.phoneNumber} ┬╖ Token: {p.token?.label ?? p.token?.token?.substring(0, 12) + 'ΓÇª'}</p>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            )}

            {/* Approve modal */}
            {approveTarget && (
                <ApproveModal
                    pending={approveTarget}
                    regions={regions} colleges={colleges} courses={courses} residences={residences}
                    onApprove={() => { setApproveTarget(null); fetchPending(); }}
                    onClose={() => setApproveTarget(null)}
                />
            )}

            {/* Reject modal */}
            {rejectTarget && (
                <div className="fixed inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                    <div className="bg-white rounded-2xl border border-slate-100 shadow-2xl w-full max-w-md">
                        <div className="px-6 py-5 border-b border-slate-100">
                            <h2 className="font-bold text-slate-900">Reject Registration</h2>
                            <p className="text-xs text-slate-500 mt-0.5">{rejectTarget.fullName}</p>
                        </div>
                        <div className="p-6 space-y-4">
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Reason <span className="font-normal normal-case text-slate-400">(optional ΓÇö will be emailed)</span></label>
                                <textarea rows={3} value={rejectNote} onChange={e => setRejectNote(e.target.value)}
                                    className="input mt-2 resize-none" placeholder="e.g. Duplicate entry, unverifiable detailsΓÇª" />
                            </div>
                            <div className="flex gap-3">
                                <button onClick={() => { setRejectTarget(null); setRejectNote(''); }}
                                    className="flex-1 px-5 py-2.5 rounded-xl border-2 border-slate-200 text-slate-600 font-semibold text-sm hover:bg-slate-50 transition-all">
                                    Cancel
                                </button>
                                <button onClick={handleReject} disabled={rejecting}
                                    className="flex-1 px-5 py-2.5 rounded-xl text-white font-semibold text-sm bg-red-500 hover:bg-red-600 shadow-lg transition-all disabled:opacity-50 flex items-center justify-center gap-2">
                                    {rejecting ? <><Loader2 size={14} className="animate-spin" /> RejectingΓÇª</> : <><ThumbsDown size={14} /> Reject</>}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default PendingMembers;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../components/ToastProvider';
import api from '../api';
import QRCode from 'react-qr-code';
import {
    User, Mail, Hash, Shield, Tag as TagIcon, Loader2,
    BookOpen, GraduationCap, Download, Phone, MapPin, Users,
    Clock, Edit2, Briefcase, Camera, Building, Calendar, Flag
} from 'lucide-react';
import TagBadge from '../components/TagBadge';
import EditRequestModal from '../components/EditRequestModal';
import ChangePasswordModal from '../components/ChangePasswordModal';
import CampaignTab from './Profile/CampaignTab';

interface Tag {
    id: string;
    name: string;
    color: string;
    type: 'SYSTEM' | 'CUSTOM';
    isSystem: boolean;
}

interface AcademicStatus {
    currentYear: number | null;
    currentSemester: number | null;
    isFinalist: boolean;
    isAlumni: boolean;
    course: {
        id: string;
        name: string;
        durationYears: number;
    } | null;
}

interface PendingEditRequest {
    id: string;
    status: 'PENDING' | 'APPROVED' | 'REJECTED';
    changes: Array<{ field: string; oldValue: string; newValue: string }>;
    reason: string;
    createdAt: string;
}

interface ExtendedProfile {
    phoneNumber: string;
    gender: string | null;
    hostelName: string | null;
    region: { id: string; name: string } | null;
    family: { id: string; name: string } | null;
    teams: Array<{ id: string; name: string }>;
    residence: { id: string; name: string; type: string } | null;
    academic: {
        courseId: string | null;
        courseName: string | null;
        collegeId: string | null;
        collegeName: string | null;
        durationYears: number | null;
        currentYear: number | null;
        currentSemester: number | null;
    } | null;
    pendingEditRequest: PendingEditRequest | null;
}

const Profile = () => {
    const { user, isManager } = useAuth();
    const navigate = useNavigate();
    const { showToast } = useToast();
    const [tags, setTags] = useState<Tag[]>([]);
    const [loadingTags, setLoadingTags] = useState(true);
    const [academicStatus, setAcademicStatus] = useState<AcademicStatus | null>(null);
    const [loadingAcademic, setLoadingAcademic] = useState(true);
    const [extProfile, setExtProfile] = useState<ExtendedProfile | null>(null);
    const [loadingExtProfile, setLoadingExtProfile] = useState(true);
    const [showEditModal, setShowEditModal] = useState(false);
    const [showPasswordModal, setShowPasswordModal] = useState(false);
    const [activeTab, setActiveTab] = useState<'personal' | 'fellowship' | 'academic' | 'security' | 'campaigns'>('personal');

    useEffect(() => {
        if (user?.id) {
            fetchUserTags();
            fetchAcademicStatus();
            fetchExtProfile();
        }
    }, [user?.id]);

    const fetchUserTags = async () => {
        try {
            setLoadingTags(true);
            const response = await api.get(`/tags/members/${user?.id}/history`);
            const activeTags = response.data
                .filter((mt: any) => mt.isActive)
                .map((mt: any) => mt.tag);
            setTags(activeTags);
        } catch (error) {
            console.error('Failed to fetch user tags:', error);
        } finally {
            setLoadingTags(false);
        }
    };

    const fetchAcademicStatus = async () => {
        try {
            setLoadingAcademic(true);
            const response = await api.get(`/members/${user?.id}/academic-status`);
            setAcademicStatus(response.data);
        } catch (error) {
            console.error('Failed to fetch academic status:', error);
        } finally {
            setLoadingAcademic(false);
        }
    };

    const fetchExtProfile = async () => {
        try {
            setLoadingExtProfile(true);
            const response = await api.get('/members/me');
            setExtProfile({ ...response.data, teams: response.data.teams || [] });
        } catch (error) {
            console.error('Failed to fetch extended profile:', error);
        } finally {
            setLoadingExtProfile(false);
        }
    };

    if (!user) return null;

    const downloadQRCode = () => {
        const svg = document.getElementById('profile-qr-code');
        if (!svg) return;
        const svgData = new XMLSerializer().serializeToString(svg);
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const img = new Image();
        img.onload = () => {
            const padding = 30;
            canvas.width = img.width + padding * 2;
            canvas.height = img.height + padding * 2;
            if (ctx) {
                ctx.fillStyle = '#FFFFFF';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
                ctx.drawImage(img, padding, padding);
            }
            const pngFile = canvas.toDataURL('image/png');
            const link = document.createElement('a');
            link.download = `${user.fullName.replace(/\s+/g, '-')}-QR.png`;
            link.href = pngFile;
            link.click();
        };
        img.src = 'data:image/svg+xml;base64,' + btoa(svgData);
    };

    const pendingRequest = extProfile?.pendingEditRequest;

    const renderEditRequestStatus = () => {
        if (loadingExtProfile) return null;

        if (isManager) {
            return (
                <button
                    onClick={() => navigate('/profile/edit')}
                    className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold bg-white text-slate-700 shadow-sm border border-slate-200 hover:bg-slate-50 transition-all"
                >
                    <Edit2 size={15} />
                    Edit Profile
                </button>
            );
        }

        if (!pendingRequest) {
            return (
                <button
                    onClick={() => setShowEditModal(true)}
                    className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold bg-white text-slate-700 shadow-sm border border-slate-200 hover:bg-slate-50 transition-all"
                >
                    <Edit2 size={15} />
                    Request Edit
                </button>
            );
        }
        
        if (pendingRequest.status === 'PENDING') {
            return (
                <div className="flex items-center gap-2 px-4 py-2.5 rounded-xl bg-amber-50 border border-amber-200 text-amber-700 text-sm font-medium shadow-sm">
                    <Clock size={15} />
                    Edit pending
                </div>
            );
        }
        return null;
    };

    const tabs = [
        { id: 'personal', label: 'Personal Details', icon: User },
        { id: 'fellowship', label: 'Fellowship Life', icon: Briefcase },
        { id: 'academic', label: 'Academic & Housing', icon: GraduationCap },
        { id: 'campaigns', label: 'Bring 1 Campaign', icon: Flag },
        { id: 'security', label: 'Security', icon: Shield }
    ] as const;

    return (
        <div className="max-w-6xl mx-auto space-y-6 animate-fade-in pb-12">
            {/* Header Banner */}
            <div className="relative rounded-3xl overflow-hidden bg-[#48A111] shadow-xl">
                <div className="absolute inset-0 opacity-20 bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))] from-white to-[#48A111]"></div>
                <div className="relative px-8 py-10 md:py-14 flex flex-col md:flex-row items-center md:items-start justify-between gap-6">
                    <div className="flex flex-col md:flex-row items-center md:items-start gap-6">
                        <div className="w-24 h-24 md:w-32 md:h-32 rounded-3xl bg-white shadow-lg flex items-center justify-center text-4xl font-bold text-[#48A111] relative group overflow-hidden border-4 border-[#e9f5e1]/30">
                            {user.fullName.charAt(0)}
                            <div className="absolute inset-0 bg-black/5 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                <Camera className="text-white drop-shadow-md" />
                            </div>
                        </div>
                        <div className="text-center md:text-left text-white mt-3">
                            <h1 className="text-3xl md:text-4xl font-extrabold tracking-tight mb-3">{user.fullName}</h1>
                            <div className="flex flex-wrap items-center justify-center md:justify-start gap-3">
                                <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-bold bg-[#F2B50B] text-slate-900 shadow-sm uppercase tracking-wider">
                                    {user.role.replace('_', ' ')}
                                </span>
                                <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-white/20 text-white backdrop-blur-sm shadow-sm font-mono tracking-wide">
                                    <Hash size={12} className="mr-1" /> {user.fellowshipNumber}
                                </span>
                            </div>
                        </div>
                    </div>
                    <div className="flex-shrink-0 mt-4 md:mt-0">
                        {renderEditRequestStatus()}
                    </div>
                </div>
            </div>

            {/* Main Content Area */}
            <div className="grid lg:grid-cols-3 gap-6">
                
                {/* Left Sidebar: Nav & QR */}
                <div className="lg:col-span-1 space-y-6">
                    {/* Navigation Tabs */}
                    <div className="bg-white rounded-3xl p-3 shadow-sm border border-slate-200">
                        <nav className="flex flex-col space-y-1">
                            {tabs.map(tab => {
                                const Icon = tab.icon;
                                const isActive = activeTab === tab.id;
                                return (
                                    <button
                                        key={tab.id}
                                        onClick={() => setActiveTab(tab.id as any)}
                                        className={`flex items-center gap-3 px-4 py-3.5 rounded-2xl text-sm font-semibold transition-all duration-200 ${
                                            isActive 
                                            ? 'bg-[#e9f5e1] text-[#48A111] translate-x-1 shadow-sm' 
                                            : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'
                                        }`}
                                    >
                                        <Icon size={18} className={isActive ? 'text-[#48A111]' : 'text-slate-400'} />
                                        {tab.label}
                                    </button>
                                );
                            })}
                        </nav>
                    </div>

                    {/* QR Code Card */}
                    <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-200 text-center flex flex-col items-center">
                        <div className="p-4 bg-white rounded-2xl shadow-sm border border-slate-100 mb-4 inline-block hover:shadow-md transition-shadow">
                            <QRCode
                                id="profile-qr-code"
                                value={user.qrCode}
                                size={140}
                                level="M"
                            />
                        </div>
                        <h3 className="text-slate-900 font-bold text-lg mb-1">Check-in Pass</h3>
                        <p className="text-slate-500 text-xs mb-5 px-4 leading-relaxed">
                            Present this QR code at events for quick check-in.
                        </p>
                        <button
                            onClick={downloadQRCode}
                            className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-white text-sm font-bold w-full justify-center shadow-md transition-all hover:shadow-lg hover:-translate-y-0.5"
                            style={{ backgroundColor: '#48A111' }}
                        >
                            <Download size={16} />
                            Save Image
                        </button>
                    </div>
                </div>

                {/* Right Content Space */}
                <div className="lg:col-span-2">
                    <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden min-h-[500px]">
                        
                        {/* Personal Tab */}
                        {activeTab === 'personal' && (
                            <div className="p-8 animate-fade-in space-y-8">
                                <div>
                                    <h2 className="text-2xl font-bold text-slate-900 mb-6 flex items-center gap-2">
                                        <User className="text-[#48A111]" size={24} /> Personal Details
                                    </h2>
                                    <div className="grid md:grid-cols-2 gap-5">
                                        <div className="p-5 rounded-2xl bg-slate-50 border border-slate-100 transition-colors hover:border-[#c5e3b0]">
                                            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Email Address</p>
                                            <div className="flex items-center gap-2 text-slate-900 font-medium break-all mt-2">
                                                <Mail size={18} className="text-[#48A111]" /> {user.email}
                                            </div>
                                        </div>
                                        <div className="p-5 rounded-2xl bg-slate-50 border border-slate-100 transition-colors hover:border-[#c5e3b0]">
                                            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Phone Number</p>
                                            <div className="flex items-center gap-2 text-slate-900 font-medium mt-2">
                                                <Phone size={18} className="text-[#48A111]" /> 
                                                {loadingExtProfile ? <Loader2 size={14} className="animate-spin text-slate-400" /> : extProfile?.phoneNumber || 'ΓÇö'}
                                            </div>
                                        </div>
                                        <div className="p-5 rounded-2xl bg-slate-50 border border-slate-100 transition-colors hover:border-[#c5e3b0]">
                                            <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Gender</p>
