                                    <h2 className="text-2xl font-bold text-slate-900 mb-6 flex items-center gap-2">
                                        <GraduationCap className="text-[#48A111]" size={24} /> Education & Housing
                                    </h2>
                                    
                                    {loadingAcademic || loadingExtProfile ? (
                                        <div className="flex items-center justify-center py-12">
                                            <Loader2 size={32} className="text-[#48A111] animate-spin" />
                                        </div>
                                    ) : (
                                        <div className="space-y-5">
                                            <div className="p-6 rounded-2xl bg-slate-50 border border-slate-200 flex flex-col md:flex-row gap-5 md:items-center justify-between shadow-sm">
                                                <div className="flex gap-5 items-center">
                                                    <div className="w-14 h-14 rounded-2xl bg-white border border-[#c5e3b0] flex items-center justify-center shrink-0 shadow-sm">
                                                        <Building className="text-[#48A111]" size={26} />
                                                    </div>
                                                    <div>
                                                        <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Institution</p>
                                                        <p className="text-slate-900 font-extrabold text-lg">{academicStatus?.course?.durationYears ? extProfile?.academic?.collegeName || 'Unknown College' : 'N/A'}</p>
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="p-6 rounded-2xl bg-slate-50 border border-slate-200 flex flex-col md:flex-row gap-5 md:items-center justify-between shadow-sm">
                                                <div className="flex gap-5 items-center">
                                                    <div className="w-14 h-14 rounded-2xl bg-white border border-[#c5e3b0] flex items-center justify-center shrink-0 shadow-sm">
                                                        <BookOpen className="text-[#48A111]" size={26} />
                                                    </div>
                                                    <div>
                                                        <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Course of Study</p>
                                                        <p className="text-slate-900 font-extrabold text-lg">{academicStatus?.course?.name || 'Not filled'}</p>
                                                        {academicStatus?.course?.durationYears && (
                                                            <p className="text-sm font-medium text-slate-500 mt-1">{academicStatus.course.durationYears} Year Program</p>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="flex flex-col sm:flex-row gap-5 pt-2">
                                                <div className="flex-1 p-6 rounded-2xl bg-slate-50 border border-slate-200 flex items-start gap-4 shadow-sm">
                                                    <Calendar className="text-[#48A111] shrink-0 mt-1" size={22} />
                                                    <div>
                                                        <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Current Standing</p>
                                                        <p className="text-slate-900 font-bold text-lg">
                                                            {academicStatus?.currentYear ? `Year ${academicStatus.currentYear}` : 'ΓÇö'}
                                                        </p>
                                                        <div className="flex gap-2 mt-3">
                                                            {academicStatus?.isFinalist && (
                                                                <span className="px-3 py-1 rounded-lg text-[11px] font-bold bg-[#F2B50B]/20 text-yellow-900 border border-[#F2B50B]/40 uppercase tracking-wider">Finalist</span>
                                                            )}
                                                            {academicStatus?.isAlumni && (
                                                                <span className="px-3 py-1 rounded-lg text-[11px] font-bold bg-[#48A111]/10 text-[#48A111] border border-[#48A111]/30 uppercase tracking-wider">Alumni</span>
                                                            )}
                                                        </div>
                                                    </div>
                                                </div>

                                                <div className="flex-1 p-6 rounded-2xl bg-slate-50 border border-slate-200 flex items-start gap-4 shadow-sm">
                                                    <MapPin className="text-[#48A111] shrink-0 mt-1" size={22} />
                                                    <div>
                                                        <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Current Residence</p>
                                                        <p className="text-slate-900 font-bold text-lg">
                                                            {extProfile?.residence?.name || extProfile?.hostelName || 'Not filled'}
                                                        </p>
                                                        {extProfile?.residence && (
                                                            <p className="text-sm font-medium text-slate-500 mt-1 capitalize">{extProfile.residence.type.toLowerCase()}</p>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}

                        {/* Security Tab */}
                        {activeTab === 'security' && (
                            <div className="p-8 animate-fade-in space-y-8">
                                <div>
                                    <h2 className="text-2xl font-bold text-slate-900 mb-6 flex items-center gap-2">
                                        <Shield className="text-[#48A111]" size={24} /> Security Settings
                                    </h2>
                                    <div className="p-6 rounded-2xl bg-slate-50 border border-slate-200 flex flex-col sm:flex-row sm:items-center justify-between gap-6 shadow-sm">
                                        <div>
                                            <p className="font-bold text-slate-900 text-lg">Account Password</p>
                                            <p className="text-sm font-medium text-slate-500 mt-1">Ensure your account uses a strong, unique password.</p>
                                        </div>
                                        <button
                                            onClick={() => setShowPasswordModal(true)}
                                            className="px-6 py-3 bg-white border border-slate-300 text-slate-700 font-bold rounded-xl hover:bg-slate-50 hover:border-slate-400 transition-all shadow-sm whitespace-nowrap"
                                        >
                                            Change Password
                                        </button>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
                <div className="lg:col-span-2 space-y-6">
                    {activeTab === 'campaigns' && <CampaignTab />}
                </div>

            </div>

            {/* Modals */}
            {showEditModal && !isManager && extProfile && (
                <EditRequestModal
                    isOpen={showEditModal}
                    currentProfile={{
                        fullName: user!.fullName,
                        email: user!.email,
                        phoneNumber: extProfile.phoneNumber,
                        hostelName: extProfile.hostelName,
                        region: extProfile.region,
                        residence: extProfile.residence,
                        academic: extProfile.academic,
                    }}
                    onClose={() => setShowEditModal(false)}
                    onSuccess={fetchExtProfile}
                />
            )}

            <ChangePasswordModal
                isOpen={showPasswordModal}
                onClose={() => setShowPasswordModal(false)}
            />
        </div>
    );
};

export default Profile;

import React, { useState, useEffect } from 'react';
import api from '../../api';
import { Target, UserPlus, Loader2, CheckCircle2, Clock, Plus, Flag, Trash2, Calendar, AlertCircle, Pencil, X, Check, MessageCircle } from 'lucide-react';
import { useToast } from '../../components/ToastProvider';
import ContactChatModal from '../../components/Campaigns/ContactChatModal';

export default function CampaignTab() {
    const { showToast } = useToast();
    const [loading, setLoading] = useState(true);
    const [campaigns, setCampaigns] = useState<any[]>([]);
    const [pledges, setPledges] = useState<any[]>([]);
    const [events, setEvents] = useState<any[]>([]);
    const [selectedEventId, setSelectedEventId] = useState<string>('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [editingPledge, setEditingPledge] = useState<{ id: string; name: string; email: string; phone1: string; phone2: string } | null>(null);

    // Chat State
    const [chatEntity, setChatEntity] = useState<{ id: string; name: string } | null>(null);

    const getUserIdFromToken = () => {
        const token = localStorage.getItem('token');
        if (!token) return '';
        try {
            const payload = JSON.parse(atob(token.split('.')[1]));
            return payload.id;
        } catch {
            return '';
        }
    };
    const currentUserId = getUserIdFromToken();

    // Form state for new pledges
    const [newPledges, setNewPledges] = useState([{ name: '', email: '', phone1: '', phone2: '' }]);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            setLoading(true);
            const [campRes, pledgeRes, eventsRes] = await Promise.all([
                api.get('/bring-one/campaigns'),
                api.get('/bring-one/my-pledges'),
                api.get('/events')
            ]);
            setCampaigns(campRes.data);
            setPledges(pledgeRes.data);

            const upcomingEvents = eventsRes.data.filter((e: any) => e.status === 'UPCOMING' || e.status === 'ONGOING');
            setEvents(upcomingEvents);
            if (upcomingEvents.length > 0) {
                setSelectedEventId(upcomingEvents[0].id);
            }
        } catch (error) {
            console.error('Failed to fetch campaign data:', error);
            showToast('error', 'Failed to load campaign data');
        } finally {
            setLoading(false);
        }
    };

    const activeCampaign = campaigns.length > 0 ? campaigns[0] : null;

    const handleAddRow = () => {
        setNewPledges([...newPledges, { name: '', email: '', phone1: '', phone2: '' }]);
    };

    const handleRemoveRow = (index: number) => {
        if (newPledges.length === 1) return;
        setNewPledges(newPledges.filter((_, i) => i !== index));
    };

    const handleChange = (index: number, field: string, value: string) => {
        const updated = [...newPledges];
        updated[index] = { ...updated[index], [field]: value };
        setNewPledges(updated);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!activeCampaign) return;
        if (!selectedEventId) {
            showToast('error', 'Please select a target event');
            return;
        }

        const validPledges = newPledges.filter(p => p.name.trim() && p.email.trim());
        
        if (validPledges.length === 0) {
            showToast('error', 'Please fill out at least one name and email');
            return;
        }

        try {
            setIsSubmitting(true);
            await api.post('/bring-one/pledges', {
                campaignId: activeCampaign.id,
                eventId: selectedEventId,
                pledges: validPledges.map(p => ({
                    ...p,
                    email: p.email.trim().toLowerCase()
                }))
            });
            showToast('success', 'Pledges submitted successfully!');
            setNewPledges([{ name: '', email: '', phone1: '', phone2: '' }]);
            
            // Refresh pledges
            const pledgeRes = await api.get('/bring-one/my-pledges');
            setPledges(pledgeRes.data);
        } catch (error: any) {
            console.error('Submission error:', error);
            showToast('error', error.response?.data?.message || 'Failed to submit pledges');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleSavePledgeEdit = async () => {
        if (!editingPledge) return;
        try {
            await api.patch(`/bring-one/pledges/${editingPledge.id}`, {
                name: editingPledge.name,
                email: editingPledge.email,
                phone1: editingPledge.phone1 || null,
                phone2: editingPledge.phone2 || null,
            });
            showToast('success', 'Pledge updated!');
            setEditingPledge(null);
            const pledgeRes = await api.get('/bring-one/my-pledges');
            setPledges(pledgeRes.data);
        } catch (error: any) {
            showToast('error', error.response?.data?.message || 'Failed to update pledge');
        }
    };

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'PLEDGED':
                return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-700">Pledged</span>;
            case 'PENDING_APPROVAL':
                return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-amber-100 text-amber-800">Registered</span>;
            case 'JOINED':
                return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">Member</span>;
            case 'ATTENDED':
                return <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium bg-[#e9f5e1] text-[#48A111]"><CheckCircle2 size={12}/> Attended</span>;
            case 'LAPSED':
                return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">Lapsed</span>;
            default:
                return null;
        }
    };

    if (loading) {
        return (
            <div className="p-8 flex justify-center items-center h-48">
                <Loader2 size={32} className="animate-spin text-[#48A111]" />
            </div>
        );
    }

    return (
        <div className="p-8 animate-fade-in space-y-8">
            <div>
                <h2 className="text-2xl font-bold text-slate-900 mb-6 flex items-center gap-2">
                    <Flag className="text-[#48A111]" size={24} /> Bring 1 Campaign
                </h2>
                
                {!activeCampaign ? (
                    <div className="p-8 text-center rounded-2xl bg-slate-50 border border-slate-200 shadow-sm border-dashed">
                        <Target className="mx-auto text-slate-400 mb-3" size={32} />
                        <h3 className="text-lg font-bold text-slate-700">No Active Campaigns</h3>
                        <p className="text-slate-500 mt-2">There is currently no active Bring 1 campaign.</p>
                    </div>
                ) : (
                    <div className="space-y-8">
                        {/* Campaign Info */}
                        <div className="p-6 rounded-2xl bg-gradient-to-br from-[#e9f5e1] to-white border border-[#c5e3b0] shadow-sm relative overflow-hidden">
                            <div className="relative z-10">
                                <h3 className="text-xl font-bold text-[#48A111] mb-2">{activeCampaign.title}</h3>
                                {activeCampaign.description && (
                                    <p className="text-slate-700 mb-4">{activeCampaign.description}</p>
                                )}
                                <div className="inline-flex items-center gap-2 px-3 py-1.5 bg-white rounded-lg border border-[#c5e3b0] text-sm font-semibold text-slate-800 shadow-sm">
                                    <UserPlus size={16} className="text-[#48A111]" />
                                    Minimum Pledges Goal: {activeCampaign.minPledges}
                                </div>
                            </div>
                            <Target size={120} className="absolute -right-10 -bottom-10 text-[#48A111] opacity-5 transform -rotate-12" />
                        </div>

                        {/* Submit Pledges Form */}
                        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                            <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                                    <Plus size={20} className="text-[#48A111]" /> Add New Pledges
                                </h3>
                                {events.length > 0 && (
                                    <div className="flex items-center gap-2 relative">
                                        <Calendar size={16} className="absolute left-3 text-slate-400" />
                                        <select
                                            value={selectedEventId}
                                            onChange={(e) => setSelectedEventId(e.target.value)}
                                            className="pl-9 pr-8 py-2 border border-slate-200 rounded-lg text-sm bg-white font-medium text-slate-700 focus:outline-none focus:border-[#48A111] shadow-sm appearance-none cursor-pointer hover:bg-slate-50"
                                        >
                                            {events.map((event) => (
                                                <option key={event.id} value={event.id}>
                                                    {event.name} ({new Date(event.date).toLocaleDateString()})
                                                </option>
                                            ))}
                                        </select>
                                        <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-slate-500">
                                            <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                                        </div>
                                    </div>
                                )}
                            </div>
                            
                            <form onSubmit={handleSubmit} className="p-6">
                                {events.length === 0 ? (
                                    <div className="p-4 bg-amber-50 text-amber-800 rounded-lg border border-amber-200 flex items-center gap-2 text-sm">
                                        <AlertCircle size={16} />
                                        No upcoming events available for pledging.
                                    </div>
                                ) : (
                                    <>
                                        <div className="space-y-4">
                                            {newPledges.map((pledge, index) => (
                                                <div key={index} className="flex flex-col sm:flex-row gap-4 items-start sm:items-center p-4 bg-slate-50/50 rounded-xl border border-slate-100 hover:border-slate-200 transition-colors group">
                                                    <div className="flex items-center justify-center w-6 h-6 rounded-full bg-slate-200 text-slate-500 text-xs font-bold shrink-0">
                                                        {index + 1}
                                                    </div>
                                                    <div className="flex-1 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 w-full">
                                                        <input 
                                                            type="text" 
                                                            placeholder="Full Name *" 
                                                            required
                                                            value={pledge.name}
                                                            onChange={(e) => handleChange(index, 'name', e.target.value)}
                                                            className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:border-[#48A111] bg-white"
                                                        />
                                                        <input 
                                                            type="email" 
                                                            placeholder="Email Address *" 
                                                            required
                                                            value={pledge.email}
                                                            onChange={(e) => handleChange(index, 'email', e.target.value)}
                                                            className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:border-[#48A111] bg-white"
                                                        />
                                                        <input 
                                                            type="tel" 
                                                            placeholder="Phone 1 (Optional)" 
                                                            value={pledge.phone1}
                                                            onChange={(e) => handleChange(index, 'phone1', e.target.value)}
                                                            className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:border-[#48A111] bg-white"
                                                        />
                                                        <input 
                                                            type="tel" 
                                                            placeholder="Phone 2 (Optional)" 
                                                            value={pledge.phone2}
                                                            onChange={(e) => handleChange(index, 'phone2', e.target.value)}
                                                            className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:border-[#48A111] bg-white"
                                                        />
                                                    </div>
                                                    <button 
                                                        type="button" 
                                                        onClick={() => handleRemoveRow(index)}
                                                        disabled={newPledges.length === 1}
                                                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-30 disabled:hover:bg-transparent shrink-0"
                                                    >
                                                        <Trash2 size={18} />
                                                    </button>
                                                </div>
                                            ))}
                                        </div>

                                        <div className="mt-5 flex justify-between items-center">
                                            <button 
                                                type="button" 
                                                onClick={handleAddRow}
                                                className="flex items-center gap-1.5 text-sm font-semibold text-[#48A111] hover:text-[#387f0e] px-2 py-1"
                                            >
                                                <Plus size={16} /> Add another person
                                            </button>
                                            <button 
                                                type="submit" 
                                                disabled={isSubmitting}
                                                className="px-6 py-2.5 bg-[#48A111] text-white font-bold rounded-xl hover:bg-[#387f0e] shadow-sm transition-all disabled:opacity-75 disabled:cursor-not-allowed flex items-center gap-2"
                                            >
                                                {isSubmitting ? <Loader2 size={18} className="animate-spin" /> : 'Submit Pledges'}
                                            </button>
                                        </div>
                                    </>
                                )}
                            </form>
                        </div>

                        {/* My Pledges List */}
                        {pledges.length > 0 && (
                            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                                <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between">
                                    <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                                        <Target size={20} className="text-[#48A111]" /> My Tracked Pledges
                                    </h3>
                                </div>
                                <div className="overflow-x-auto">
                                    <table className="w-full text-left border-collapse min-w-[700px]">
                                        <thead>
                                            <tr className="bg-slate-50 border-b border-slate-200 text-xs uppercase tracking-wider text-slate-500 font-bold">
                                                <th className="px-6 py-3">Name</th>
                                                <th className="px-6 py-3">Contact Email</th>
                                                <th className="px-6 py-3">Event Target</th>
                                                <th className="px-6 py-3">Status</th>
                                                <th className="px-6 py-3 text-right">Submitted</th>
                                                <th className="px-6 py-3"></th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-slate-100 text-sm">
                                            {pledges.map((pledge) => (
                                                <React.Fragment key={pledge.id}>
                                                    <tr className="hover:bg-slate-50/50 transition-colors">
                                                        <td className="px-6 py-4 font-semibold text-slate-700">
                                                            {editingPledge?.id === pledge.id ? (
                                                                <input className="w-full text-sm border border-slate-300 rounded-lg px-2 py-1 outline-none focus:border-[#48A111]" value={editingPledge!.name} onChange={e => setEditingPledge({ ...editingPledge!, name: e.target.value })} />
                                                            ) : pledge.name}
                                                        </td>
                                                        <td className="px-6 py-4 text-slate-500">
                                                            {editingPledge?.id === pledge.id ? (
                                                                <div className="flex flex-col gap-1 min-w-[180px]">
                                                                    <input className="w-full text-sm border border-slate-300 rounded-lg px-2 py-1 outline-none focus:border-[#48A111]" placeholder="Email" value={editingPledge!.email} onChange={e => setEditingPledge({ ...editingPledge!, email: e.target.value })} />
                                                                    <input className="w-full text-sm border border-slate-300 rounded-lg px-2 py-1 outline-none focus:border-[#48A111]" placeholder="Phone 1" value={editingPledge!.phone1} onChange={e => setEditingPledge({ ...editingPledge!, phone1: e.target.value })} />
                                                                    <input className="w-full text-sm border border-slate-300 rounded-lg px-2 py-1 outline-none focus:border-[#48A111]" placeholder="Phone 2" value={editingPledge!.phone2} onChange={e => setEditingPledge({ ...editingPledge!, phone2: e.target.value })} />
                                                                </div>
                                                            ) : pledge.email}
                                                        </td>
                                                        <td className="px-6 py-4 text-slate-600 font-medium">{pledge.event.name}</td>
                                                        <td className="px-6 py-4">{getStatusBadge(pledge.status)}</td>
                                                        <td className="px-6 py-4 text-slate-400 text-right">{new Date(pledge.createdAt).toLocaleDateString()}</td>
                                                        <td className="px-6 py-4">
                                                            <div className="flex gap-2 items-center">
                                                                <button
                                                                    onClick={() => setChatEntity({ id: pledge.id, name: pledge.name })}
                                                                    className="p-1.5 text-cyan-600 hover:bg-cyan-50 rounded-lg transition-colors relative"
                                                                    title="Chat with Admin"
                                                                >
                                                                    <MessageCircle size={16} />
                                                                    {pledge._count?.messages > 0 && (
                                                                        <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>
                                                                    )}
                                                                </button>
                                                                {editingPledge?.id === pledge.id ? (
                                                                    <div className="flex gap-1.5">
                                                                        <button onClick={handleSavePledgeEdit} className="p-1.5 bg-[#48A111] text-white rounded-lg hover:bg-[#3a8a0e] transition-colors" title="Save"><Check size={14} /></button>
                                                                        <button onClick={() => setEditingPledge(null)} className="p-1.5 bg-slate-200 text-slate-600 rounded-lg hover:bg-slate-300 transition-colors" title="Cancel"><X size={14} /></button>
                                                                    </div>
                                                                ) : pledge.status === 'PLEDGED' && new Date() < new Date(pledge.event.date) ? (
                                                                    <button onClick={() => setEditingPledge({ id: pledge.id, name: pledge.name, email: pledge.email, phone1: pledge.phone1 || '', phone2: pledge.phone2 || '' })} className="p-1.5 text-slate-400 hover:text-[#48A111] hover:bg-[#e9f5e1] rounded-lg transition-colors" title="Edit pledge"><Pencil size={15} /></button>
                                                                ) : null}
                                                            </div>
                                                        </td>
                                                    </tr>
                                                </React.Fragment>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Chat Modal */}
            {chatEntity && (
                <ContactChatModal
                    isOpen={!!chatEntity}
                    onClose={() => setChatEntity(null)}
                    entityId={chatEntity.id}
                    entityName={chatEntity.name}
                    type="BRING_ONE"
                    currentUserId={currentUserId}
                    onMessagesRead={() => {
                        api.get('/bring-one/my-pledges').then((res) => setPledges(res.data));
                    }}
                />
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import type { E164Number } from 'libphonenumber-js/core';
import api from '../../api';
import { useToast } from '../../components/ToastProvider';
import {
    User, Users, Mail, Phone, Building, BookOpen, GraduationCap,
    MapPin, Plus, Loader2, ArrowLeft, Save,
} from 'lucide-react';
import PhoneInput from '../../components/PhoneInput';
import CustomSelect from '../../components/CustomSelect';
import AddCollegeModal from '../../components/AddCollegeModal';
import AddCourseModal from '../../components/AddCourseModal';
import AddResidenceModal from '../../components/AddResidenceModal';
import ChangePasswordModal from '../../components/ChangePasswordModal';
import TransferRequestModal from '../../components/TransferRequestModal';
import FamilyTransferRequestModal from '../../components/FamilyTransferRequestModal';
import '../../styles/phoneInput.css';

interface College { id: string; name: string; code?: string; }
interface Course { id: string; name: string; durationYears?: number; }
interface Residence { id: string; name: string; type: string; }

const ProfileEditPage: React.FC = () => {
    const navigate = useNavigate();
    const { showToast } = useToast();

    const [loading, setLoading] = useState(false);
    const [loadingProfile, setLoadingProfile] = useState(true);

    // Reference data
    const [colleges, setColleges] = useState<College[]>([]);
    const [courses, setCourses] = useState<Course[]>([]);
    const [residences, setResidences] = useState<Residence[]>([]);

    // Sub-modals
    const [isCourseModalOpen, setIsCourseModalOpen] = useState(false);
    const [isCollegeModalOpen, setIsCollegeModalOpen] = useState(false);
    const [isResidenceModalOpen, setIsResidenceModalOpen] = useState(false);
    const [showPasswordModal, setShowPasswordModal] = useState(false);
    const [isTransferModalOpen, setIsTransferModalOpen] = useState(false);
    const [isFamilyTransferModalOpen, setIsFamilyTransferModalOpen] = useState(false);

    // Form state
    const [formData, setFormData] = useState({
        fullName: '',
        email: '',
        phoneNumber: '' as E164Number | '',
        collegeId: '',
        courseId: '',
        initialYearOfStudy: 1,
        initialSemester: 1,
        residenceId: '',
        hostelName: '',
    });

    // Region and Family info (from profile, read-only ΓÇö FM region/family change is admin-level)
    const [regionName, setRegionName] = useState('');
    const [familyName, setFamilyName] = useState('');

    // Load profile + reference data
    useEffect(() => {
        const init = async () => {
            try {
                const [profileRes, collegesRes, residencesRes] = await Promise.all([
                    api.get('/members/me'),
                    api.get('/colleges'),
                    api.get('/residences'),
                ]);

                const p = profileRes.data;
                setRegionName(p.region?.name ?? '');
                setFamilyName(p.family?.name ?? '');
                setColleges(collegesRes.data);
                setResidences(residencesRes.data);

                setFormData({
                    fullName: p.fullName ?? '',
                    email: p.email ?? '',
                    phoneNumber: (p.phoneNumber || '') as E164Number | '',
                    collegeId: p.academic?.collegeId || '',
                    courseId: p.academic?.courseId || '',
                    initialYearOfStudy: p.academic?.currentYear || 1,
                    initialSemester: p.academic?.currentSemester || 1,
                    residenceId: p.residence?.id || '',
                    hostelName: p.hostelName || '',
                });

                // Load courses for existing college
                if (p.academic?.collegeId) {
                    const coursesRes = await api.get(`/courses?collegeId=${p.academic.collegeId}`);
                    setCourses(coursesRes.data);
                }
            } catch {
                showToast('error', 'Failed to load profile data.');
            } finally {
                setLoadingProfile(false);
            }
        };
        init();
    }, []);

    // Reload courses when college changes
    useEffect(() => {
        if (!formData.collegeId) { setCourses([]); return; }
        api.get(`/courses?collegeId=${formData.collegeId}`)
            .then(r => setCourses(r.data))
            .catch(() => showToast('error', 'Failed to load courses.'));
    }, [formData.collegeId]);

    const handleCollegeChange = (value: string) => {
        if (value === 'NEW_COLLEGE') { setIsCollegeModalOpen(true); return; }
        setFormData(prev => ({ ...prev, collegeId: value, courseId: '' }));
    };

    const handleCourseChange = (value: string) => {
        if (value === 'NEW_COURSE') { setIsCourseModalOpen(true); return; }
        const selected = courses.find(c => c.id === value);
        let year = formData.initialYearOfStudy;
        if (selected?.durationYears && year > selected.durationYears) year = 1;
        setFormData(prev => ({ ...prev, courseId: value, initialYearOfStudy: year }));
    };

    const handleCollegeSaved = (college: College) => {
        setColleges(prev => [...prev, college].sort((a, b) => a.name.localeCompare(b.name)));
        setFormData(prev => ({ ...prev, collegeId: college.id, courseId: '' }));
    };

    const handleCourseSaved = (course: Course) => {
        setCourses(prev => [...prev, course].sort((a, b) => a.name.localeCompare(b.name)));
        setFormData(prev => ({ ...prev, courseId: course.id }));
    };

    const handleResidenceSaved = (residence: Residence) => {
        setResidences(prev => [...prev, residence].sort((a, b) => a.name.localeCompare(b.name)));
        setFormData(prev => ({ ...prev, residenceId: residence.id }));
    };

    // Region-based residence logic (same as registration)
    const upperRegion = regionName.toUpperCase();
    const isCentralRegion = upperRegion === 'CENTRAL';
    const isNonResident = upperRegion === 'NON-RESIDENT';
    const showResidenceField = isCentralRegion;
    const showHostelField = !isCentralRegion && !isNonResident;

    // Year options from selected course
    const selectedCourse = courses.find(c => c.id === formData.courseId);
    const maxYears = selectedCourse?.durationYears || 5;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            const payload: Record<string, any> = {
                fullName: formData.fullName,
                email: formData.email,
                phoneNumber: String(formData.phoneNumber || ''),
            };
            if (formData.courseId) payload.courseId = formData.courseId;
            if (formData.initialYearOfStudy) payload.initialYearOfStudy = formData.initialYearOfStudy;
            if (formData.initialSemester) payload.initialSemester = formData.initialSemester;
            if (formData.residenceId) payload.residenceId = formData.residenceId;
            if (formData.hostelName) payload.hostelName = formData.hostelName;

            await api.patch('/members/me', payload);
            showToast('success', 'Profile updated successfully!');
            navigate('/profile');
        } catch (err: any) {
            const msg = err.response?.data?.message || 'Failed to update profile.';
            showToast('error', msg);
        } finally {
            setLoading(false);
        }
    };

    if (loadingProfile) {
        return (
            <div className="flex items-center justify-center min-h-[60vh]">
                <Loader2 className="w-8 h-8 animate-spin text-slate-400" />
            </div>
        );
    }

    return (
        <div className="w-[90%] mx-auto">
            <div className="bg-white rounded-2xl shadow-xl border border-slate-200 p-8 relative overflow-hidden">
                {/* Background decoration */}
                <div className="absolute top-0 right-0 w-64 h-64 bg-teal-50 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 opacity-60" />

                <div className="relative">
                    {/* Header */}
                    <div className="flex items-center gap-3 mb-8">
                        <button
                            onClick={() => navigate('/profile')}
                            className="p-2.5 rounded-xl hover:bg-slate-100 transition-colors text-slate-500"
                        >
                            <ArrowLeft className="w-5 h-5" />
                        </button>
                        <div className="p-3 rounded-xl" style={{ backgroundColor: '#e9f5e1', color: '#48A111', outline: '1.5px solid #c5e3b0' }}>
                            <User className="w-6 h-6" />
                        </div>
                        <div>
                            <h2 className="text-2xl font-bold text-slate-900">Edit My Profile</h2>
                            <p className="text-slate-500">Changes are applied immediately ΓÇö no approval required</p>
                        </div>
                    </div>

                    <form onSubmit={handleSubmit} className="space-y-6">

                        {/* ΓöÇΓöÇ Personal & Contact ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            {/* Full Name */}
                            <div className="space-y-2 md:col-span-2">
                                <label className="text-sm font-semibold text-slate-700">
                                    Full Name <span className="text-red-500">*</span>
                                </label>
                                <input
                                    type="text"
                                    className="input transition-smooth"
                                    value={formData.fullName}
                                    onChange={e => setFormData(p => ({ ...p, fullName: e.target.value }))}
                                    placeholder="Your full name"
                                    required
                                />
                            </div>

                            {/* Email */}
                            <div className="space-y-2 md:col-span-2">
                                <label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                    <Mail className="w-4 h-4" style={{ color: '#48A111' }} />
                                    Email Address <span className="text-red-500">*</span>
                                </label>
                                <input
                                    type="email"
                                    className="input transition-smooth"
                                    value={formData.email}
                                    onChange={e => setFormData(p => ({ ...p, email: e.target.value }))}
                                    placeholder="your@email.com"
                                    required
                                />
                            </div>

                            {/* Phone */}
                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                    <Phone className="w-4 h-4" style={{ color: '#48A111' }} />
                                    Phone Number <span className="text-red-500">*</span>
                                </label>
                                <PhoneInput
                                    value={formData.phoneNumber as E164Number | undefined}
                                    onChange={val => setFormData(p => ({ ...p, phoneNumber: val || '' }))}
                                    required
                                    placeholder="700 123 456"
                                />
                            </div>
                        </div>

                        {/* ΓöÇΓöÇ Academic Information ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            {/* College */}
                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-700 flex items-center justify-between">
                                    <span className="flex items-center gap-2">
                                        <Building className="w-4 h-4" style={{ color: '#48A111' }} />
                                        College
                                    </span>
                                    <button
                                        type="button"
                                        onClick={() => setIsCollegeModalOpen(true)}
                                        className="text-xs font-semibold flex items-center gap-1 hover:opacity-75 transition-opacity"
                                        style={{ color: '#48A111' }}
                                    >
                                        <Plus size={12} /> Add New
                                    </button>
                                </label>
                                <CustomSelect
                                    value={formData.collegeId}
                                    onChange={handleCollegeChange}
                                    placeholder="Select College"
                                    options={[
                                        { value: '', label: 'Select College', disabled: true },
                                        ...colleges.map(c => ({ value: c.id, label: c.code ? `${c.code} ΓÇô ${c.name}` : c.name })),
                                        ...(colleges.length > 0 ? [{ value: '__sep__', label: 'ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ', disabled: true }] : []),
                                        { value: 'NEW_COLLEGE', label: '+ Add New College...', className: 'font-semibold' },
                                    ]}
                                />
                            </div>

                            {/* Course */}
                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-700 flex items-center justify-between">
                                    <span className="flex items-center gap-2">
                                        <BookOpen className="w-4 h-4" style={{ color: '#48A111' }} />
                                        Course
                                    </span>
                                    <button
                                        type="button"
                                        onClick={() => setIsCourseModalOpen(true)}
                                        className="text-xs font-semibold flex items-center gap-1 hover:opacity-75 transition-opacity"
                                        style={{ color: '#48A111' }}
                                    >
                                        <Plus size={12} /> Add New
                                    </button>
                                </label>
                                <CustomSelect
                                    value={formData.courseId}
                                    onChange={handleCourseChange}
                                    disabled={!formData.collegeId && courses.length === 0}
                                    placeholder="Select Course"
                                    options={[
                                        { value: '', label: formData.collegeId ? 'Select Course' : 'Select a college first', disabled: true },
                                        ...courses.map(c => ({ value: c.id, label: c.name.length > 50 ? `${c.name.substring(0, 50)}...` : c.name })),
                                        ...(courses.length > 0 ? [{ value: '__sep_c__', label: 'ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ', disabled: true }] : []),
                                        { value: 'NEW_COURSE', label: '+ Add New Course...', className: 'font-semibold' },
                                    ]}
                                />
                                {!formData.collegeId && (
                                    <p className="text-xs text-slate-500">Please select a college first</p>
                                )}
                            </div>

                            {/* Year of Study */}
                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                    <GraduationCap className="w-4 h-4" style={{ color: '#48A111' }} />
                                    Year of Study
                                </label>
                                <CustomSelect
                                    value={String(formData.initialYearOfStudy)}
                                    onChange={v => setFormData(p => ({ ...p, initialYearOfStudy: parseInt(v) }))}
                                    placeholder="Select year"
                                    options={[
                                        { value: '', label: 'Select year', disabled: true },
                                        ...Array.from({ length: maxYears }, (_, i) => i + 1).map(yr => ({
                                            value: String(yr), label: `Year ${yr}`,
                                        })),
                                    ]}
                                />
                            </div>

                            {/* Semester */}
                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-700">Current Semester</label>
                                <CustomSelect
                                    value={String(formData.initialSemester)}
                                    onChange={v => setFormData(p => ({ ...p, initialSemester: parseInt(v) }))}
                                    placeholder="Select semester"
                                    options={[
                                        { value: '', label: 'Select semester', disabled: true },
                                        { value: '1', label: 'Semester 1' },
                                        { value: '2', label: 'Semester 2' },
                                    ]}
                                />
                            </div>

                            {/* Residence (region-conditional) */}
                            {showResidenceField && (
                                <div className="space-y-2">
                                    <label className="text-sm font-semibold text-slate-700 flex items-center justify-between">
                                        <span className="flex items-center gap-2">
                                            <Building className="w-4 h-4" style={{ color: '#48A111' }} />
                                            Hall / Residence
                                        </span>
                                        <button
                                            type="button"
                                            onClick={() => setIsResidenceModalOpen(true)}
                                            className="text-xs font-semibold flex items-center gap-1 hover:opacity-75 transition-opacity"
                                            style={{ color: '#48A111' }}
                                        >
                                            <Plus size={12} /> Add New Hall
                                        </button>
                                    </label>
                                    <CustomSelect
                                        value={formData.residenceId}
                                        onChange={v => setFormData(p => ({ ...p, residenceId: v }))}
                                        placeholder="Select Hall"
                                        options={[
                                            { value: '', label: 'Select Hall', disabled: true },
                                            ...residences.filter(r => r.type === 'HALL').map(r => ({ value: r.id, label: r.name })),
                                        ]}
                                    />
                                </div>
                            )}

                            {showHostelField && (
                                <div className="space-y-2">
                                    <label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                        <MapPin className="w-4 h-4" style={{ color: '#48A111' }} />
                                        Hostel / Hall
                                    </label>
                                    <input
                                        type="text"
                                        className="input transition-smooth"
                                        value={formData.hostelName}
                                        onChange={e => setFormData(p => ({ ...p, hostelName: e.target.value }))}
                                        placeholder="e.g. Olympia, Dream Land"
                                    />
                                    <p className="text-xs text-slate-500">Enter the hostel where you reside</p>
                                </div>
                            )}
                        </div>

